INSERT INTO questions (subject, topic, question, options, answer, explanation, difficulty, source, tags) VALUES
  ('Anatomy', 'Inguinal Canal & Hernia Anatomy', 'A 25-year-old male presents with a swelling in the groin that extends into the scrotum and is controlled by pressure over the midpoint of the inguinal ligament. What type of hernia is this?', '[{"key": "A", "text": "Direct inguinal hernia"}, {"key": "B", "text": "Indirect inguinal hernia"}, {"key": "C", "text": "Femoral hernia"}, {"key": "D", "text": "Spigelian hernia"}]'::jsonb, 'B', 'The hernia extends into the scrotum (follows spermatic cord) and is controlled by deep ring occlusion (midpoint of inguinal ligament). These are classic features of indirect inguinal hernia, which exits lateral to the inferior epigastric vessels through the deep ring. 📚 BD Chaurasia, Vol.2, Ch.14', 1, 'nucleux-content', '{}'),
  ('Anatomy', 'Inguinal Canal & Hernia Anatomy', 'Hesselbach''s triangle is bounded laterally by which structure?', '[{"key": "A", "text": "Inguinal ligament"}, {"key": "B", "text": "Lateral border of rectus abdominis"}, {"key": "C", "text": "Inferior epigastric vessels"}, {"key": "D", "text": "Deep inguinal ring"}]'::jsonb, 'C', 'Hesselbach''s triangle: medial — rectus abdominis; lateral — inferior epigastric vessels; inferior — inguinal ligament. Direct inguinal hernias protrude through this triangle. 📚 Gray''s Anatomy, 42nd Ed', 1, 'nucleux-content', '{}'),
  ('Anatomy', 'Inguinal Canal & Hernia Anatomy', 'Which layer of the abdominal wall gives rise to the cremasteric fascia of the spermatic cord?', '[{"key": "A", "text": "External oblique"}, {"key": "B", "text": "Internal oblique"}, {"key": "C", "text": "Transversus abdominis"}, {"key": "D", "text": "Transversalis fascia"}]'::jsonb, 'B', 'Coverings of spermatic cord are derived from abdominal wall layers: external spermatic fascia (external oblique), cremasteric fascia and muscle (internal oblique), internal spermatic fascia (transversalis fascia). 📚 BD Chaurasia, Vol.2, Ch.14', 2, 'nucleux-content', '{}'),
  ('Anatomy', 'Inguinal Canal & Hernia Anatomy', 'An indirect inguinal hernia enters the inguinal canal at the deep ring, which is located in relation to the inferior epigastric vessels:', '[{"key": "A", "text": "Medial"}, {"key": "B", "text": "Lateral"}, {"key": "C", "text": "Superior"}, {"key": "D", "text": "Posterior"}]'::jsonb, 'B', 'The deep inguinal ring is located lateral to the inferior epigastric vessels. Indirect hernias pass through the deep ring (lateral to vessels). Direct hernias pass medial to the vessels through Hesselbach''s triangle. This is the key anatomical distinction between the two types. 📚 Gray''s Anatomy, 42nd Ed', 1, 'nucleux-content', '{}'),
  ('Anatomy', 'Inguinal Canal & Hernia Anatomy', 'The floor of the inguinal canal is formed by which structure?', '[{"key": "A", "text": "External oblique aponeurosis"}, {"key": "B", "text": "Inguinal ligament"}, {"key": "C", "text": "Transversalis fascia"}, {"key": "D", "text": "Conjoint tendon"}]'::jsonb, 'B', 'The floor (inferior wall) of the inguinal canal is formed by the inguinal ligament (Poupart''s ligament) with the lacunar ligament medially. The inguinal ligament is the rolled lower edge of the external oblique aponeurosis extending from ASIS to the pubic tubercle. 📚 BD Chaurasia, Vol.2, Ch.14', 1, 'nucleux-content', '{}'),
  ('Anatomy', 'Kidney & Retroperitoneum', 'At the hilum of the kidney, from anterior to posterior, the structures are arranged as:', '[{"key": "A", "text": "Artery, vein, pelvis"}, {"key": "B", "text": "Vein, artery, pelvis"}, {"key": "C", "text": "Pelvis, artery, vein"}, {"key": "D", "text": "Vein, pelvis, artery"}]'::jsonb, 'B', 'At the renal hilum, from anterior to posterior: renal Vein, renal Artery, renal Pelvis (VAP). This arrangement is important during nephrectomy — the vein is encountered first anteriorly. 📚 BD Chaurasia, Vol.2', 1, 'nucleux-content', '{}'),
  ('Anatomy', 'Kidney & Retroperitoneum', 'The left renal vein crosses anterior to which structure?', '[{"key": "A", "text": "Inferior vena cava only"}, {"key": "B", "text": "Aorta"}, {"key": "C", "text": "Superior mesenteric artery"}, {"key": "D", "text": "Left crus of diaphragm"}]'::jsonb, 'B', 'The left renal vein crosses anterior to the aorta (and behind the SMA) to drain into the IVC. This longer course makes it preferable for renal transplant donor nephrectomy. Nutcracker syndrome occurs when the left renal vein is compressed between the aorta and SMA. 📚 Gray''s Anatomy, 42nd Ed', 1, 'nucleux-content', '{}'),
  ('Anatomy', 'Kidney & Retroperitoneum', 'Horseshoe kidney is arrested in its ascent by which artery?', '[{"key": "A", "text": "Superior mesenteric artery"}, {"key": "B", "text": "Inferior mesenteric artery"}, {"key": "C", "text": "Renal artery"}, {"key": "D", "text": "Common iliac artery"}]'::jsonb, 'B', 'The isthmus of a horseshoe kidney hooks under the inferior mesenteric artery during embryological ascent, preventing normal ascent to T12-L2 level. It remains at L3 level. Associated with Turner syndrome. 📚 Gray''s Anatomy, 42nd Ed', 1, 'nucleux-content', '{}'),
  ('Anatomy', 'Kidney & Retroperitoneum', 'The avascular plane of the kidney (Brödel''s line) used for nephrotomy is located:', '[{"key": "A", "text": "Along the hilum"}, {"key": "B", "text": "At the upper pole"}, {"key": "C", "text": "1 cm behind the lateral border"}, {"key": "D", "text": "At the lower pole"}]'::jsonb, 'C', 'Brödel''s line is the avascular plane between the territories of anterior and posterior segmental arteries. It is located about 1 cm posterior to the lateral convex border. Incision here minimizes vascular injury during nephrotomy. 📚 BD Chaurasia, Vol.2', 2, 'nucleux-content', '{}'),
  ('Anatomy', 'Kidney & Retroperitoneum', 'Which of the following is a primary retroperitoneal organ?', '[{"key": "A", "text": "Stomach"}, {"key": "B", "text": "Jejunum"}, {"key": "C", "text": "Transverse colon"}, {"key": "D", "text": "Kidney"}]'::jsonb, 'D', 'Kidneys are primary retroperitoneal organs (developed and remain retroperitoneal). Stomach, jejunum, and transverse colon are intraperitoneal. Ascending/descending colon and pancreas are secondarily retroperitoneal. 📚 Gray''s Anatomy, 42nd Ed', 1, 'nucleux-content', '{}'),
  ('Anatomy', 'Large Intestine & Rectum', 'The watershed area most vulnerable to ischemic colitis is located at:', '[{"key": "A", "text": "Hepatic flexure"}, {"key": "B", "text": "Splenic flexure"}, {"key": "C", "text": "Cecum"}, {"key": "D", "text": "Sigmoid colon"}]'::jsonb, 'B', 'The splenic flexure (Griffiths'' point) is the watershed between SMA and IMA territories. It is the most common site of ischemic colitis, especially in low-flow states after aortic surgery. 📚 Gray''s Anatomy, 42nd Ed', 1, 'nucleux-content', '{}'),
  ('Anatomy', 'Large Intestine & Rectum', 'The pectinate (dentate) line of the anal canal is significant because structures above it:', '[{"key": "A", "text": "Have somatic innervation and systemic venous drainage"}, {"key": "B", "text": "Have visceral innervation and portal venous drainage"}, {"key": "C", "text": "Are lined by stratified squamous epithelium"}, {"key": "D", "text": "Are supplied by inferior rectal artery"}]'::jsonb, 'B', 'Above the pectinate line: columnar epithelium, visceral nerve supply (painless), portal venous drainage (to superior rectal vein → IMV → portal vein), supplied by superior rectal artery. Below: squamous epithelium, somatic (painful), systemic drainage. 📚 BD Chaurasia, Vol.2', 2, 'nucleux-content', '{}'),
  ('Anatomy', 'Large Intestine & Rectum', 'The most common position of the appendix is:', '[{"key": "A", "text": "Pelvic"}, {"key": "B", "text": "Retrocecal"}, {"key": "C", "text": "Subcecal"}, {"key": "D", "text": "Preileal"}]'::jsonb, 'B', 'Retrocecal position (65%) is the most common. Pelvic (31%) is second most common. In retrocecal appendicitis, signs may be atypical — absent Rovsing''s sign, positive psoas sign. 📚 BD Chaurasia, Vol.2', 1, 'nucleux-content', '{}'),
  ('Anatomy', 'Large Intestine & Rectum', 'McBurney''s point is located at the junction of:', '[{"key": "A", "text": "Upper 1/3 and lower 2/3 of line from umbilicus to ASIS"}, {"key": "B", "text": "Lateral 1/3 and medial 2/3 of line from ASIS to umbilicus"}, {"key": "C", "text": "Midpoint of line from ASIS to pubic symphysis"}, {"key": "D", "text": "Lateral 1/3 and medial 2/3 of line from umbilicus to pubic symphysis"}]'::jsonb, 'B', 'McBurney''s point marks the base of the appendix at the junction of the lateral 1/3 and medial 2/3 of the line drawn from the right ASIS to the umbilicus. Maximum tenderness here suggests acute appendicitis. 📚 BD Chaurasia, Vol.2', 1, 'nucleux-content', '{}'),
  ('Anatomy', 'Large Intestine & Rectum', 'Which artery is the sole blood supply to the appendix?', '[{"key": "A", "text": "Right colic artery"}, {"key": "B", "text": "Ileocolic artery"}, {"key": "C", "text": "Appendicular artery"}, {"key": "D", "text": "Middle colic artery"}]'::jsonb, 'C', 'The appendicular artery is a branch of the ileocolic artery (from SMA). It is an end artery, running in the mesoappendix. Thrombosis leads to gangrenous appendicitis. The ileocolic gives rise to it but does not directly supply the appendix. 📚 Gray''s Anatomy, 42nd Ed', 1, 'nucleux-content', '{}'),
  ('Anatomy', 'Liver Anatomy (Segments, Portal Triad)', 'Cantlie''s line, which divides the liver into functional right and left lobes, runs from:', '[{"key": "A", "text": "Porta hepatis to ligamentum teres"}, {"key": "B", "text": "Gallbladder fossa to IVC"}, {"key": "C", "text": "Falciform ligament to bare area"}, {"key": "D", "text": "Right triangular ligament to left triangular ligament"}]'::jsonb, 'B', 'Cantlie''s line runs from the gallbladder fossa to the IVC, corresponding to the plane of the middle hepatic vein. It divides the liver into functional right (segments V-VIII) and left (segments II-IV) lobes. 📚 Gray''s Anatomy, 42nd Ed', 1, 'nucleux-content', '{}'),
  ('Anatomy', 'Liver Anatomy (Segments, Portal Triad)', 'Which segment of the liver receives portal blood from both right and left portal vein branches?', '[{"key": "A", "text": "Segment IV"}, {"key": "B", "text": "Segment I (caudate lobe)"}, {"key": "C", "text": "Segment V"}, {"key": "D", "text": "Segment VIII"}]'::jsonb, 'B', 'The caudate lobe (segment I) is unique — it receives portal blood from both right and left portal vein branches and drains directly into the IVC via short hepatic veins, independent of the three main hepatic veins. 📚 Gray''s Anatomy, 42nd Ed; 📚 Netter''s Atlas, 6th Ed', 2, 'nucleux-content', '{}'),
  ('Anatomy', 'Liver Anatomy (Segments, Portal Triad)', 'The Pringle maneuver involves clamping which structure?', '[{"key": "A", "text": "Hepatic veins"}, {"key": "B", "text": "Inferior vena cava"}, {"key": "C", "text": "Hepatoduodenal ligament"}, {"key": "D", "text": "Falciform ligament"}]'::jsonb, 'C', 'The Pringle maneuver is compression of the hepatoduodenal ligament (free edge of lesser omentum) containing the portal triad (portal vein, hepatic artery, bile duct). It controls hepatic inflow bleeding. 📚 Gray''s Anatomy, 42nd Ed', 1, 'nucleux-content', '{}'),
  ('Anatomy', 'Liver Anatomy (Segments, Portal Triad)', 'In the portal triad, the common bile duct is located:', '[{"key": "A", "text": "Posterior to portal vein"}, {"key": "B", "text": "To the left of hepatic artery"}, {"key": "C", "text": "To the right in the free edge"}, {"key": "D", "text": "Anterior to all structures"}]'::jsonb, 'C', 'In the hepatoduodenal ligament: bile duct is to the RIGHT, hepatic artery proper is to the LEFT, and portal vein is POSTERIOR. This arrangement is critical during cholecystectomy and bile duct surgery. 📚 BD Chaurasia, Vol.2', 1, 'nucleux-content', '{}'),
  ('Anatomy', 'Liver Anatomy (Segments, Portal Triad)', 'The bare area of the liver is located between the layers of which ligament?', '[{"key": "A", "text": "Falciform ligament"}, {"key": "B", "text": "Coronary ligament"}, {"key": "C", "text": "Triangular ligament"}, {"key": "D", "text": "Hepatoduodenal ligament"}]'::jsonb, 'B', 'The bare area is the posterior surface of the liver between the superior and inferior layers of the coronary ligament, in direct contact with the diaphragm without peritoneal covering. Liver abscesses can spread transdiaphragmatically to the right pleural cavity through this area. 📚 BD Chaurasia, Vol.2', 2, 'nucleux-content', '{}'),
  ('Anatomy', 'Stomach & Duodenum Anatomy', 'A posterior duodenal ulcer causes massive hematemesis. Which artery is most likely eroded?', '[{"key": "A", "text": "Left gastric artery"}, {"key": "B", "text": "Splenic artery"}, {"key": "C", "text": "Gastroduodenal artery"}, {"key": "D", "text": "Superior mesenteric artery"}]'::jsonb, 'C', 'The GDA runs directly behind the first part of the duodenum. Posterior D1 ulcers erode into the GDA causing massive upper GI hemorrhage. Anterior D1 ulcers perforate into the peritoneal cavity instead. 📚 Gray''s Anatomy, 42nd Ed; 📚 BD Chaurasia, Vol.2', 1, 'nucleux-content', '{}'),
  ('Anatomy', 'Stomach & Duodenum Anatomy', 'The ampulla of Vater (major duodenal papilla) opens into which part of the duodenum?', '[{"key": "A", "text": "First part (D1)"}, {"key": "B", "text": "Second part (D2)"}, {"key": "C", "text": "Third part (D3)"}, {"key": "D", "text": "Fourth part (D4)"}]'::jsonb, 'B', 'The CBD and main pancreatic duct join to form the ampulla of Vater, which opens on the posteromedial wall of D2. The minor papilla (accessory pancreatic duct) opens 2 cm proximal to it. 📚 BD Chaurasia, Vol.2', 1, 'nucleux-content', '{}'),
  ('Anatomy', 'Stomach & Duodenum Anatomy', 'Which artery provides the largest blood supply to the stomach?', '[{"key": "A", "text": "Right gastric artery"}, {"key": "B", "text": "Left gastric artery"}, {"key": "C", "text": "Right gastroepiploic artery"}, {"key": "D", "text": "Short gastric arteries"}]'::jsonb, 'B', 'The left gastric artery (direct branch of celiac trunk) is the largest arterial contributor to the stomach, supplying the lesser curvature. It also gives esophageal branches and is the source of the left gastric (coronary) vein — important in portal hypertension. 📚 Netter''s Atlas, 6th Ed', 1, 'nucleux-content', '{}'),
  ('Anatomy', 'Stomach & Duodenum Anatomy', 'SMA syndrome causes obstruction of which part of the duodenum?', '[{"key": "A", "text": "First part"}, {"key": "B", "text": "Second part"}, {"key": "C", "text": "Third part"}, {"key": "D", "text": "Fourth part"}]'::jsonb, 'C', 'D3 (horizontal part) crosses between the aorta posteriorly and the SMA anteriorly. In patients with reduced mesenteric fat, the aortomesenteric angle narrows and SMA compresses D3, causing obstruction. 📚 Gray''s Anatomy, 42nd Ed', 2, 'nucleux-content', '{}'),
  ('Anatomy', 'Stomach & Duodenum Anatomy', 'The ligament of Treitz is attached to which structure?', '[{"key": "A", "text": "Pylorus"}, {"key": "B", "text": "Duodenojejunal flexure"}, {"key": "C", "text": "Ileocecal junction"}, {"key": "D", "text": "Hepatic flexure"}]'::jsonb, 'B', 'The ligament of Treitz (suspensory muscle of duodenum) is a musculofibrous band extending from the right crus of the diaphragm to the duodenojejunal flexure. It is the landmark dividing upper from lower GI tract. 📚 BD Chaurasia, Vol.2', 1, 'nucleux-content', '{}'),
  ('Anatomy', 'Cranial Nerves (Overview + Clinical)', 'A patient presents with inability to close the right eye, loss of right nasolabial fold, and inability to wrinkle the forehead on the right side. This is most likely:', '[{"key": "A", "text": "UMN lesion of facial nerve"}, {"key": "B", "text": "LMN lesion of facial nerve (Bell''s palsy)"}, {"key": "C", "text": "Trigeminal nerve lesion"}, {"key": "D", "text": "Oculomotor nerve palsy"}]'::jsonb, 'B', 'Entire ipsilateral face involvement (including forehead) indicates LMN facial nerve palsy. In UMN lesion, forehead is SPARED because the upper face motor neurons receive bilateral cortical innervation. 📚 Gray''s Anatomy, 42nd Ed', 1, 'nucleux-content', '{}'),
  ('Anatomy', 'Cranial Nerves (Overview + Clinical)', 'Which cranial nerve has the longest intracranial course and is a ''false localizing sign'' in raised intracranial pressure?', '[{"key": "A", "text": "CN III"}, {"key": "B", "text": "CN IV"}, {"key": "C", "text": "CN VI"}, {"key": "D", "text": "CN VII"}]'::jsonb, 'C', 'CN VI (abducens) has the longest intracranial course along the clivus. Raised ICP compresses it against the petrous temporal bone → lateral rectus palsy → medial strabismus. This is a "false localizing sign" as the pathology is not at CN VI itself. 📚 Gray''s Anatomy, 42nd Ed', 2, 'nucleux-content', '{}'),
  ('Anatomy', 'Cranial Nerves (Overview + Clinical)', 'In a CN XII (hypoglossal) nerve palsy, the tongue deviates:', '[{"key": "A", "text": "Away from the side of lesion"}, {"key": "B", "text": "Toward the side of lesion"}, {"key": "C", "text": "Does not deviate"}, {"key": "D", "text": "Upward"}]'::jsonb, 'B', 'In LMN hypoglossal palsy, the tongue deviates toward the lesion because the opposite genioglossus (which pushes the tongue contralaterally) is unopposed. Ipsilateral tongue atrophy and fasciculations are also seen. 📚 BD Chaurasia, Vol.3', 1, 'nucleux-content', '{}'),
  ('Anatomy', 'Cranial Nerves (Overview + Clinical)', 'The corneal reflex tests the integrity of which two cranial nerves?', '[{"key": "A", "text": "CN II and CN III"}, {"key": "B", "text": "CN V1 and CN VII"}, {"key": "C", "text": "CN V2 and CN VII"}, {"key": "D", "text": "CN V3 and CN VII"}]'::jsonb, 'B', 'Corneal reflex: afferent limb = CN V1 (ophthalmic division of trigeminal, via nasociliary nerve); efferent limb = CN VII (facial nerve → orbicularis oculi contraction). Testing involves touching the cornea and observing bilateral eye closure. 📚 Gray''s Anatomy, 42nd Ed', 1, 'nucleux-content', '{}'),
  ('Anatomy', 'Cranial Nerves (Overview + Clinical)', 'Which cranial nerves pass through the jugular foramen?', '[{"key": "A", "text": "CN VII, VIII, IX"}, {"key": "B", "text": "CN IX, X, XI"}, {"key": "C", "text": "CN X, XI, XII"}, {"key": "D", "text": "CN III, IV, V1, VI"}]'::jsonb, 'B', 'The jugular foramen transmits CN IX (glossopharyngeal), CN X (vagus), and CN XI (spinal accessory), along with the internal jugular vein. CN VII and VIII exit through the internal acoustic meatus. CN III, IV, V1, VI pass through the superior orbital fissure. 📚 BD Chaurasia, Vol.3', 1, 'nucleux-content', '{}'),
  ('Anatomy', 'Ear Anatomy (Middle & Inner Ear)', 'The stapedius muscle is supplied by which nerve?', '[{"key": "A", "text": "CN V3 (mandibular)"}, {"key": "B", "text": "CN VII (facial)"}, {"key": "C", "text": "CN IX (glossopharyngeal)"}, {"key": "D", "text": "CN VIII (vestibulocochlear)"}]'::jsonb, 'B', 'Stapedius (smallest skeletal muscle) is supplied by a branch of CN VII (facial nerve). It dampens stapes vibrations to protect from loud sounds. In Bell''s palsy (CN VII lesion), stapedius paralysis causes hyperacusis (increased sensitivity to sound). 📚 BD Chaurasia, Vol.3', 1, 'nucleux-content', '{}'),
  ('Anatomy', 'Ear Anatomy (Middle & Inner Ear)', 'The chorda tympani nerve crosses the middle ear between which two ossicles?', '[{"key": "A", "text": "Malleus and stapes"}, {"key": "B", "text": "Incus and stapes"}, {"key": "C", "text": "Malleus and incus"}, {"key": "D", "text": "Does not cross between ossicles"}]'::jsonb, 'C', 'Chorda tympani (branch of CN VII) crosses the middle ear between the handle of the malleus and the long process of the incus. It carries taste from the anterior 2/3 of the tongue and parasympathetic fibers to the submandibular and sublingual glands. 📚 Gray''s Anatomy, 42nd Ed', 2, 'nucleux-content', '{}'),
  ('Anatomy', 'Ear Anatomy (Middle & Inner Ear)', 'In a patient with conductive hearing loss in the right ear, Weber''s test will lateralize to:', '[{"key": "A", "text": "Left ear"}, {"key": "B", "text": "Right ear"}, {"key": "C", "text": "Both ears equally"}, {"key": "D", "text": "Neither ear"}]'::jsonb, 'B', 'In conductive hearing loss, Weber lateralizes to the AFFECTED ear because bone conduction is relatively enhanced (background noise is reduced in that ear). In sensorineural loss, it lateralizes to the unaffected (better) ear. 📚 BD Chaurasia, Vol.3', 1, 'nucleux-content', '{}'),
  ('Anatomy', 'Ear Anatomy (Middle & Inner Ear)', 'The endolymph in the membranous labyrinth is characterized by:', '[{"key": "A", "text": "High sodium, low potassium (similar to ECF)"}, {"key": "B", "text": "High potassium, low sodium (similar to ICF)"}, {"key": "C", "text": "Equal sodium and potassium"}, {"key": "D", "text": "High calcium"}]'::jsonb, 'B', 'Endolymph has a unique ionic composition similar to intracellular fluid (high K+, low Na+), produced by the stria vascularis in the cochlea. Perilymph resembles ECF (high Na+, low K+). This K+ gradient is essential for hair cell transduction. 📚 Gray''s Anatomy, 42nd Ed', 2, 'nucleux-content', '{}'),
  ('Anatomy', 'Ear Anatomy (Middle & Inner Ear)', 'The roof of the middle ear (tegmen tympani) separates it from which cranial fossa?', '[{"key": "A", "text": "Anterior cranial fossa"}, {"key": "B", "text": "Middle cranial fossa"}, {"key": "C", "text": "Posterior cranial fossa"}, {"key": "D", "text": "Infratemporal fossa"}]'::jsonb, 'B', 'Tegmen tympani is a thin plate of bone forming the roof of the middle ear, separating it from the middle cranial fossa (temporal lobe of brain). Middle ear infections can spread intracranially through this thin bone, causing temporal lobe abscess or meningitis. 📚 BD Chaurasia, Vol.3', 1, 'nucleux-content', '{}'),
  ('Anatomy', 'Eye Anatomy (Extraocular Muscles, Nerve Supply)', 'A patient has ptosis, eye in ''down and out'' position, and a fixed dilated pupil. Which cranial nerve is affected?', '[{"key": "A", "text": "CN IV"}, {"key": "B", "text": "CN III"}, {"key": "C", "text": "CN VI"}, {"key": "D", "text": "CN VII"}]'::jsonb, 'B', 'CN III supplies all extraocular muscles except LR (VI) and SO (IV). Loss of CN III leaves LR and SO unopposed → eye deviates laterally (out) and down. Ptosis from levator palpebrae paralysis. Dilated pupil from parasympathetic fiber damage. 📚 BD Chaurasia, Vol.3', 1, 'nucleux-content', '{}'),
  ('Anatomy', 'Eye Anatomy (Extraocular Muscles, Nerve Supply)', 'A pituitary tumor compressing the optic chiasm would most likely cause:', '[{"key": "A", "text": "Ipsilateral blindness"}, {"key": "B", "text": "Bitemporal hemianopia"}, {"key": "C", "text": "Homonymous hemianopia"}, {"key": "D", "text": "Superior quadrantanopia"}]'::jsonb, 'B', 'The optic chiasm is located above the pituitary gland. A pituitary tumor compresses the crossing nasal fibers (which carry temporal visual fields) → bilateral loss of temporal visual fields = bitemporal hemianopia. 📚 Gray''s Anatomy, 42nd Ed', 1, 'nucleux-content', '{}'),
  ('Anatomy', 'Eye Anatomy (Extraocular Muscles, Nerve Supply)', 'The superior oblique muscle is tested by asking the patient to look:', '[{"key": "A", "text": "Up and out"}, {"key": "B", "text": "Down and out"}, {"key": "C", "text": "Down and in"}, {"key": "D", "text": "Up and in"}]'::jsonb, 'C', 'The superior oblique (CN IV) is the primary depressor when the eye is adducted (looking medially). Testing: patient looks down and in. CN IV palsy causes difficulty looking downward when reading or descending stairs. 📚 BD Chaurasia, Vol.3', 2, 'nucleux-content', '{}'),
  ('Anatomy', 'Eye Anatomy (Extraocular Muscles, Nerve Supply)', 'Horner''s syndrome consists of all EXCEPT:', '[{"key": "A", "text": "Miosis"}, {"key": "B", "text": "Ptosis"}, {"key": "C", "text": "Mydriasis"}, {"key": "D", "text": "Anhidrosis"}]'::jsonb, 'C', 'Horner''s syndrome results from loss of sympathetic supply: miosis (not mydriasis), partial ptosis, anhidrosis, and apparent enophthalmos. Mydriasis (pupil dilation) would occur with parasympathetic loss (CN III palsy), not sympathetic loss. 📚 Gray''s Anatomy, 42nd Ed', 1, 'nucleux-content', '{}'),
  ('Anatomy', 'Eye Anatomy (Extraocular Muscles, Nerve Supply)', 'A lesion in Meyer''s loop (temporal lobe) causes:', '[{"key": "A", "text": "Ipsilateral blindness"}, {"key": "B", "text": "Bitemporal hemianopia"}, {"key": "C", "text": "Contralateral superior quadrantanopia"}, {"key": "D", "text": "Contralateral inferior quadrantanopia"}]'::jsonb, 'C', 'Meyer''s loop carries inferior retinal fibers (representing the superior visual field) through the temporal lobe. Lesion causes contralateral superior quadrantanopia ("pie in the sky"). Parietal lobe lesion causes inferior quadrantanopia ("pie on the floor"). 📚 Gray''s Anatomy, 42nd Ed', 2, 'nucleux-content', '{}'),
  ('Anatomy', 'Triangles of Neck', 'A surgeon performing lymph node biopsy in the posterior triangle of the neck must be careful to preserve which nerve that crosses superficially?', '[{"key": "A", "text": "Vagus nerve"}, {"key": "B", "text": "Phrenic nerve"}, {"key": "C", "text": "Spinal accessory nerve"}, {"key": "D", "text": "Hypoglossal nerve"}]'::jsonb, 'C', 'CN XI (spinal accessory) crosses the posterior triangle superficially from the posterior border of SCM to the anterior border of trapezius. It is the most commonly injured nerve during posterior triangle surgery. Injury causes trapezius paralysis with shoulder droop. 📚 BD Chaurasia, Vol.3, Ch.5', 1, 'nucleux-content', '{}'),
  ('Anatomy', 'Triangles of Neck', 'The carotid bifurcation is located at the level of which vertebra?', '[{"key": "A", "text": "C2"}, {"key": "B", "text": "C3-C4"}, {"key": "C", "text": "C5-C6"}, {"key": "D", "text": "C7"}]'::jsonb, 'B', 'The common carotid artery bifurcates into internal and external carotid arteries at the level of the upper border of the thyroid cartilage, corresponding to C3-C4 vertebral level. This is located within the carotid triangle. 📚 Gray''s Anatomy, 42nd Ed, Ch.28', 1, 'nucleux-content', '{}'),
  ('Anatomy', 'Triangles of Neck', 'Virchow''s node is located in which triangle of the neck?', '[{"key": "A", "text": "Carotid triangle"}, {"key": "B", "text": "Submental triangle"}, {"key": "C", "text": "Left supraclavicular triangle"}, {"key": "D", "text": "Right supraclavicular triangle"}]'::jsonb, 'C', 'Virchow''s node (signal node) is located in the left supraclavicular triangle. Enlargement (Troisier''s sign) is a classic sign of metastatic gastric carcinoma, as it is the terminal node of the thoracic duct drainage. 📚 BD Chaurasia, Vol.3', 1, 'nucleux-content', '{}'),
  ('Anatomy', 'Triangles of Neck', 'Which of the following is NOT a content of the carotid triangle?', '[{"key": "A", "text": "Common carotid artery"}, {"key": "B", "text": "Internal jugular vein"}, {"key": "C", "text": "Spinal accessory nerve"}, {"key": "D", "text": "Hypoglossal nerve"}]'::jsonb, 'C', 'The spinal accessory nerve crosses the posterior triangle, not the carotid triangle. The carotid triangle contains the carotid arteries, IJV, vagus nerve, hypoglossal nerve, and superior laryngeal nerve. 📚 BD Chaurasia, Vol.3, Ch.5', 2, 'nucleux-content', '{}'),
  ('Anatomy', 'Triangles of Neck', 'The posterior triangle of the neck is bounded posteriorly by which muscle?', '[{"key": "A", "text": "Sternocleidomastoid"}, {"key": "B", "text": "Trapezius"}, {"key": "C", "text": "Omohyoid"}, {"key": "D", "text": "Splenius capitis"}]'::jsonb, 'B', 'Posterior triangle boundaries: anterior — posterior border of SCM; posterior — anterior border of trapezius; inferior — middle third of clavicle. Splenius capitis forms part of the floor, not a boundary. Omohyoid subdivides it. 📚 BD Chaurasia, Vol.3, Ch.5', 1, 'nucleux-content', '{}'),
  ('Anatomy', 'Femoral Triangle & Canal', 'A femoral hernia passes through the femoral canal, which lies:', '[{"key": "A", "text": "Lateral to the femoral artery"}, {"key": "B", "text": "Between the femoral artery and vein"}, {"key": "C", "text": "Medial to the femoral vein"}, {"key": "D", "text": "Lateral to the femoral nerve"}]'::jsonb, 'C', 'The femoral canal is the most medial compartment of the femoral sheath, lying medial to the femoral vein. From lateral to medial: nerve (outside sheath), artery, vein, canal (NAVY). 📚 BD Chaurasia, Vol.2', 1, 'nucleux-content', '{}'),
  ('Anatomy', 'Femoral Triangle & Canal', 'Femoral hernia is more common in females because of:', '[{"key": "A", "text": "Weaker abdominal muscles"}, {"key": "B", "text": "Wider pelvis and larger femoral canal"}, {"key": "C", "text": "More pregnancies"}, {"key": "D", "text": "Longer inguinal canal"}]'::jsonb, 'B', 'The female pelvis is wider, resulting in a larger femoral canal. This anatomical predisposition makes femoral hernias more common in females (though inguinal hernias are still more common overall even in females). 📚 Gray''s Anatomy, 42nd Ed', 1, 'nucleux-content', '{}'),
  ('Anatomy', 'Femoral Triangle & Canal', 'The structure that lies immediately lateral to the femoral canal is the:', '[{"key": "A", "text": "Femoral artery"}, {"key": "B", "text": "Femoral nerve"}, {"key": "C", "text": "Femoral vein"}, {"key": "D", "text": "Lacunar ligament"}]'::jsonb, 'C', 'The femoral vein forms the lateral boundary of the femoral canal. The medial boundary is the lacunar ligament. The femoral artery is further lateral, separated by the vein. 📚 BD Chaurasia, Vol.2', 1, 'nucleux-content', '{}'),
  ('Anatomy', 'Femoral Triangle & Canal', 'The femoral artery is palpated at the mid-inguinal point, which is midway between:', '[{"key": "A", "text": "ASIS and pubic tubercle"}, {"key": "B", "text": "ASIS and pubic symphysis"}, {"key": "C", "text": "Umbilicus and pubic symphysis"}, {"key": "D", "text": "Ischial tuberosity and pubic symphysis"}]'::jsonb, 'B', 'The mid-inguinal point (midway between ASIS and pubic symphysis) marks the femoral artery pulsation. This is different from the midpoint of the inguinal ligament (ASIS to pubic tubercle) which marks the deep inguinal ring. 📚 BD Chaurasia, Vol.2', 2, 'nucleux-content', '{}'),
  ('Anatomy', 'Femoral Triangle & Canal', 'Which structure in the femoral hernia is most commonly responsible for constriction leading to strangulation?', '[{"key": "A", "text": "Inguinal ligament"}, {"key": "B", "text": "Pectineal ligament"}, {"key": "C", "text": "Lacunar ligament"}, {"key": "D", "text": "Femoral vein"}]'::jsonb, 'C', 'The lacunar ligament (Gimbernat''s ligament) forms the sharp, rigid medial boundary of the femoral ring. Its cutting edge is the most common site of constriction in a strangulated femoral hernia. It may be incised to release the hernia, taking care to avoid an abnormal obturator artery. 📚 Gray''s Anatomy, 42nd Ed', 2, 'nucleux-content', '{}'),
  ('Anatomy', 'Knee Joint', 'The ''unhappy triad'' of the knee involves injury to:', '[{"key": "A", "text": "ACL, LCL, lateral meniscus"}, {"key": "B", "text": "ACL, MCL, medial meniscus"}, {"key": "C", "text": "PCL, MCL, medial meniscus"}, {"key": "D", "text": "PCL, LCL, lateral meniscus"}]'::jsonb, 'B', 'A lateral blow to the knee causes valgus stress → MCL tear, followed by ACL tear and medial meniscus tear (which is attached to MCL). This classic triad (O''Donoghue''s) is a common sports injury. 📚 BD Chaurasia, Vol.2', 1, 'nucleux-content', '{}'),
  ('Anatomy', 'Knee Joint', 'The most sensitive clinical test for ACL tear is:', '[{"key": "A", "text": "Anterior drawer test"}, {"key": "B", "text": "Lachman test"}, {"key": "C", "text": "McMurray test"}, {"key": "D", "text": "Pivot shift test"}]'::jsonb, 'B', 'Lachman test (performed at 20-30° knee flexion) is the most sensitive test for ACL tear. Anterior drawer test (at 90°) is less sensitive due to hamstring guarding. McMurray test is for meniscal tears. 📚 Gray''s Anatomy, 42nd Ed', 1, 'nucleux-content', '{}'),
  ('Anatomy', 'Knee Joint', 'Which muscle is called the ''key to the knee joint''?', '[{"key": "A", "text": "Quadriceps"}, {"key": "B", "text": "Popliteus"}, {"key": "C", "text": "Gastrocnemius"}, {"key": "D", "text": "Sartorius"}]'::jsonb, 'B', 'Popliteus initiates lateral rotation of the femur on the fixed tibia (or medial rotation of tibia on femur), unlocking the knee from its fully extended (locked) position to begin flexion. 📚 BD Chaurasia, Vol.2', 1, 'nucleux-content', '{}'),
  ('Anatomy', 'Knee Joint', 'The medial meniscus is more commonly injured than the lateral because it is:', '[{"key": "A", "text": "Smaller and more mobile"}, {"key": "B", "text": "Attached to the MCL and less mobile"}, {"key": "C", "text": "Attached to the LCL"}, {"key": "D", "text": "Avascular throughout"}]'::jsonb, 'B', 'The medial meniscus is firmly attached to the MCL, making it less mobile and more prone to injury during valgus stress. The lateral meniscus is not attached to the LCL and is more mobile, hence less commonly injured. 📚 Gray''s Anatomy, 42nd Ed', 1, 'nucleux-content', '{}'),
  ('Anatomy', 'Knee Joint', 'A Baker''s cyst is an enlargement of which bursa?', '[{"key": "A", "text": "Suprapatellar bursa"}, {"key": "B", "text": "Prepatellar bursa"}, {"key": "C", "text": "Semimembranosus bursa"}, {"key": "D", "text": "Infrapatellar bursa"}]'::jsonb, 'C', 'Baker''s (popliteal) cyst is a distension of the semimembranosus bursa, which communicates with the knee joint cavity in adults. It presents as a swelling in the popliteal fossa. Rupture mimics DVT. 📚 BD Chaurasia, Vol.2', 1, 'nucleux-content', '{}'),
  ('Anatomy', 'Circle of Willis & Brain Blood Supply', 'The most common site of berry aneurysm in the circle of Willis is:', '[{"key": "A", "text": "Middle cerebral artery bifurcation"}, {"key": "B", "text": "Posterior communicating artery"}, {"key": "C", "text": "Anterior communicating artery"}, {"key": "D", "text": "Basilar artery tip"}]'::jsonb, 'C', 'AComA is the most common site (40%) for berry aneurysms. PComA is second (30%), MCA bifurcation third (20%). Rupture causes subarachnoid hemorrhage with sudden severe headache. 📚 Gray''s Anatomy, 42nd Ed', 1, 'nucleux-content', '{}'),
  ('Anatomy', 'Circle of Willis & Brain Blood Supply', 'A patient presents with contralateral weakness predominantly affecting the face and arm, with Broca''s aphasia. Which artery is most likely occluded?', '[{"key": "A", "text": "Anterior cerebral artery"}, {"key": "B", "text": "Middle cerebral artery"}, {"key": "C", "text": "Posterior cerebral artery"}, {"key": "D", "text": "Basilar artery"}]'::jsonb, 'B', 'MCA supplies the lateral surface of the hemisphere including face/arm motor cortex and Broca''s area. Occlusion causes contralateral face+arm weakness (greater than leg) with aphasia in the dominant hemisphere. ACA occlusion would primarily affect the leg. 📚 Gray''s Anatomy, 42nd Ed', 1, 'nucleux-content', '{}'),
  ('Anatomy', 'Circle of Willis & Brain Blood Supply', 'The ''arteries of stroke'' (lenticulostriate arteries) are branches of:', '[{"key": "A", "text": "Anterior cerebral artery"}, {"key": "B", "text": "Middle cerebral artery"}, {"key": "C", "text": "Posterior cerebral artery"}, {"key": "D", "text": "Anterior choroidal artery"}]'::jsonb, 'B', 'Lenticulostriate arteries are perforating branches of the MCA that supply the internal capsule and basal ganglia. They are end arteries prone to rupture in hypertension, causing hemorrhagic stroke with contralateral hemiplegia. 📚 Gray''s Anatomy, 42nd Ed', 1, 'nucleux-content', '{}'),
  ('Anatomy', 'Circle of Willis & Brain Blood Supply', 'Lateral medullary syndrome (Wallenberg''s syndrome) results from occlusion of:', '[{"key": "A", "text": "AICA"}, {"key": "B", "text": "PICA"}, {"key": "C", "text": "Superior cerebellar artery"}, {"key": "D", "text": "Basilar artery"}]'::jsonb, 'B', 'PICA (posterior inferior cerebellar artery) occlusion causes lateral medullary syndrome: dysphagia, hoarseness, ipsilateral Horner''s syndrome, loss of pain/temp on ipsilateral face and contralateral body, cerebellar ataxia. 📚 Netter''s Atlas, 6th Ed', 2, 'nucleux-content', '{}'),
  ('Anatomy', 'Circle of Willis & Brain Blood Supply', 'Occlusion of the posterior cerebral artery causes:', '[{"key": "A", "text": "Contralateral hemiplegia"}, {"key": "B", "text": "Contralateral homonymous hemianopia with macular sparing"}, {"key": "C", "text": "Broca''s aphasia"}, {"key": "D", "text": "Contralateral leg weakness"}]'::jsonb, 'B', 'PCA supplies the occipital lobe (primary visual cortex). Occlusion causes contralateral homonymous hemianopia. Macular sparing occurs because the macular cortex has dual supply from PCA and MCA. 📚 Gray''s Anatomy, 42nd Ed', 2, 'nucleux-content', '{}'),
  ('Anatomy', 'Spinal Cord Cross-Section & Tracts', 'A patient presents with bilateral loss of pain and temperature sensation in the upper limbs (cape-like distribution) with preserved proprioception. The most likely diagnosis is:', '[{"key": "A", "text": "Brown-S\u00e9quard syndrome"}, {"key": "B", "text": "Syringomyelia"}, {"key": "C", "text": "Posterior cord syndrome"}, {"key": "D", "text": "Anterior cord syndrome"}]'::jsonb, 'B', 'Syringomyelia causes a central cord cavitation that first damages the anterior white commissure (where spinothalamic fibers cross), resulting in bilateral suspended loss of pain/temperature. Dorsal columns (proprioception) are preserved. Cape-like distribution is classic. 📚 Gray''s Anatomy, 42nd Ed', 1, 'nucleux-content', '{}'),
  ('Anatomy', 'Spinal Cord Cross-Section & Tracts', 'In Brown-Séquard syndrome, the loss of pain and temperature is:', '[{"key": "A", "text": "Ipsilateral to the lesion"}, {"key": "B", "text": "Contralateral to the lesion"}, {"key": "C", "text": "Bilateral"}, {"key": "D", "text": "Not affected"}]'::jsonb, 'B', 'The spinothalamic tract crosses in the anterior white commissure 1-2 segments above entry, then ascends contralaterally. In cord hemisection, spinothalamic damage causes contralateral pain/temperature loss. Motor and proprioception loss are ipsilateral (corticospinal and dorsal columns are uncrossed at spinal level). 📚 BD Chaurasia, Vol.3', 1, 'nucleux-content', '{}'),
  ('Anatomy', 'Spinal Cord Cross-Section & Tracts', 'The dorsal columns carry all of the following EXCEPT:', '[{"key": "A", "text": "Fine touch"}, {"key": "B", "text": "Proprioception"}, {"key": "C", "text": "Pain"}, {"key": "D", "text": "Vibration"}]'::jsonb, 'C', 'Dorsal columns (fasciculus gracilis and cuneatus) carry fine touch, proprioception, vibration, and 2-point discrimination. Pain and temperature travel via the lateral spinothalamic tract. 📚 Gray''s Anatomy, 42nd Ed', 1, 'nucleux-content', '{}'),
  ('Anatomy', 'Spinal Cord Cross-Section & Tracts', 'At which level does the spinal cord terminate in adults?', '[{"key": "A", "text": "T12"}, {"key": "B", "text": "L1-L2"}, {"key": "C", "text": "L3-L4"}, {"key": "D", "text": "S1-S2"}]'::jsonb, 'B', 'The conus medullaris (terminal end of the spinal cord) is at L1-L2 in adults (L3 in newborns). Below this is the cauda equina (nerve roots). Lumbar puncture is performed at L3-L4 or L4-L5 to avoid cord injury. 📚 BD Chaurasia, Vol.3', 1, 'nucleux-content', '{}'),
  ('Anatomy', 'Spinal Cord Cross-Section & Tracts', 'Subacute combined degeneration of the spinal cord (vitamin B12 deficiency) affects which tracts?', '[{"key": "A", "text": "Spinothalamic + anterior corticospinal"}, {"key": "B", "text": "Dorsal columns + lateral corticospinal"}, {"key": "C", "text": "Dorsal columns + spinothalamic"}, {"key": "D", "text": "Lateral corticospinal + rubrospinal"}]'::jsonb, 'B', 'B12 deficiency causes demyelination of dorsal columns (loss of proprioception, vibration — sensory ataxia) and lateral corticospinal tracts (UMN signs — spasticity, Babinski). Combined = both sensory and motor tracts. Spinothalamic tracts are typically spared. 📚 Gray''s Anatomy, 42nd Ed', 2, 'nucleux-content', '{}'),
  ('Anatomy', 'Perineum & Pelvic Floor', 'The puborectalis muscle is important for maintaining fecal continence by:', '[{"key": "A", "text": "Constricting the anal canal"}, {"key": "B", "text": "Maintaining the anorectal angle"}, {"key": "C", "text": "Compressing the rectum"}, {"key": "D", "text": "Supporting the bladder neck"}]'::jsonb, 'B', 'Puborectalis forms a U-shaped sling around the anorectal junction, maintaining the anorectal angle at approximately 90°. This kink acts as a valve mechanism for fecal continence. Relaxation during defecation straightens the angle. 📚 BD Chaurasia, Vol.2, Ch.21', 1, 'nucleux-content', '{}'),
  ('Anatomy', 'Perineum & Pelvic Floor', 'A pudendal nerve block is administered at which landmark?', '[{"key": "A", "text": "Pubic tubercle"}, {"key": "B", "text": "Ischial tuberosity"}, {"key": "C", "text": "Ischial spine"}, {"key": "D", "text": "Sacral hiatus"}]'::jsonb, 'C', 'The pudendal nerve (S2,3,4) hooks around the ischial spine as it passes from the greater to lesser sciatic foramen. Pudendal nerve block is administered transvaginally at the ischial spine for perineal anesthesia during childbirth. 📚 Gray''s Anatomy, 42nd Ed', 1, 'nucleux-content', '{}'),
  ('Anatomy', 'Perineum & Pelvic Floor', 'The pudendal (Alcock''s) canal is located on the lateral wall of which structure?', '[{"key": "A", "text": "Pelvic cavity"}, {"key": "B", "text": "Urogenital triangle"}, {"key": "C", "text": "Ischioanal fossa"}, {"key": "D", "text": "Obturator canal"}]'::jsonb, 'C', 'Alcock''s canal is a fascial canal within the obturator internus fascia on the lateral wall of the ischioanal fossa. It transmits the pudendal nerve and internal pudendal vessels. 📚 BD Chaurasia, Vol.2, Ch.21', 2, 'nucleux-content', '{}'),
  ('Anatomy', 'Perineum & Pelvic Floor', 'Which structure forms the roof of the ischioanal fossa?', '[{"key": "A", "text": "Obturator internus"}, {"key": "B", "text": "Levator ani"}, {"key": "C", "text": "Perineal membrane"}, {"key": "D", "text": "Gluteus maximus"}]'::jsonb, 'B', 'The ischioanal fossa has levator ani as its medial wall/roof (sloping), obturator internus as lateral wall, sacrotuberous ligament posteriorly, and posterior edge of perineal membrane anteriorly. 📚 BD Chaurasia, Vol.2', 2, 'nucleux-content', '{}'),
  ('Anatomy', 'Perineum & Pelvic Floor', 'The perineal body is located between the:', '[{"key": "A", "text": "Anal canal and coccyx"}, {"key": "B", "text": "Anal canal and vagina/bulb of penis"}, {"key": "C", "text": "Urethra and vagina"}, {"key": "D", "text": "Pubic symphysis and coccyx"}]'::jsonb, 'B', 'The perineal body (central tendon of perineum) is a fibromuscular node located between the anal canal posteriorly and the vagina (females) or bulb of penis (males) anteriorly. It is the central anchor point for perineal muscles. 📚 BD Chaurasia, Vol.2, Ch.21', 1, 'nucleux-content', '{}'),
  ('Anatomy', 'Blood Supply of Heart (Coronary Arteries)', 'Which coronary artery is known as the ''artery of sudden death''?', '[{"key": "A", "text": "Right coronary artery"}, {"key": "B", "text": "Left circumflex artery"}, {"key": "C", "text": "Left anterior descending artery"}, {"key": "D", "text": "Posterior descending artery"}]'::jsonb, 'C', 'LAD supplies the largest territory of myocardium (anterior wall + anterior 2/3 of septum). Its occlusion causes massive anterior MI with highest risk of cardiogenic shock and sudden death. 📚 Netter''s Atlas, 6th Ed', 1, 'nucleux-content', '{}'),
  ('Anatomy', 'Blood Supply of Heart (Coronary Arteries)', 'In the most common pattern of coronary dominance, the posterior descending artery arises from:', '[{"key": "A", "text": "Left anterior descending artery"}, {"key": "B", "text": "Left circumflex artery"}, {"key": "C", "text": "Right coronary artery"}, {"key": "D", "text": "Left main coronary artery"}]'::jsonb, 'C', 'Right dominance (85%) means the PDA arises from the RCA. Left dominance (10%) has PDA from LCx. The PDA runs in the posterior interventricular groove and supplies the posterior 1/3 of the interventricular septum. 📚 Gray''s Anatomy, 42nd Ed', 1, 'nucleux-content', '{}'),
  ('Anatomy', 'Blood Supply of Heart (Coronary Arteries)', 'The SA node is most commonly supplied by a branch of:', '[{"key": "A", "text": "Left anterior descending artery"}, {"key": "B", "text": "Left circumflex artery"}, {"key": "C", "text": "Right coronary artery"}, {"key": "D", "text": "Posterior descending artery"}]'::jsonb, 'C', 'The SA nodal artery arises from the RCA in 60% and from LCx in 40%. Similarly, the AV nodal artery arises from the RCA (via PDA) in 80% of cases. RCA occlusion can therefore cause SA/AV node dysfunction. 📚 Gray''s Anatomy, 42nd Ed', 1, 'nucleux-content', '{}'),
  ('Anatomy', 'Blood Supply of Heart (Coronary Arteries)', 'The coronary sinus drains into which chamber of the heart?', '[{"key": "A", "text": "Left atrium"}, {"key": "B", "text": "Right atrium"}, {"key": "C", "text": "Left ventricle"}, {"key": "D", "text": "Right ventricle"}]'::jsonb, 'B', 'The coronary sinus runs in the posterior AV groove and opens into the right atrium between the opening of the IVC and the tricuspid valve. Its opening is guarded by the valve of Thebesius. 📚 Gray''s Anatomy, 42nd Ed, Ch.56', 1, 'nucleux-content', '{}'),
  ('Anatomy', 'Blood Supply of Heart (Coronary Arteries)', 'A patient with inferior wall MI on ECG (ST elevation in II, III, aVF) develops complete heart block. Which artery is most likely occluded?', '[{"key": "A", "text": "Left anterior descending"}, {"key": "B", "text": "Left circumflex"}, {"key": "C", "text": "Right coronary artery"}, {"key": "D", "text": "Diagonal branch"}]'::jsonb, 'C', 'RCA supplies the inferior wall of the LV (via PDA) and the AV node (in 80%). Occlusion causes inferior MI (II, III, aVF) with AV nodal block. LAD causes anterior MI. LCx causes lateral MI. 📚 Netter''s Atlas, 6th Ed; 📚 Gray''s Anatomy, 42nd Ed', 2, 'nucleux-content', '{}'),
  ('Anatomy', 'Diaphragm', 'Which structure passes through the esophageal hiatus of the diaphragm along with the esophagus?', '[{"key": "A", "text": "Thoracic duct"}, {"key": "B", "text": "Azygos vein"}, {"key": "C", "text": "Vagal trunks"}, {"key": "D", "text": "Inferior vena cava"}]'::jsonb, 'C', 'The esophageal hiatus (T10, in right crus) transmits the esophagus and vagal trunks (anterior = left vagus, posterior = right vagus). Thoracic duct and azygos pass through aortic hiatus. IVC through caval opening. 📚 Gray''s Anatomy, 42nd Ed', 1, 'nucleux-content', '{}'),
  ('Anatomy', 'Diaphragm', 'A neonate presents with respiratory distress immediately after birth. Chest X-ray shows bowel loops in the left hemithorax. What is the most likely diagnosis?', '[{"key": "A", "text": "Morgagni hernia"}, {"key": "B", "text": "Bochdalek hernia"}, {"key": "C", "text": "Hiatus hernia"}, {"key": "D", "text": "Eventration of diaphragm"}]'::jsonb, 'B', 'Bochdalek hernia is a posterolateral congenital diaphragmatic hernia, more common on the LEFT side (pleuroperitoneal membrane closes later on left). Presents with respiratory distress in neonates. Morgagni is anterior and usually presents later in life. 📚 Gray''s Anatomy, 42nd Ed', 1, 'nucleux-content', '{}'),
  ('Anatomy', 'Diaphragm', 'The phrenic nerve is derived from which cervical segments?', '[{"key": "A", "text": "C1, C2, C3"}, {"key": "B", "text": "C3, C4, C5"}, {"key": "C", "text": "C4, C5, C6"}, {"key": "D", "text": "C5, C6, C7"}]'::jsonb, 'B', '"C3, 4, 5 keeps the diaphragm alive." The phrenic nerve (primarily C4, with contributions from C3 and C5) is the sole motor nerve to the diaphragm. It also provides sensory supply to the central diaphragm, pericardium, and mediastinal pleura. 📚 BD Chaurasia, Vol.1', 1, 'nucleux-content', '{}'),
  ('Anatomy', 'Diaphragm', 'Referred pain to the shoulder tip from subphrenic abscess is mediated by which nerve?', '[{"key": "A", "text": "Intercostal nerves"}, {"key": "B", "text": "Vagus nerve"}, {"key": "C", "text": "Phrenic nerve"}, {"key": "D", "text": "Splanchnic nerves"}]'::jsonb, 'C', 'The central diaphragm is innervated by the phrenic nerve (C3-C5). Irritation refers pain to the shoulder tip (C3-C5 dermatome — supraclavicular nerves). This is Kehr''s sign when caused by splenic rupture. 📚 BD Chaurasia, Vol.1', 1, 'nucleux-content', '{}'),
  ('Anatomy', 'Diaphragm', 'The aortic hiatus of the diaphragm is located at the level of which vertebra?', '[{"key": "A", "text": "T8"}, {"key": "B", "text": "T10"}, {"key": "C", "text": "T12"}, {"key": "D", "text": "L1"}]'::jsonb, 'C', 'The aortic hiatus is at T12 level, behind the diaphragm between the crura and median arcuate ligament. It transmits the aorta, thoracic duct, and azygos vein. T8 = IVC (caval opening), T10 = esophagus. 📚 Gray''s Anatomy, 42nd Ed', 1, 'nucleux-content', '{}'),
  ('Anatomy', 'Mediastinum', 'The sternal angle (angle of Louis) corresponds to the level of which vertebra?', '[{"key": "A", "text": "T2"}, {"key": "B", "text": "T4-T5"}, {"key": "C", "text": "T6"}, {"key": "D", "text": "T8"}]'::jsonb, 'B', 'The sternal angle marks the junction of manubrium and body of sternum at T4-T5 level. It is a key landmark for tracheal bifurcation, beginning/end of aortic arch, and the 2nd costal cartilage. 📚 BD Chaurasia, Vol.1', 1, 'nucleux-content', '{}'),
  ('Anatomy', 'Mediastinum', 'Which of the following is the most common tumor of the posterior mediastinum?', '[{"key": "A", "text": "Thymoma"}, {"key": "B", "text": "Lymphoma"}, {"key": "C", "text": "Neurogenic tumor"}, {"key": "D", "text": "Teratoma"}]'::jsonb, 'C', 'Neurogenic tumors (schwannoma, neurofibroma, ganglioneuroma) are the most common posterior mediastinal masses. Thymoma and teratoma are anterior mediastinal. Lymphoma can occur in any compartment but classically anterior. 📚 Gray''s Anatomy, 42nd Ed', 1, 'nucleux-content', '{}'),
  ('Anatomy', 'Mediastinum', 'The left recurrent laryngeal nerve hooks around which structure?', '[{"key": "A", "text": "Right subclavian artery"}, {"key": "B", "text": "Aortic arch"}, {"key": "C", "text": "Pulmonary trunk"}, {"key": "D", "text": "Left common carotid artery"}]'::jsonb, 'B', 'The left RLN loops under the aortic arch (at the level of ligamentum arteriosum) before ascending in the tracheoesophageal groove. The right RLN hooks under the right subclavian artery. 📚 BD Chaurasia, Vol.1', 1, 'nucleux-content', '{}'),
  ('Anatomy', 'Mediastinum', 'A 60-year-old smoker presents with facial swelling, distended neck veins, and cyanosis. Which structure is most likely compressed?', '[{"key": "A", "text": "Thoracic duct"}, {"key": "B", "text": "Superior vena cava"}, {"key": "C", "text": "Aortic arch"}, {"key": "D", "text": "Left brachiocephalic vein"}]'::jsonb, 'B', 'This is SVC syndrome — compression of the SVC in the superior/middle mediastinum, commonly by lung carcinoma or lymphoma. Causes venous congestion of head, neck, and upper limbs. 📚 Gray''s Anatomy, 42nd Ed', 1, 'nucleux-content', '{}'),
  ('Anatomy', 'Mediastinum', 'Which mediastinal compartment contains the thoracic duct and esophagus?', '[{"key": "A", "text": "Superior mediastinum only"}, {"key": "B", "text": "Anterior mediastinum"}, {"key": "C", "text": "Middle mediastinum"}, {"key": "D", "text": "Posterior mediastinum"}]'::jsonb, 'D', 'The posterior mediastinum (between pericardium and vertebral column) contains the esophagus (lower 2/3), descending thoracic aorta, thoracic duct, azygos/hemiazygos veins, vagus nerves, and sympathetic trunks. The esophagus and thoracic duct also pass through the superior mediastinum, but "posterior" is the best answer. 📚 BD Chaurasia, Vol.1', 2, 'nucleux-content', '{}'),
  ('Anatomy', 'Brachial Plexus', 'A newborn delivered after shoulder dystocia presents with the arm adducted, medially rotated, forearm pronated, and wrist flexed. Which nerve roots are most likely injured?', '[{"key": "A", "text": "C5, C6"}, {"key": "B", "text": "C8, T1"}, {"key": "C", "text": "C7"}, {"key": "D", "text": "C5, C6, C7, C8, T1"}]'::jsonb, 'A', 'This is Erb-Duchenne palsy (waiter''s tip position) due to upper trunk injury at Erb''s point (C5,C6). Klumpke''s (C8,T1) causes claw hand. C7 injury would affect wrist/finger extension. 📚 BD Chaurasia, Vol.1, Ch.4', 1, 'nucleux-content', '{}'),
  ('Anatomy', 'Brachial Plexus', 'Winging of the scapula results from injury to which nerve?', '[{"key": "A", "text": "Dorsal scapular nerve"}, {"key": "B", "text": "Long thoracic nerve"}, {"key": "C", "text": "Suprascapular nerve"}, {"key": "D", "text": "Thoracodorsal nerve"}]'::jsonb, 'B', 'Long thoracic nerve (C5,6,7) supplies serratus anterior, which holds the scapula against the chest wall. Its injury causes medial winging. Dorsal scapular nerve supplies rhomboids. Suprascapular supplies supraspinatus and infraspinatus. Thoracodorsal supplies latissimus dorsi. 📚 Gray''s Anatomy, 42nd Ed', 1, 'nucleux-content', '{}'),
  ('Anatomy', 'Brachial Plexus', 'A patient with a stab wound in the posterior triangle of the neck has loss of shoulder abduction beyond 15° and loss of sensation over the regimental badge area. Which nerve is injured?', '[{"key": "A", "text": "Radial nerve"}, {"key": "B", "text": "Suprascapular nerve"}, {"key": "C", "text": "Axillary nerve"}, {"key": "D", "text": "Musculocutaneous nerve"}]'::jsonb, 'C', 'Axillary nerve (C5,C6, posterior cord) supplies deltoid (abduction 15-90°) and teres minor, with cutaneous supply to regimental badge area (lateral aspect of upper arm). Suprascapular nerve supplies supraspinatus (0-15° abduction) and infraspinatus. 📚 Netter''s Atlas, 6th Ed, Plate 416', 2, 'nucleux-content', '{}'),
  ('Anatomy', 'Brachial Plexus', 'The cords of the brachial plexus are named in relation to which structure?', '[{"key": "A", "text": "First part of axillary artery"}, {"key": "B", "text": "Second part of axillary artery"}, {"key": "C", "text": "Third part of axillary artery"}, {"key": "D", "text": "Subclavian artery"}]'::jsonb, 'B', 'The lateral, medial, and posterior cords are named by their position relative to the second part of the axillary artery (behind pectoralis minor). The first part has no cord relation; the third part has the terminal branches around it. 📚 BD Chaurasia, Vol.1, Ch.4', 1, 'nucleux-content', '{}'),
  ('Anatomy', 'Brachial Plexus', 'A patient presents with claw hand and Horner''s syndrome after a motorcycle accident. Which part of the brachial plexus is most likely damaged?', '[{"key": "A", "text": "Upper trunk"}, {"key": "B", "text": "Middle trunk"}, {"key": "C", "text": "Lower trunk"}, {"key": "D", "text": "Posterior cord"}]'::jsonb, 'C', 'Klumpke''s palsy involves lower trunk (C8,T1) — causes claw hand (loss of intrinsic hand muscles via ulnar + T1 median). Horner''s syndrome (miosis, ptosis, anhidrosis) occurs when T1 sympathetic fibers are disrupted. Upper trunk injury causes Erb''s palsy. 📚 Gray''s Anatomy, 42nd Ed; 📚 BD Chaurasia, Vol.1', 2, 'nucleux-content', '{}'),
  ('Anatomy', 'Hand Anatomy (Spaces, Tendons)', 'The carpal tunnel contains all of the following EXCEPT:', '[{"key": "A", "text": "Flexor digitorum superficialis tendons"}, {"key": "B", "text": "Median nerve"}, {"key": "C", "text": "Ulnar nerve"}, {"key": "D", "text": "Flexor pollicis longus tendon"}]'::jsonb, 'C', 'The ulnar nerve passes through Guyon''s canal (between pisiform and hook of hamate), NOT the carpal tunnel. The carpal tunnel contains 9 tendons (4 FDS, 4 FDP, 1 FPL) and the median nerve. 📚 BD Chaurasia, Vol.1', 1, 'nucleux-content', '{}'),
  ('Anatomy', 'Hand Anatomy (Spaces, Tendons)', 'Ulnar nerve injury at the wrist causes claw hand affecting which fingers?', '[{"key": "A", "text": "Index and middle"}, {"key": "B", "text": "Ring and little"}, {"key": "C", "text": "All fingers"}, {"key": "D", "text": "Thumb only"}]'::jsonb, 'B', 'Ulnar nerve supplies the 3rd and 4th lumbricals (ring and little fingers). Loss of lumbrical action → unopposed EDC at MCP (hyperextension) with intact FDP at IP (flexion) → clawing of ring and little fingers. Index and middle lumbricals (median nerve) are intact. 📚 Gray''s Anatomy, 42nd Ed', 1, 'nucleux-content', '{}'),
  ('Anatomy', 'Hand Anatomy (Spaces, Tendons)', 'Froment''s sign tests for paralysis of which muscle?', '[{"key": "A", "text": "First dorsal interosseous"}, {"key": "B", "text": "Adductor pollicis"}, {"key": "C", "text": "Opponens pollicis"}, {"key": "D", "text": "Flexor pollicis brevis"}]'::jsonb, 'B', 'Froment''s sign: patient grips paper between thumb and index finger. With adductor pollicis paralysis (ulnar nerve), the thumb IP joint flexes (FPL, median nerve substitutes) instead of adducting at MCP. 📚 BD Chaurasia, Vol.1', 2, 'nucleux-content', '{}'),
  ('Anatomy', 'Hand Anatomy (Spaces, Tendons)', 'The ''ulnar paradox'' refers to:', '[{"key": "A", "text": "More clawing with higher ulnar nerve lesion"}, {"key": "B", "text": "Less clawing with higher ulnar nerve lesion"}, {"key": "C", "text": "Clawing only in median nerve injury"}, {"key": "D", "text": "No clawing in combined nerve injury"}]'::jsonb, 'B', 'In high ulnar nerve lesion (above elbow), FDP to ring and little fingers is also paralyzed (in addition to intrinsic muscles). Without FDP action, the IP joints cannot flex → less obvious clawing. Low lesion (at wrist): lumbricals lost but FDP intact → more pronounced clawing. 📚 Gray''s Anatomy, 42nd Ed', 2, 'nucleux-content', '{}'),
  ('Anatomy', 'Hand Anatomy (Spaces, Tendons)', 'Infection in the radial bursa can spread to form a horseshoe abscess by communicating through:', '[{"key": "A", "text": "Midpalmar space"}, {"key": "B", "text": "Thenar space"}, {"key": "C", "text": "Space of Parona"}, {"key": "D", "text": "Dorsal subaponeurotic space"}]'::jsonb, 'C', 'The radial bursa (thumb flexor sheath) and ulnar bursa (little finger sheath) can communicate through the space of Parona (anterior to pronator quadratus in the distal forearm), forming a horseshoe abscess. 📚 BD Chaurasia, Vol.1', 2, 'nucleux-content', '{}'),
  ('Biochemistry', 'Carbohydrate Metabolism (Glycolysis, TCA, Gluconeogenesis)', 'Which enzyme catalyzes the rate-limiting step of glycolysis?', '[{"key": "A", "text": "Hexokinase"}, {"key": "B", "text": "Phosphofructokinase-1"}, {"key": "C", "text": "Pyruvate kinase"}, {"key": "D", "text": "Aldolase"}]'::jsonb, 'B', 'PFK-1 catalyzes F6P→F1,6BP and is the committed/rate-limiting step of glycolysis. It is allosterically activated by AMP and F2,6BP, and inhibited by ATP and citrate. 📚 Harper''s Biochemistry, 31st Ed, Ch.17', 1, 'nucleux-content', '{}'),
  ('Biochemistry', 'Carbohydrate Metabolism (Glycolysis, TCA, Gluconeogenesis)', 'A patient with Von Gierke disease has severe fasting hypoglycemia because of deficiency of:', '[{"key": "A", "text": "Glucose-6-phosphatase"}, {"key": "B", "text": "Liver phosphorylase"}, {"key": "C", "text": "Debranching enzyme"}, {"key": "D", "text": "Pyruvate carboxylase"}]'::jsonb, 'A', 'Von Gierke disease (GSD Type I) = glucose-6-phosphatase deficiency. This enzyme catalyzes the final step of both gluconeogenesis and glycogenolysis. Without it, the liver cannot release free glucose into the blood. 📚 Harper''s Biochemistry, 31st Ed, Ch.20', 1, 'nucleux-content', '{}'),
  ('Biochemistry', 'Carbohydrate Metabolism (Glycolysis, TCA, Gluconeogenesis)', 'Which TCA cycle intermediate is used for heme synthesis?', '[{"key": "A", "text": "Citrate"}, {"key": "B", "text": "\u03b1-Ketoglutarate"}, {"key": "C", "text": "Succinyl-CoA"}, {"key": "D", "text": "Oxaloacetate"}]'::jsonb, 'C', 'Succinyl-CoA + glycine → δ-aminolevulinic acid (ALA), the first step of heme synthesis catalyzed by ALA synthase. This is a key drain on TCA cycle intermediates. 📚 Harper''s Biochemistry, 31st Ed, Ch.18,31', 2, 'nucleux-content', '{}'),
  ('Biochemistry', 'Carbohydrate Metabolism (Glycolysis, TCA, Gluconeogenesis)', 'The most potent activator of PFK-1 and inhibitor of fructose-1,6-bisphosphatase is:', '[{"key": "A", "text": "ATP"}, {"key": "B", "text": "Citrate"}, {"key": "C", "text": "Fructose-2,6-bisphosphate"}, {"key": "D", "text": "AMP"}]'::jsonb, 'C', 'F2,6BP is the master regulator that reciprocally controls glycolysis (activates PFK-1) and gluconeogenesis (inhibits F1,6BPase). Its levels are controlled by the bifunctional enzyme PFK-2/FBPase-2. 📚 Stryer Biochemistry, Ch.16', 2, 'nucleux-content', '{}'),
  ('Biochemistry', 'Carbohydrate Metabolism (Glycolysis, TCA, Gluconeogenesis)', 'In the Cori cycle, which substrate is transported from muscle to liver?', '[{"key": "A", "text": "Alanine"}, {"key": "B", "text": "Lactate"}, {"key": "C", "text": "Pyruvate"}, {"key": "D", "text": "Glucose-6-phosphate"}]'::jsonb, 'B', 'The Cori cycle: muscle produces lactate (anaerobic glycolysis) → lactate travels to liver → liver converts lactate back to glucose (gluconeogenesis) → glucose returns to muscle. Alanine is transported in the glucose-alanine cycle (different cycle). 📚 Harper''s Biochemistry, 31st Ed, Ch.20', 1, 'nucleux-content', '{}'),
  ('Biochemistry', 'Inborn Errors of Metabolism', 'A newborn screening test shows elevated phenylalanine levels. The enzyme deficiency is:', '[{"key": "A", "text": "Tyrosinase"}, {"key": "B", "text": "Phenylalanine hydroxylase"}, {"key": "C", "text": "Homogentisic acid oxidase"}, {"key": "D", "text": "Cystathionine \u03b2-synthase"}]'::jsonb, 'B', 'PKU = phenylalanine hydroxylase deficiency → cannot convert Phe to Tyr → ↑Phe. Without dietary restriction, causes severe intellectual disability. 📚 Harper''s Biochemistry, 31st Ed, Ch.29', 1, 'nucleux-content', '{}'),
  ('Biochemistry', 'Inborn Errors of Metabolism', 'Which lysosomal storage disease is characterized by ''crinkled paper'' macrophages?', '[{"key": "A", "text": "Tay-Sachs disease"}, {"key": "B", "text": "Niemann-Pick disease"}, {"key": "C", "text": "Gaucher''s disease"}, {"key": "D", "text": "Fabry''s disease"}]'::jsonb, 'C', 'Gaucher''s disease: glucocerebrosidase deficiency → glucocerebroside accumulates in macrophages giving them a characteristic "crinkled tissue paper" appearance on histology. 📚 Stryer Biochemistry, Ch.23', 1, 'nucleux-content', '{}'),
  ('Biochemistry', 'Inborn Errors of Metabolism', 'A child with exercise intolerance has no rise in blood lactate after ischemic forearm exercise. The diagnosis is:', '[{"key": "A", "text": "Von Gierke disease"}, {"key": "B", "text": "Pompe disease"}, {"key": "C", "text": "McArdle disease"}, {"key": "D", "text": "Cori disease"}]'::jsonb, 'C', 'McArdle disease (GSD V) = muscle glycogen phosphorylase deficiency. Muscle cannot break down glycogen → no pyruvate → no lactate production during exercise. Second wind phenomenon occurs when fatty acids are mobilized as alternative fuel. 📚 Harper''s Biochemistry, 31st Ed, Ch.44', 2, 'nucleux-content', '{}'),
  ('Biochemistry', 'Inborn Errors of Metabolism', 'Downward subluxation of the lens is characteristic of:', '[{"key": "A", "text": "Marfan syndrome"}, {"key": "B", "text": "Homocystinuria"}, {"key": "C", "text": "Ehlers-Danlos syndrome"}, {"key": "D", "text": "PKU"}]'::jsonb, 'B', 'Homocystinuria → downward lens subluxation (inferonasal). Marfan syndrome → upward (superotemporal). Both have marfanoid habitus but are distinguished by lens direction and thrombotic tendency (homocystinuria). 📚 Harper''s Biochemistry, 31st Ed, Ch.29', 2, 'nucleux-content', '{}'),
  ('Biochemistry', 'Inborn Errors of Metabolism', 'Which is the ONLY glycogen storage disease with lysosomal glycogen accumulation?', '[{"key": "A", "text": "Von Gierke (Type I)"}, {"key": "B", "text": "Pompe (Type II)"}, {"key": "C", "text": "Cori (Type III)"}, {"key": "D", "text": "McArdle (Type V)"}]'::jsonb, 'B', 'Pompe disease = acid maltase (lysosomal α-1,4-glucosidase) deficiency. Glycogen accumulates INSIDE lysosomes (unlike other GSDs where it''s cytoplasmic). Presents with cardiomegaly and hypotonia. 📚 Harper''s Biochemistry, 31st Ed, Ch.44', 1, 'nucleux-content', '{}'),
  ('Biochemistry', 'Porphyrin Metabolism & Heme Synthesis', 'The rate-limiting enzyme of heme synthesis is:', '[{"key": "A", "text": "ALA dehydratase"}, {"key": "B", "text": "ALA synthase"}, {"key": "C", "text": "Ferrochelatase"}, {"key": "D", "text": "PBG deaminase"}]'::jsonb, 'B', 'ALA synthase catalyzes the first and rate-limiting step: succinyl-CoA + glycine → ALA. It requires PLP (B6) and is subject to feedback inhibition by heme. 📚 Harper''s Biochemistry, 31st Ed, Ch.31', 1, 'nucleux-content', '{}'),
  ('Biochemistry', 'Porphyrin Metabolism & Heme Synthesis', 'Lead poisoning causes sideroblastic anemia by inhibiting which two enzymes?', '[{"key": "A", "text": "ALA synthase and PBG deaminase"}, {"key": "B", "text": "ALA dehydratase and ferrochelatase"}, {"key": "C", "text": "Uroporphyrinogen decarboxylase and coproporphyrinogen oxidase"}, {"key": "D", "text": "Heme oxygenase and biliverdin reductase"}]'::jsonb, 'B', 'Lead inhibits ALA dehydratase (↑ALA) and ferrochelatase (↑protoporphyrin IX, cannot insert Fe²+). Result: sideroblastic anemia with ringed sideroblasts, basophilic stippling. 📚 Harper''s Biochemistry, 31st Ed, Ch.31', 2, 'nucleux-content', '{}'),
  ('Biochemistry', 'Porphyrin Metabolism & Heme Synthesis', 'A young woman has recurrent attacks of severe abdominal pain with port-wine colored urine. The most likely diagnosis is:', '[{"key": "A", "text": "Porphyria cutanea tarda"}, {"key": "B", "text": "Acute intermittent porphyria"}, {"key": "C", "text": "Erythropoietic protoporphyria"}, {"key": "D", "text": "Gilbert syndrome"}]'::jsonb, 'B', 'AIP = PBG deaminase deficiency → ↑ALA and PBG in urine (oxidize to port-wine color). Acute abdominal pain + neuropsychiatric symptoms + NO skin lesions. Autosomal dominant. 📚 Harper''s Biochemistry, 31st Ed, Ch.31', 2, 'nucleux-content', '{}'),
  ('Biochemistry', 'Porphyrin Metabolism & Heme Synthesis', 'In obstructive jaundice, which of the following is expected?', '[{"key": "A", "text": "\u2191Unconjugated bilirubin, dark stools"}, {"key": "B", "text": "\u2191Conjugated bilirubin, pale stools, dark urine"}, {"key": "C", "text": "\u2191Urobilinogen in urine"}, {"key": "D", "text": "Normal ALP"}]'::jsonb, 'B', 'Obstruction prevents conjugated bilirubin from reaching the gut → no stercobilin (pale stools), CB backs up into blood and spills into urine (dark urine/cola colored). ALP is markedly elevated. 📚 Harper''s Biochemistry, 31st Ed, Ch.32', 1, 'nucleux-content', '{}'),
  ('Biochemistry', 'Porphyrin Metabolism & Heme Synthesis', 'Gilbert syndrome is characterized by:', '[{"key": "A", "text": "Absent UDP-glucuronosyltransferase"}, {"key": "B", "text": "Mild decrease in UGT activity with benign unconjugated hyperbilirubinemia"}, {"key": "C", "text": "Elevated conjugated bilirubin"}, {"key": "D", "text": "Kernicterus in neonates"}]'::jsonb, 'B', 'Gilbert syndrome = common (5-10%), benign, mild ↓UGT activity. Mild jaundice exacerbated by fasting/stress/illness. No treatment needed. Crigler-Najjar Type I = absent UGT, severe. 📚 Harper''s Biochemistry, 31st Ed, Ch.32', 1, 'nucleux-content', '{}'),
  ('Biochemistry', 'Enzyme Kinetics (Michaelis-Menten, Lineweaver-Burk)', 'In a Lineweaver-Burk plot, a competitive inhibitor causes lines that intersect at which point?', '[{"key": "A", "text": "X-axis"}, {"key": "B", "text": "Y-axis"}, {"key": "C", "text": "Origin"}, {"key": "D", "text": "Lines are parallel"}]'::jsonb, 'B', 'Competitive inhibitors increase apparent Km but do not change Vmax. On a Lineweaver-Burk plot, 1/Vmax (Y-intercept) remains the same, so lines converge on the Y-axis. The X-intercept (-1/Km) shifts closer to zero (apparent Km increases). 📚 Stryer Biochemistry, Ch.8', 1, 'nucleux-content', '{}'),
  ('Biochemistry', 'Enzyme Kinetics (Michaelis-Menten, Lineweaver-Burk)', 'An enzyme has a Km of 2 mM. At what substrate concentration will the reaction velocity be 75% of Vmax?', '[{"key": "A", "text": "2 mM"}, {"key": "B", "text": "4 mM"}, {"key": "C", "text": "6 mM"}, {"key": "D", "text": "8 mM"}]'::jsonb, 'C', 'Using V = Vmax[S]/(Km+[S]): 0.75Vmax = Vmax[S]/(2+[S]). Solving: 0.75(2+[S]) = [S]; 1.5 + 0.75[S] = [S]; 1.5 = 0.25[S]; [S] = 6 mM. 📚 Harper''s Biochemistry, 31st Ed, Ch.8', 2, 'nucleux-content', '{}'),
  ('Biochemistry', 'Enzyme Kinetics (Michaelis-Menten, Lineweaver-Burk)', 'Which type of enzyme inhibition shows parallel lines on a Lineweaver-Burk plot?', '[{"key": "A", "text": "Competitive"}, {"key": "B", "text": "Non-competitive"}, {"key": "C", "text": "Uncompetitive"}, {"key": "D", "text": "Mixed"}]'::jsonb, 'C', 'Uncompetitive inhibitors bind only the ES complex, decreasing both apparent Km and Vmax by the same factor. This produces parallel lines on Lineweaver-Burk plot (same slope = Km/Vmax). 📚 Stryer Biochemistry, Ch.8', 2, 'nucleux-content', '{}'),
  ('Biochemistry', 'Enzyme Kinetics (Michaelis-Menten, Lineweaver-Burk)', 'Methotrexate inhibits dihydrofolate reductase. This inhibition can be overcome by increasing substrate concentration. What type of inhibition is this?', '[{"key": "A", "text": "Non-competitive"}, {"key": "B", "text": "Uncompetitive"}, {"key": "C", "text": "Competitive"}, {"key": "D", "text": "Irreversible"}]'::jsonb, 'C', 'Methotrexate is a structural analog of folic acid and competes for the active site of DHFR. Competitive inhibition can be overcome by increasing [S], restoring Vmax. 📚 Harper''s Biochemistry, 31st Ed, Ch.8', 1, 'nucleux-content', '{}'),
  ('Biochemistry', 'Enzyme Kinetics (Michaelis-Menten, Lineweaver-Burk)', 'The turnover number (Kcat) of an enzyme is defined as:', '[{"key": "A", "text": "Km/Vmax"}, {"key": "B", "text": "Vmax/[Et]"}, {"key": "C", "text": "Vmax \u00d7 Km"}, {"key": "D", "text": "[S] at half-Vmax"}]'::jsonb, 'B', 'Kcat = Vmax/[Et] where [Et] is total enzyme concentration. It represents the number of substrate molecules converted to product per enzyme molecule per unit time when enzyme is saturated. 📚 Stryer Biochemistry, Ch.8', 2, 'nucleux-content', '{}'),
  ('Biochemistry', 'Lipid Metabolism (Beta-oxidation, Ketogenesis, Cholesterol)', 'The rate-limiting enzyme of fatty acid beta-oxidation is:', '[{"key": "A", "text": "Acyl-CoA dehydrogenase"}, {"key": "B", "text": "Carnitine palmitoyltransferase I (CPT-I)"}, {"key": "C", "text": "Thiolase"}, {"key": "D", "text": "HMG-CoA synthase"}]'::jsonb, 'B', 'CPT-I on the outer mitochondrial membrane is rate-limiting for long-chain FA entry into mitochondria. It is inhibited by malonyl-CoA (first committed intermediate of FA synthesis). 📚 Harper''s Biochemistry, 31st Ed, Ch.22', 1, 'nucleux-content', '{}'),
  ('Biochemistry', 'Lipid Metabolism (Beta-oxidation, Ketogenesis, Cholesterol)', 'Why can''t the liver utilize ketone bodies for energy?', '[{"key": "A", "text": "Lacks HMG-CoA lyase"}, {"key": "B", "text": "Lacks thiophorase (succinyl-CoA:acetoacetate CoA transferase)"}, {"key": "C", "text": "Lacks \u03b2-hydroxybutyrate dehydrogenase"}, {"key": "D", "text": "Lacks acetyl-CoA"}]'::jsonb, 'B', 'Thiophorase converts acetoacetate back to acetoacetyl-CoA for utilization. The liver lacks this enzyme, so it produces ketone bodies for export to extrahepatic tissues (brain, heart, muscle). 📚 Harper''s Biochemistry, 31st Ed, Ch.22', 2, 'nucleux-content', '{}'),
  ('Biochemistry', 'Lipid Metabolism (Beta-oxidation, Ketogenesis, Cholesterol)', 'A child presents with hypoketotic hypoglycemia during fasting. The most likely diagnosis is:', '[{"key": "A", "text": "Type 1 diabetes mellitus"}, {"key": "B", "text": "MCAD deficiency"}, {"key": "C", "text": "Carnitine deficiency"}, {"key": "D", "text": "HMG-CoA lyase deficiency"}]'::jsonb, 'B', 'MCAD deficiency is the most common fatty acid oxidation disorder. Impaired beta-oxidation → cannot generate ketone bodies (hypoketotic) and cannot provide fuel during fasting → hypoglycemia. 📚 Harper''s Biochemistry, 31st Ed, Ch.22', 2, 'nucleux-content', '{}'),
  ('Biochemistry', 'Lipid Metabolism (Beta-oxidation, Ketogenesis, Cholesterol)', 'Which lipoprotein is responsible for reverse cholesterol transport?', '[{"key": "A", "text": "LDL"}, {"key": "B", "text": "VLDL"}, {"key": "C", "text": "HDL"}, {"key": "D", "text": "Chylomicrons"}]'::jsonb, 'C', 'HDL picks up cholesterol from peripheral tissues and transports it back to the liver for excretion as bile acids — reverse cholesterol transport. This is why high HDL is protective. 📚 Harper''s Biochemistry, 31st Ed, Ch.26', 1, 'nucleux-content', '{}'),
  ('Biochemistry', 'Lipid Metabolism (Beta-oxidation, Ketogenesis, Cholesterol)', 'Malonyl-CoA inhibits beta-oxidation by acting on which enzyme?', '[{"key": "A", "text": "CPT-I"}, {"key": "B", "text": "CPT-II"}, {"key": "C", "text": "Acyl-CoA dehydrogenase"}, {"key": "D", "text": "HMG-CoA reductase"}]'::jsonb, 'A', 'Malonyl-CoA (first intermediate of fatty acid synthesis) inhibits CPT-I, preventing FA entry into mitochondria for oxidation. This ensures FA synthesis and oxidation don''t occur simultaneously. 📚 Stryer Biochemistry, Ch.22', 1, 'nucleux-content', '{}'),
  ('Biochemistry', 'DNA Replication & Repair', 'A child with extreme photosensitivity develops multiple skin cancers. The defect is in which DNA repair mechanism?', '[{"key": "A", "text": "Base excision repair"}, {"key": "B", "text": "Nucleotide excision repair"}, {"key": "C", "text": "Mismatch repair"}, {"key": "D", "text": "Homologous recombination"}]'::jsonb, 'B', 'Xeroderma pigmentosum (XP) = defect in NER, which normally repairs UV-induced thymine dimers (bulky lesions). Without NER, UV damage accumulates → multiple skin cancers. 📚 Harper''s Biochemistry, 31st Ed, Ch.36', 1, 'nucleux-content', '{}'),
  ('Biochemistry', 'DNA Replication & Repair', 'Lynch syndrome (HNPCC) is caused by defects in which DNA repair pathway?', '[{"key": "A", "text": "Base excision repair"}, {"key": "B", "text": "Nucleotide excision repair"}, {"key": "C", "text": "Mismatch repair"}, {"key": "D", "text": "Non-homologous end joining"}]'::jsonb, 'C', 'Lynch syndrome = autosomal dominant defect in mismatch repair genes (MSH2, MLH1, MSH6, PMS2). Leads to microsatellite instability and early-onset colorectal/endometrial cancer. 📚 Harper''s Biochemistry, 31st Ed, Ch.36', 1, 'nucleux-content', '{}'),
  ('Biochemistry', 'DNA Replication & Repair', 'Which enzyme extends telomeres and is active in cancer cells but not normal somatic cells?', '[{"key": "A", "text": "DNA polymerase \u03b1"}, {"key": "B", "text": "Telomerase"}, {"key": "C", "text": "Helicase"}, {"key": "D", "text": "Primase"}]'::jsonb, 'B', 'Telomerase is a reverse transcriptase that adds TTAGGG repeats to telomeres. Active in germ cells, stem cells, and ~90% of cancers (immortalization). Absent in somatic cells → telomere shortening → senescence. 📚 Stryer Biochemistry, Ch.28', 1, 'nucleux-content', '{}'),
  ('Biochemistry', 'DNA Replication & Repair', 'On the lagging strand of DNA replication, short DNA fragments are synthesized and later joined. These are called:', '[{"key": "A", "text": "Primer fragments"}, {"key": "B", "text": "Okazaki fragments"}, {"key": "C", "text": "Restriction fragments"}, {"key": "D", "text": "Telomeric fragments"}]'::jsonb, 'B', 'The lagging strand is synthesized discontinuously as Okazaki fragments (100-200nt in eukaryotes, 1000-2000nt in prokaryotes). RNA primers are removed by DNA pol I/FEN1, gaps filled, and fragments joined by DNA ligase. 📚 Harper''s Biochemistry, 31st Ed, Ch.35', 1, 'nucleux-content', '{}'),
  ('Biochemistry', 'DNA Replication & Repair', 'BRCA1 and BRCA2 are involved in which DNA repair mechanism?', '[{"key": "A", "text": "Nucleotide excision repair"}, {"key": "B", "text": "Base excision repair"}, {"key": "C", "text": "Homologous recombination"}, {"key": "D", "text": "Mismatch repair"}]'::jsonb, 'C', 'BRCA1/2 are essential for error-free repair of double-strand breaks via homologous recombination. Mutations → impaired DSB repair → genomic instability → breast and ovarian cancer predisposition. 📚 Harper''s Biochemistry, 31st Ed, Ch.36', 2, 'nucleux-content', '{}'),
  ('Biochemistry', 'Molecular Biology Techniques (PCR, Blotting, CRISPR)', 'In PCR, the thermostable DNA polymerase used is derived from:', '[{"key": "A", "text": "E. coli"}, {"key": "B", "text": "Thermus aquaticus"}, {"key": "C", "text": "Bacillus subtilis"}, {"key": "D", "text": "Staphylococcus aureus"}]'::jsonb, 'B', 'Taq polymerase from the thermophilic bacterium Thermus aquaticus is stable at 94°C (denaturation temperature) and functions optimally at 72°C (extension). 📚 Harper''s Biochemistry, 31st Ed, Ch.39', 1, 'nucleux-content', '{}'),
  ('Biochemistry', 'Molecular Biology Techniques (PCR, Blotting, CRISPR)', 'Which blotting technique is used as a confirmatory test for HIV?', '[{"key": "A", "text": "Southern blot"}, {"key": "B", "text": "Northern blot"}, {"key": "C", "text": "Western blot"}, {"key": "D", "text": "Southwestern blot"}]'::jsonb, 'C', 'Western blot detects specific proteins/antibodies. For HIV, it detects antibodies against specific HIV proteins (gp120, gp41, p24) after a positive screening ELISA. 📚 Stryer Biochemistry, Ch.5', 1, 'nucleux-content', '{}'),
  ('Biochemistry', 'Molecular Biology Techniques (PCR, Blotting, CRISPR)', 'CRISPR-Cas9 creates a double-strand break in DNA which is repaired by:', '[{"key": "A", "text": "Base excision repair only"}, {"key": "B", "text": "NHEJ or homology-directed repair"}, {"key": "C", "text": "Nucleotide excision repair"}, {"key": "D", "text": "Mismatch repair"}]'::jsonb, 'B', 'CRISPR-Cas9 DSBs are repaired by either NHEJ (error-prone → gene knockout) or HDR with a donor template (precise gene editing). The choice determines whether it''s a knockout or knock-in. 📚 Harper''s Biochemistry, 31st Ed, Ch.39', 2, 'nucleux-content', '{}'),
  ('Biochemistry', 'Molecular Biology Techniques (PCR, Blotting, CRISPR)', 'A research lab wants to analyze mRNA expression levels of a gene. Which technique should they use?', '[{"key": "A", "text": "Southern blot"}, {"key": "B", "text": "Northern blot"}, {"key": "C", "text": "Western blot"}, {"key": "D", "text": "FISH"}]'::jsonb, 'B', 'Northern blot detects and quantifies specific mRNA. Southern blot is for DNA, Western blot for proteins. Today, RT-qPCR and RNA-seq have largely replaced Northern blots. 📚 Stryer Biochemistry, Ch.5', 1, 'nucleux-content', '{}'),
  ('Biochemistry', 'Molecular Biology Techniques (PCR, Blotting, CRISPR)', 'In RT-PCR for COVID-19 diagnosis, the first step involves:', '[{"key": "A", "text": "DNA denaturation at 94\u00b0C"}, {"key": "B", "text": "Reverse transcription of viral RNA to cDNA"}, {"key": "C", "text": "Restriction enzyme digestion"}, {"key": "D", "text": "Gel electrophoresis"}]'::jsonb, 'B', 'SARS-CoV-2 is an RNA virus. RT (reverse transcriptase) first converts viral RNA to complementary DNA (cDNA), which is then amplified by standard PCR. This is why it''s called RT-PCR. 📚 Harper''s Biochemistry, 31st Ed, Ch.39', 1, 'nucleux-content', '{}'),
  ('Biochemistry', 'Transcription & Translation', 'Which RNA polymerase synthesizes mRNA in eukaryotes and is inhibited by α-amanitin?', '[{"key": "A", "text": "RNA polymerase I"}, {"key": "B", "text": "RNA polymerase II"}, {"key": "C", "text": "RNA polymerase III"}, {"key": "D", "text": "Primase"}]'::jsonb, 'B', 'RNA pol II transcribes mRNA (and snRNA). It is sensitive to low doses of α-amanitin (Amanita phalloides mushroom toxin). RNA pol I is resistant; RNA pol III needs high doses. 📚 Harper''s Biochemistry, 31st Ed, Ch.37', 1, 'nucleux-content', '{}'),
  ('Biochemistry', 'Transcription & Translation', 'Diphtheria toxin inhibits protein synthesis by inactivating:', '[{"key": "A", "text": "EF-Tu"}, {"key": "B", "text": "EF-2 (eEF-2)"}, {"key": "C", "text": "Peptidyl transferase"}, {"key": "D", "text": "Initiation factor eIF-2"}]'::jsonb, 'B', 'Diphtheria toxin catalyzes ADP-ribosylation of EF-2, halting translocation during elongation. This is a eukaryotic-specific effect (bacterial EF-G is not affected). 📚 Harper''s Biochemistry, 31st Ed, Ch.38', 1, 'nucleux-content', '{}'),
  ('Biochemistry', 'Transcription & Translation', 'Which of the following antibiotics acts on the 30S ribosomal subunit?', '[{"key": "A", "text": "Chloramphenicol"}, {"key": "B", "text": "Erythromycin"}, {"key": "C", "text": "Tetracycline"}, {"key": "D", "text": "Clindamycin"}]'::jsonb, 'C', 'Tetracycline blocks aminoacyl-tRNA binding to the 30S A site. Chloramphenicol, erythromycin, and clindamycin all act on the 50S subunit. 📚 Harper''s Biochemistry, 31st Ed, Ch.38', 1, 'nucleux-content', '{}'),
  ('Biochemistry', 'Transcription & Translation', 'The enzyme that catalyzes peptide bond formation during translation is:', '[{"key": "A", "text": "Aminoacyl-tRNA synthetase"}, {"key": "B", "text": "Peptidyl transferase (23S rRNA)"}, {"key": "C", "text": "EF-2"}, {"key": "D", "text": "Release factor"}]'::jsonb, 'B', 'Peptidyl transferase activity resides in the 23S rRNA of the large ribosomal subunit — it is a ribozyme (RNA with catalytic activity), not a protein enzyme. This was a Nobel Prize-winning discovery. 📚 Stryer Biochemistry, Ch.30', 2, 'nucleux-content', '{}'),
  ('Biochemistry', 'Transcription & Translation', 'A mutation at a splice site in the β-globin gene would most likely cause:', '[{"key": "A", "text": "Sickle cell disease"}, {"key": "B", "text": "\u03b2-Thalassemia"}, {"key": "C", "text": "\u03b1-Thalassemia"}, {"key": "D", "text": "Hemoglobin C disease"}]'::jsonb, 'B', 'Splice site mutations cause abnormal mRNA processing → reduced or absent β-globin production = β-thalassemia. Sickle cell is a point mutation (Glu→Val). α-Thalassemia involves α-globin gene deletions. 📚 Harper''s Biochemistry, 31st Ed, Ch.37', 2, 'nucleux-content', '{}'),
  ('Biochemistry', 'Amino Acid Metabolism & Urea Cycle', 'The rate-limiting enzyme of the urea cycle is:', '[{"key": "A", "text": "Ornithine transcarbamylase"}, {"key": "B", "text": "Carbamoyl phosphate synthetase I"}, {"key": "C", "text": "Arginase"}, {"key": "D", "text": "Argininosuccinate synthetase"}]'::jsonb, 'B', 'CPS-I catalyzes the first committed step of the urea cycle and is the rate-limiting enzyme. It requires N-acetylglutamate as an obligatory activator. 📚 Harper''s Biochemistry, 31st Ed, Ch.28', 1, 'nucleux-content', '{}'),
  ('Biochemistry', 'Amino Acid Metabolism & Urea Cycle', 'A neonate with hyperammonemia has elevated orotic acid in urine. The most likely enzyme deficiency is:', '[{"key": "A", "text": "CPS-I"}, {"key": "B", "text": "Ornithine transcarbamylase (OTC)"}, {"key": "C", "text": "Arginase"}, {"key": "D", "text": "Argininosuccinate lyase"}]'::jsonb, 'B', 'OTC deficiency → carbamoyl phosphate accumulates → diverted to pyrimidine synthesis pathway → ↑orotic acid in urine. CPS-I deficiency also causes hyperammonemia but WITHOUT orotic aciduria. 📚 Harper''s Biochemistry, 31st Ed, Ch.28', 2, 'nucleux-content', '{}'),
  ('Biochemistry', 'Amino Acid Metabolism & Urea Cycle', 'Which amino acids are purely ketogenic?', '[{"key": "A", "text": "Leucine and isoleucine"}, {"key": "B", "text": "Leucine and lysine"}, {"key": "C", "text": "Lysine and tryptophan"}, {"key": "D", "text": "Phenylalanine and tyrosine"}]'::jsonb, 'B', 'Only leucine and lysine are purely ketogenic (degraded exclusively to acetyl-CoA/acetoacetyl-CoA). Isoleucine, Phe, Trp, Tyr, Thr are both glucogenic and ketogenic. 📚 Stryer Biochemistry, Ch.23', 1, 'nucleux-content', '{}'),
  ('Biochemistry', 'Amino Acid Metabolism & Urea Cycle', 'In the glucose-alanine cycle, alanine is transported from muscle to liver where it is converted to:', '[{"key": "A", "text": "Glutamate"}, {"key": "B", "text": "Pyruvate"}, {"key": "C", "text": "Oxaloacetate"}, {"key": "D", "text": "\u03b1-Ketoglutarate"}]'::jsonb, 'B', 'In liver, ALT transaminates alanine + α-KG → pyruvate + glutamate. Pyruvate is then used for gluconeogenesis, and the glucose returns to muscle. The amino group goes to urea cycle. 📚 Harper''s Biochemistry, 31st Ed, Ch.28', 2, 'nucleux-content', '{}'),
  ('Biochemistry', 'Amino Acid Metabolism & Urea Cycle', 'All aminotransferases require which vitamin as a cofactor?', '[{"key": "A", "text": "Thiamine (B1)"}, {"key": "B", "text": "Riboflavin (B2)"}, {"key": "C", "text": "Pyridoxine (B6)"}, {"key": "D", "text": "Cobalamin (B12)"}]'::jsonb, 'C', 'Pyridoxal phosphate (PLP), the active form of vitamin B6, is the essential cofactor for all aminotransferases. It temporarily accepts the amino group during the transamination reaction. 📚 Harper''s Biochemistry, 31st Ed, Ch.28', 1, 'nucleux-content', '{}'),
  ('Biochemistry', 'Vitamins (Water-soluble & Fat-soluble — Deficiencies)', 'A chronic alcoholic presents with confusion, ataxia, and ophthalmoplegia. Which vitamin deficiency is most likely?', '[{"key": "A", "text": "Vitamin B12"}, {"key": "B", "text": "Vitamin B1 (thiamine)"}, {"key": "C", "text": "Vitamin B6"}, {"key": "D", "text": "Vitamin C"}]'::jsonb, 'B', 'Classic Wernicke''s encephalopathy triad: confusion, ophthalmoplegia, ataxia — due to thiamine deficiency. Common in alcoholics due to poor nutrition and impaired thiamine absorption. 📚 Harper''s Biochemistry, 31st Ed, Ch.44', 1, 'nucleux-content', '{}'),
  ('Biochemistry', 'Vitamins (Water-soluble & Fat-soluble — Deficiencies)', 'A patient has megaloblastic anemia with elevated methylmalonic acid and homocysteine. Which vitamin is deficient?', '[{"key": "A", "text": "Folate"}, {"key": "B", "text": "Vitamin B12"}, {"key": "C", "text": "Vitamin B6"}, {"key": "D", "text": "Vitamin C"}]'::jsonb, 'B', 'B12 is cofactor for methylmalonyl-CoA mutase (↑MMA when deficient) and methionine synthase (↑homocysteine). Folate deficiency causes ↑homocysteine but normal MMA. 📚 Harper''s Biochemistry, 31st Ed, Ch.44', 1, 'nucleux-content', '{}'),
  ('Biochemistry', 'Vitamins (Water-soluble & Fat-soluble — Deficiencies)', 'Which vitamin is required for γ-carboxylation of clotting factors?', '[{"key": "A", "text": "Vitamin A"}, {"key": "B", "text": "Vitamin D"}, {"key": "C", "text": "Vitamin E"}, {"key": "D", "text": "Vitamin K"}]'::jsonb, 'D', 'Vitamin K is essential for γ-carboxylation of glutamate residues on factors II, VII, IX, X and proteins C and S. This modification is needed for Ca²+ binding and clotting function. Warfarin inhibits vitamin K epoxide reductase. 📚 Harper''s Biochemistry, 31st Ed, Ch.44', 1, 'nucleux-content', '{}'),
  ('Biochemistry', 'Vitamins (Water-soluble & Fat-soluble — Deficiencies)', 'Pellagra (dermatitis, diarrhea, dementia) is caused by deficiency of:', '[{"key": "A", "text": "Thiamine"}, {"key": "B", "text": "Riboflavin"}, {"key": "C", "text": "Niacin"}, {"key": "D", "text": "Pyridoxine"}]'::jsonb, 'C', 'Niacin (B3) deficiency causes pellagra — the 3 D''s: dermatitis (sun-exposed skin), diarrhea, dementia. A 4th D (death) if untreated. Niacin can be synthesized from tryptophan; corn-based diets (low tryptophan) predispose. 📚 Harper''s Biochemistry, 31st Ed, Ch.44', 1, 'nucleux-content', '{}'),
  ('Biochemistry', 'Vitamins (Water-soluble & Fat-soluble — Deficiencies)', 'A patient on isoniazid therapy develops peripheral neuropathy and sideroblastic anemia. Which vitamin should be supplemented?', '[{"key": "A", "text": "B1 (thiamine)"}, {"key": "B", "text": "B6 (pyridoxine)"}, {"key": "C", "text": "B12 (cobalamin)"}, {"key": "D", "text": "B9 (folate)"}]'::jsonb, 'B', 'INH inhibits pyridoxine (B6) metabolism. B6 (PLP) is needed for ALA synthase (heme synthesis — deficiency → sideroblastic anemia) and neurotransmitter synthesis (neuropathy). Always co-prescribe B6 with INH. 📚 Harper''s Biochemistry, 31st Ed, Ch.44', 2, 'nucleux-content', '{}'),
  ('Microbiology', 'Bacterial Classification & Staining', 'The mordant used in Gram staining is:', '[{"key": "A", "text": "Crystal violet"}, {"key": "B", "text": "Safranin"}, {"key": "C", "text": "Gram''s iodine"}, {"key": "D", "text": "Acetone-alcohol"}]'::jsonb, 'C', 'Gram''s iodine acts as a mordant — forms crystal violet-iodine (CV-I) complex within the cell, making the dye harder to remove. Gram+ bacteria with thick PG retain this complex after decolorization. 📚 Ananthanarayan, 11th Ed, Ch.2', 1, 'nucleux-content', '{}'),
  ('Microbiology', 'Bacterial Classification & Staining', 'Which component of Gram-negative bacteria is responsible for endotoxic shock?', '[{"key": "A", "text": "Teichoic acid"}, {"key": "B", "text": "Peptidoglycan"}, {"key": "C", "text": "Lipid A of LPS"}, {"key": "D", "text": "Porins"}]'::jsonb, 'C', 'Lipid A is the toxic moiety of lipopolysaccharide (LPS). It activates TLR4 on macrophages → TNF-α, IL-1, IL-6 release → fever, hypotension, DIC, septic shock. 📚 Jawetz Medical Microbiology, 28th Ed, Ch.2', 1, 'nucleux-content', '{}'),
  ('Microbiology', 'Bacterial Classification & Staining', 'A CSF sample shows encapsulated yeast with clear halo on India ink preparation. The organism is:', '[{"key": "A", "text": "Candida albicans"}, {"key": "B", "text": "Cryptococcus neoformans"}, {"key": "C", "text": "Aspergillus fumigatus"}, {"key": "D", "text": "Histoplasma capsulatum"}]'::jsonb, 'B', 'India ink is a negative stain that highlights the thick polysaccharide capsule of Cryptococcus as a clear halo against a dark background. Classic finding in cryptococcal meningitis (AIDS patients). 📚 Ananthanarayan, 11th Ed, Ch.2', 1, 'nucleux-content', '{}'),
  ('Microbiology', 'Bacterial Classification & Staining', 'Which organism lacks a cell wall and is therefore not visible on Gram stain?', '[{"key": "A", "text": "Chlamydia"}, {"key": "B", "text": "Rickettsia"}, {"key": "C", "text": "Mycoplasma"}, {"key": "D", "text": "Treponema"}]'::jsonb, 'C', 'Mycoplasma has NO cell wall (no peptidoglycan) → not stained by Gram stain, resistant to β-lactams and vancomycin. Contains cholesterol in its membrane (unique among bacteria). 📚 Jawetz Medical Microbiology, 28th Ed, Ch.2', 1, 'nucleux-content', '{}'),
  ('Microbiology', 'Bacterial Classification & Staining', 'Albert''s stain is used to demonstrate metachromatic granules in:', '[{"key": "A", "text": "Mycobacterium tuberculosis"}, {"key": "B", "text": "Corynebacterium diphtheriae"}, {"key": "C", "text": "Neisseria meningitidis"}, {"key": "D", "text": "Clostridium tetani"}]'::jsonb, 'B', 'Albert''s stain shows metachromatic (volutin/polyphosphate) granules as blue-black bodies in green-colored C. diphtheriae bacilli. These granules are also called Babes-Ernst granules. 📚 Ananthanarayan, 11th Ed, Ch.2', 1, 'nucleux-content', '{}'),
  ('Microbiology', 'Enteric Gram-Negative Bacilli (E.coli, Salmonella, Shigella)', 'A child develops bloody diarrhea followed by hemolytic anemia, thrombocytopenia, and renal failure. The most likely causative organism is:', '[{"key": "A", "text": "Shigella sonnei"}, {"key": "B", "text": "E.coli O157:H7 (EHEC)"}, {"key": "C", "text": "Salmonella typhi"}, {"key": "D", "text": "Vibrio cholerae"}]'::jsonb, 'B', 'Classic HUS triad (hemolytic anemia + thrombocytopenia + renal failure) following bloody diarrhea = EHEC (O157:H7). Shiga-like toxin damages renal endothelium. Avoid antibiotics. 📚 Ananthanarayan, 11th Ed, Ch.28', 1, 'nucleux-content', '{}'),
  ('Microbiology', 'Enteric Gram-Negative Bacilli (E.coli, Salmonella, Shigella)', 'Which Shigella species produces Shiga toxin and causes the most severe dysentery?', '[{"key": "A", "text": "S. sonnei"}, {"key": "B", "text": "S. flexneri"}, {"key": "C", "text": "S. dysenteriae"}, {"key": "D", "text": "S. boydii"}]'::jsonb, 'C', 'S. dysenteriae type 1 produces Shiga toxin (AB toxin, inhibits 60S ribosome → protein synthesis arrest), causing the most severe bacillary dysentery and can lead to HUS. 📚 Jawetz Medical Microbiology, 28th Ed, Ch.15', 1, 'nucleux-content', '{}'),
  ('Microbiology', 'Enteric Gram-Negative Bacilli (E.coli, Salmonella, Shigella)', 'Rose spots on the abdomen during the second week of fever suggest infection with:', '[{"key": "A", "text": "E. coli"}, {"key": "B", "text": "Shigella flexneri"}, {"key": "C", "text": "Salmonella typhi"}, {"key": "D", "text": "Klebsiella pneumoniae"}]'::jsonb, 'C', 'Rose spots (salmon-colored, blanching maculopapular rash on abdomen/chest) appear during week 2 of typhoid fever. They represent bacterial emboli in the skin. 📚 Ananthanarayan, 11th Ed, Ch.30', 1, 'nucleux-content', '{}'),
  ('Microbiology', 'Enteric Gram-Negative Bacilli (E.coli, Salmonella, Shigella)', 'ETEC causes traveler''s diarrhea through which toxin mechanism?', '[{"key": "A", "text": "Shiga toxin inhibiting 60S ribosome"}, {"key": "B", "text": "Heat-labile toxin increasing cAMP"}, {"key": "C", "text": "Exfoliative toxin causing skin peeling"}, {"key": "D", "text": "TSST-1 superantigen activation"}]'::jsonb, 'B', 'ETEC LT (heat-labile toxin) activates adenylate cyclase → ↑cAMP → Cl⁻ secretion → watery diarrhea. Mechanism identical to cholera toxin. ST (heat-stable) activates guanylate cyclase → ↑cGMP. 📚 Jawetz Medical Microbiology, 28th Ed, Ch.15', 2, 'nucleux-content', '{}'),
  ('Microbiology', 'Enteric Gram-Negative Bacilli (E.coli, Salmonella, Shigella)', 'Which feature differentiates Shigella from Salmonella on culture?', '[{"key": "A", "text": "Shigella is motile"}, {"key": "B", "text": "Shigella produces H2S"}, {"key": "C", "text": "Shigella is non-motile and H2S-negative"}, {"key": "D", "text": "Shigella ferments lactose"}]'::jsonb, 'C', 'Shigella: non-motile, no H2S, no gas from glucose. Salmonella: motile (peritrichous flagella), H2S-positive on TSI, non-lactose fermenting. Both are non-lactose fermenters on MacConkey. 📚 Ananthanarayan, 11th Ed, Ch.29', 1, 'nucleux-content', '{}'),
  ('Microbiology', 'Staphylococcus & Streptococcus', 'Which test differentiates Staphylococcus from Streptococcus?', '[{"key": "A", "text": "Coagulase test"}, {"key": "B", "text": "Catalase test"}, {"key": "C", "text": "Optochin sensitivity"}, {"key": "D", "text": "Bacitracin sensitivity"}]'::jsonb, 'B', 'Staphylococcus is catalase-positive (breaks down H2O2 → O2 + H2O with bubbling). Streptococcus is catalase-negative. This is the first-line differentiating test for Gram+ cocci. 📚 Ananthanarayan, 11th Ed, Ch.24', 1, 'nucleux-content', '{}'),
  ('Microbiology', 'Staphylococcus & Streptococcus', 'A 6-year-old develops migratory polyarthritis, carditis, and erythema marginatum 3 weeks after pharyngitis. The causative agent is:', '[{"key": "A", "text": "S. aureus"}, {"key": "B", "text": "S. pyogenes"}, {"key": "C", "text": "S. pneumoniae"}, {"key": "D", "text": "S. agalactiae"}]'::jsonb, 'B', 'Rheumatic fever follows Group A streptococcal (S. pyogenes) pharyngitis. Molecular mimicry between M protein and cardiac myosin. Jones criteria are met (polyarthritis + carditis + erythema marginatum). 📚 Jawetz Medical Microbiology, 28th Ed, Ch.14', 1, 'nucleux-content', '{}'),
  ('Microbiology', 'Staphylococcus & Streptococcus', 'MRSA resistance to β-lactams is mediated by:', '[{"key": "A", "text": "\u03b2-lactamase production"}, {"key": "B", "text": "Altered PBP2a (mecA gene)"}, {"key": "C", "text": "Efflux pumps"}, {"key": "D", "text": "Porin mutations"}]'::jsonb, 'B', 'mecA gene encodes PBP2a, an altered penicillin-binding protein with low affinity for all β-lactams. This is distinct from β-lactamase production (which only affects penicillin, overcome by β-lactamase inhibitors). 📚 Ananthanarayan, 11th Ed, Ch.24', 2, 'nucleux-content', '{}'),
  ('Microbiology', 'Staphylococcus & Streptococcus', 'An α-hemolytic, optochin-sensitive, bile-soluble Gram-positive diplococcus is:', '[{"key": "A", "text": "S. pyogenes"}, {"key": "B", "text": "S. pneumoniae"}, {"key": "C", "text": "Enterococcus faecalis"}, {"key": "D", "text": "Viridans streptococci"}]'::jsonb, 'B', 'S. pneumoniae: α-hemolytic, lancet-shaped diplococci, optochin-SENSITIVE, bile-SOLUBLE. Viridans streptococci are also α-hemolytic but optochin-RESISTANT and bile-INSOLUBLE. 📚 Jawetz Medical Microbiology, 28th Ed, Ch.14', 1, 'nucleux-content', '{}'),
  ('Microbiology', 'Staphylococcus & Streptococcus', 'S. aureus food poisoning differs from other bacterial food poisoning because:', '[{"key": "A", "text": "It has a long incubation period (>24 hours)"}, {"key": "B", "text": "It causes bloody diarrhea"}, {"key": "C", "text": "It is caused by preformed heat-stable enterotoxin"}, {"key": "D", "text": "It requires antibiotic treatment"}]'::jsonb, 'C', 'S. aureus produces preformed, heat-stable enterotoxins in food → rapid onset (1-6h) nausea and vomiting (emetic type). Self-limiting. Reheating food does NOT destroy the toxin. 📚 Ananthanarayan, 11th Ed, Ch.24', 1, 'nucleux-content', '{}'),
  ('Microbiology', 'Immunology Basics (Innate vs Adaptive, Complement)', 'Which immunoglobulin crosses the placenta and provides passive immunity to the neonate?', '[{"key": "A", "text": "IgA"}, {"key": "B", "text": "IgM"}, {"key": "C", "text": "IgG"}, {"key": "D", "text": "IgE"}]'::jsonb, 'C', 'IgG is the only immunoglobulin that crosses the placenta (via FcRn receptor on trophoblasts), providing passive immunity to the fetus/neonate for the first 6 months of life. 📚 Ananthanarayan, 11th Ed, Ch.13', 1, 'nucleux-content', '{}'),
  ('Microbiology', 'Immunology Basics (Innate vs Adaptive, Complement)', 'Recurrent Neisseria meningitidis infections suggest deficiency of which complement components?', '[{"key": "A", "text": "C1, C4"}, {"key": "B", "text": "C3"}, {"key": "C", "text": "C5-C9 (MAC)"}, {"key": "D", "text": "Factor B"}]'::jsonb, 'C', 'Terminal complement (C5-C9) forms the membrane attack complex. Neisseria species have an outer membrane that requires MAC for lysis. Deficiency → recurrent meningococcal and gonococcal infections. 📚 Jawetz Medical Microbiology, 28th Ed, Ch.8', 2, 'nucleux-content', '{}'),
  ('Microbiology', 'Immunology Basics (Innate vs Adaptive, Complement)', 'Which cell presents antigens via MHC-II to CD4+ T helper cells?', '[{"key": "A", "text": "All nucleated cells"}, {"key": "B", "text": "Red blood cells"}, {"key": "C", "text": "Antigen-presenting cells (dendritic cells, macrophages, B cells)"}, {"key": "D", "text": "NK cells"}]'::jsonb, 'C', 'MHC-II is expressed only on professional APCs (dendritic cells, macrophages, B cells). They present extracellular antigens to CD4+ T cells. MHC-I (all nucleated cells) presents to CD8+ T cells. 📚 Ananthanarayan, 11th Ed, Ch.12', 1, 'nucleux-content', '{}'),
  ('Microbiology', 'Immunology Basics (Innate vs Adaptive, Complement)', 'The most potent anaphylatoxin and chemotactic factor in the complement system is:', '[{"key": "A", "text": "C3a"}, {"key": "B", "text": "C3b"}, {"key": "C", "text": "C4a"}, {"key": "D", "text": "C5a"}]'::jsonb, 'D', 'C5a is the most potent anaphylatoxin (mast cell degranulation → histamine release) and strongest chemotactic factor for neutrophils. C3a is a weaker anaphylatoxin. C3b = opsonization. 📚 Jawetz Medical Microbiology, 28th Ed, Ch.8', 1, 'nucleux-content', '{}'),
  ('Microbiology', 'Immunology Basics (Innate vs Adaptive, Complement)', 'Th1 cells primarily secrete which cytokine to activate macrophages?', '[{"key": "A", "text": "IL-4"}, {"key": "B", "text": "IL-5"}, {"key": "C", "text": "IFN-\u03b3"}, {"key": "D", "text": "IL-10"}]'::jsonb, 'C', 'Th1 cells produce IFN-γ, which is the most potent activator of macrophages (enhances intracellular killing of engulfed pathogens). Th2 cells produce IL-4 (B cell activation), IL-5 (eosinophils). IL-10 is anti-inflammatory (Treg/Th2). 📚 Ananthanarayan, 11th Ed, Ch.12', 1, 'nucleux-content', '{}'),
  ('Microbiology', 'Mycobacterium tuberculosis', 'Acid-fastness of M. tuberculosis is due to:', '[{"key": "A", "text": "Capsule"}, {"key": "B", "text": "Endotoxin"}, {"key": "C", "text": "Mycolic acid in cell wall"}, {"key": "D", "text": "Protein A"}]'::jsonb, 'C', 'Mycolic acid (long-chain fatty acids, C60-C90) constitutes ~60% of the mycobacterial cell wall. It resists decolorization by acid-alcohol in ZN staining, hence "acid-fast." 📚 Ananthanarayan, 11th Ed, Ch.37', 1, 'nucleux-content', '{}'),
  ('Microbiology', 'Mycobacterium tuberculosis', 'A patient''s Mantoux test shows 12mm induration at 72 hours. This test measures which type of hypersensitivity?', '[{"key": "A", "text": "Type I (immediate)"}, {"key": "B", "text": "Type II (cytotoxic)"}, {"key": "C", "text": "Type III (immune complex)"}, {"key": "D", "text": "Type IV (delayed/cell-mediated)"}]'::jsonb, 'D', 'Mantoux test (TST) measures delayed-type (Type IV) hypersensitivity. Sensitized T cells react to PPD → cytokine release → induration at 48-72 hours. It indicates prior exposure, not active disease. 📚 Jawetz Medical Microbiology, 28th Ed, Ch.23', 1, 'nucleux-content', '{}'),
  ('Microbiology', 'Mycobacterium tuberculosis', 'GeneXpert (CBNAAT) for TB diagnosis can detect rifampicin resistance by identifying mutations in:', '[{"key": "A", "text": "katG gene"}, {"key": "B", "text": "rpoB gene"}, {"key": "C", "text": "inhA gene"}, {"key": "D", "text": "embB gene"}]'::jsonb, 'B', 'GeneXpert detects mutations in the rpoB gene (encodes RNA polymerase β subunit). >95% of rifampicin-resistant strains have rpoB mutations. Rifampicin resistance is a proxy for MDR-TB. 📚 Ananthanarayan, 11th Ed, Ch.37', 2, 'nucleux-content', '{}'),
  ('Microbiology', 'Mycobacterium tuberculosis', 'Which anti-TB drug causes optic neuritis?', '[{"key": "A", "text": "Isoniazid"}, {"key": "B", "text": "Rifampicin"}, {"key": "C", "text": "Ethambutol"}, {"key": "D", "text": "Pyrazinamide"}]'::jsonb, 'C', 'Ethambutol causes dose-dependent optic neuritis → decreased visual acuity, red-green color blindness. Baseline and monthly eye exams recommended. Avoid in young children who cannot report visual symptoms. 📚 Jawetz Medical Microbiology, 28th Ed, Ch.23', 1, 'nucleux-content', '{}'),
  ('Microbiology', 'Mycobacterium tuberculosis', 'The standard DOTS regimen for new pulmonary TB consists of:', '[{"key": "A", "text": "2 months HRZE + 4 months HR"}, {"key": "B", "text": "6 months HRZ"}, {"key": "C", "text": "2 months HR + 4 months HRE"}, {"key": "D", "text": "9 months isoniazid alone"}]'::jsonb, 'A', 'DOTS Category I: intensive phase (2 months of HRZE — isoniazid, rifampicin, pyrazinamide, ethambutol) followed by continuation phase (4 months of HR). Total 6 months for drug-sensitive TB. 📚 Ananthanarayan, 11th Ed, Ch.37', 1, 'nucleux-content', '{}'),
  ('Microbiology', 'Fungal Infections (Candida, Aspergillus, Cryptococcus)', 'The diagnostic test that demonstrates a clear halo around yeast cells in CSF is:', '[{"key": "A", "text": "Gram stain"}, {"key": "B", "text": "KOH mount"}, {"key": "C", "text": "India ink preparation"}, {"key": "D", "text": "Giemsa stain"}]'::jsonb, 'C', 'India ink is a negative stain that highlights the thick polysaccharide capsule of Cryptococcus neoformans as a clear halo against a dark background. Used for CSF examination in suspected cryptococcal meningitis. 📚 Ananthanarayan, 11th Ed, Ch.72', 1, 'nucleux-content', '{}'),
  ('Microbiology', 'Fungal Infections (Candida, Aspergillus, Cryptococcus)', 'Septate hyphae with 45° angle branching on tissue biopsy is characteristic of:', '[{"key": "A", "text": "Candida"}, {"key": "B", "text": "Mucor"}, {"key": "C", "text": "Aspergillus"}, {"key": "D", "text": "Cryptococcus"}]'::jsonb, 'C', 'Aspergillus has septate hyphae with acute-angle (45°/dichotomous) branching. Mucor/Rhizopus has non-septate (ribbon-like) hyphae with wide-angle (90°) branching. This distinction is critical on histopathology. 📚 Jawetz Medical Microbiology, 28th Ed, Ch.45', 1, 'nucleux-content', '{}'),
  ('Microbiology', 'Fungal Infections (Candida, Aspergillus, Cryptococcus)', 'An AIDS patient with CD4 of 50/μL presents with subacute headache. CSF shows elevated opening pressure, lymphocytic pleocytosis, and positive CrAg. The most likely pathogen is:', '[{"key": "A", "text": "Mycobacterium tuberculosis"}, {"key": "B", "text": "Toxoplasma gondii"}, {"key": "C", "text": "Cryptococcus neoformans"}, {"key": "D", "text": "Listeria monocytogenes"}]'::jsonb, 'C', 'Cryptococcal meningitis: subacute onset, CD4 <100, elevated CSF opening pressure, positive CrAg (cryptococcal antigen). Most common fungal meningitis in AIDS. 📚 Ananthanarayan, 11th Ed, Ch.72', 1, 'nucleux-content', '{}'),
  ('Microbiology', 'Fungal Infections (Candida, Aspergillus, Cryptococcus)', 'The drug of choice for invasive aspergillosis is:', '[{"key": "A", "text": "Fluconazole"}, {"key": "B", "text": "Amphotericin B"}, {"key": "C", "text": "Voriconazole"}, {"key": "D", "text": "Caspofungin"}]'::jsonb, 'C', 'Voriconazole is the first-line treatment for invasive aspergillosis (superior to amphotericin B in clinical trials). It inhibits 14α-demethylase → blocks ergosterol synthesis. 📚 Jawetz Medical Microbiology, 28th Ed, Ch.45', 2, 'nucleux-content', '{}'),
  ('Microbiology', 'Fungal Infections (Candida, Aspergillus, Cryptococcus)', 'Germ tube test is used to identify:', '[{"key": "A", "text": "Cryptococcus neoformans"}, {"key": "B", "text": "Candida albicans"}, {"key": "C", "text": "Aspergillus fumigatus"}, {"key": "D", "text": "Histoplasma capsulatum"}]'::jsonb, 'B', 'C. albicans produces germ tubes (short hyphal projections without constriction at the base) when incubated in serum at 37°C for 2-3 hours. This differentiates it from other Candida species. 📚 Ananthanarayan, 11th Ed, Ch.70', 1, 'nucleux-content', '{}'),
  ('Microbiology', 'Malaria Parasite (Life Cycle, Diagnosis)', 'Relapse in P. vivax malaria is due to reactivation of:', '[{"key": "A", "text": "Merozoites in RBCs"}, {"key": "B", "text": "Sporozoites in blood"}, {"key": "C", "text": "Hypnozoites in liver"}, {"key": "D", "text": "Gametocytes in circulation"}]'::jsonb, 'C', 'Hypnozoites are dormant liver stages unique to P. vivax and P. ovale. They can reactivate months to years later causing relapse. Primaquine is the only drug that kills hypnozoites. 📚 Ananthanarayan, 11th Ed, Ch.84', 1, 'nucleux-content', '{}'),
  ('Microbiology', 'Malaria Parasite (Life Cycle, Diagnosis)', 'Banana-shaped gametocytes on peripheral blood smear are characteristic of:', '[{"key": "A", "text": "P. vivax"}, {"key": "B", "text": "P. falciparum"}, {"key": "C", "text": "P. malariae"}, {"key": "D", "text": "P. ovale"}]'::jsonb, 'B', 'P. falciparum gametocytes have a distinctive crescent/banana shape (also called "sausage-shaped"). This is pathognomonic and helps species identification on thin smear. 📚 Jawetz Medical Microbiology, 28th Ed, Ch.46', 1, 'nucleux-content', '{}'),
  ('Microbiology', 'Malaria Parasite (Life Cycle, Diagnosis)', 'Before prescribing primaquine, which test must be performed?', '[{"key": "A", "text": "Liver function test"}, {"key": "B", "text": "Renal function test"}, {"key": "C", "text": "G6PD assay"}, {"key": "D", "text": "Coagulation profile"}]'::jsonb, 'C', 'Primaquine causes oxidative hemolysis in G6PD-deficient patients. G6PD testing is mandatory before prescribing. Alternative for G6PD-deficient: tafenoquine (weekly dosing) with testing. 📚 Ananthanarayan, 11th Ed, Ch.84', 1, 'nucleux-content', '{}'),
  ('Microbiology', 'Malaria Parasite (Life Cycle, Diagnosis)', 'The drug of choice for severe/cerebral malaria is:', '[{"key": "A", "text": "Chloroquine"}, {"key": "B", "text": "Mefloquine"}, {"key": "C", "text": "IV artesunate"}, {"key": "D", "text": "Primaquine"}]'::jsonb, 'C', 'IV artesunate has replaced IV quinine as the drug of choice for severe malaria (WHO recommendation). It acts faster, reduces mortality by 35% compared to quinine, and is better tolerated. 📚 Jawetz Medical Microbiology, 28th Ed, Ch.46', 1, 'nucleux-content', '{}'),
  ('Microbiology', 'Malaria Parasite (Life Cycle, Diagnosis)', 'P. vivax preferentially invades which type of RBCs?', '[{"key": "A", "text": "All ages of RBCs"}, {"key": "B", "text": "Only reticulocytes (young RBCs)"}, {"key": "C", "text": "Only mature RBCs"}, {"key": "D", "text": "Only sickle cells"}]'::jsonb, 'B', 'P. vivax uses the Duffy blood group antigen (DARC) on reticulocytes for invasion, limiting it to young RBCs → lower parasitemia → benign tertian. P. falciparum invades all RBC ages → high parasitemia. 📚 Ananthanarayan, 11th Ed, Ch.84', 2, 'nucleux-content', '{}'),
  ('Microbiology', 'Hepatitis Viruses (A-E)', 'During the ''window period'' of HBV infection, the only positive serologic marker is:', '[{"key": "A", "text": "HBsAg"}, {"key": "B", "text": "Anti-HBs"}, {"key": "C", "text": "Anti-HBc IgM"}, {"key": "D", "text": "HBeAg"}]'::jsonb, 'C', 'Window period: HBsAg has been cleared but anti-HBs has not yet appeared. The only detectable marker is anti-HBc IgM (core antibody, IgM class indicates recent/acute infection). 📚 Jawetz Medical Microbiology, 28th Ed, Ch.35', 1, 'nucleux-content', '{}'),
  ('Microbiology', 'Hepatitis Viruses (A-E)', 'A person has anti-HBs positive with all other HBV markers negative. This indicates:', '[{"key": "A", "text": "Acute HBV infection"}, {"key": "B", "text": "Chronic HBV carrier"}, {"key": "C", "text": "Prior HBV vaccination"}, {"key": "D", "text": "Window period"}]'::jsonb, 'C', 'Vaccination produces ONLY anti-HBs antibodies (against recombinant HBsAg). No exposure to whole virus, so anti-HBc is absent. This pattern is unique to vaccination. 📚 Ananthanarayan, 11th Ed, Ch.58', 1, 'nucleux-content', '{}'),
  ('Microbiology', 'Hepatitis Viruses (A-E)', 'Hepatitis D virus requires which component of HBV for its replication?', '[{"key": "A", "text": "HBcAg"}, {"key": "B", "text": "HBsAg"}, {"key": "C", "text": "HBeAg"}, {"key": "D", "text": "HBV DNA polymerase"}]'::jsonb, 'B', 'HDV is a defective virus that requires HBsAg (surface antigen) from HBV as its envelope. HDV can only infect patients who are HBsAg-positive (coinfection or superinfection). 📚 Jawetz Medical Microbiology, 28th Ed, Ch.35', 1, 'nucleux-content', '{}'),
  ('Microbiology', 'Hepatitis Viruses (A-E)', 'A pregnant woman in her third trimester develops fulminant hepatic failure. The most likely viral etiology is:', '[{"key": "A", "text": "HAV"}, {"key": "B", "text": "HBV"}, {"key": "C", "text": "HCV"}, {"key": "D", "text": "HEV"}]'::jsonb, 'D', 'HEV causes fulminant hepatitis with up to 20% mortality in pregnant women (especially 3rd trimester). This high mortality in pregnancy is unique to HEV among all hepatitis viruses. 📚 Ananthanarayan, 11th Ed, Ch.58', 1, 'nucleux-content', '{}'),
  ('Microbiology', 'Hepatitis Viruses (A-E)', 'Which hepatitis virus has the highest rate of chronicity?', '[{"key": "A", "text": "HAV"}, {"key": "B", "text": "HBV"}, {"key": "C", "text": "HCV"}, {"key": "D", "text": "HEV"}]'::jsonb, 'C', 'HCV has ~80% chronicity rate (highest among hepatitis viruses). HBV chronicity depends on age at infection (90% neonatal, 5% adult). HAV and HEV do not cause chronic hepatitis. 📚 Jawetz Medical Microbiology, 28th Ed, Ch.35', 1, 'nucleux-content', '{}'),
  ('Microbiology', 'HIV Virology & Diagnosis', 'HIV enters CD4+ T cells by binding gp120 to CD4 and which coreceptor on macrophage-tropic strains?', '[{"key": "A", "text": "CXCR4"}, {"key": "B", "text": "CCR5"}, {"key": "C", "text": "CCR7"}, {"key": "D", "text": "CXCR5"}]'::jsonb, 'B', 'Macrophage-tropic (R5) HIV strains use CCR5 as coreceptor. T-cell-tropic (X4) strains use CXCR4. CCR5-Δ32 mutation confers resistance to R5 strains of HIV. 📚 Jawetz Medical Microbiology, 28th Ed, Ch.44', 1, 'nucleux-content', '{}'),
  ('Microbiology', 'HIV Virology & Diagnosis', 'The earliest detectable marker of HIV infection during the window period is:', '[{"key": "A", "text": "Anti-gp120 antibodies"}, {"key": "B", "text": "Anti-gp41 antibodies"}, {"key": "C", "text": "p24 antigen"}, {"key": "D", "text": "Anti-p24 antibodies"}]'::jsonb, 'C', 'p24 (capsid protein) antigen appears in blood before antibodies develop (window period). 4th generation ELISA detects both p24 antigen and antibodies, shortening the diagnostic window. 📚 Ananthanarayan, 11th Ed, Ch.62', 1, 'nucleux-content', '{}'),
  ('Microbiology', 'HIV Virology & Diagnosis', 'An HIV patient with CD4 count of 80/μL presents with ring-enhancing brain lesions. The most likely diagnosis is:', '[{"key": "A", "text": "PCP pneumonia"}, {"key": "B", "text": "Toxoplasma encephalitis"}, {"key": "C", "text": "Cryptococcal meningitis"}, {"key": "D", "text": "CMV retinitis"}]'::jsonb, 'B', 'Ring-enhancing lesions in brain + CD4 <100 = Toxoplasma encephalitis (most common cause of focal brain lesions in AIDS). Treatment: pyrimethamine + sulfadiazine + leucovorin. 📚 Jawetz Medical Microbiology, 28th Ed, Ch.44', 2, 'nucleux-content', '{}'),
  ('Microbiology', 'HIV Virology & Diagnosis', 'Which class of antiretroviral drugs inhibits HIV integrase?', '[{"key": "A", "text": "NRTIs"}, {"key": "B", "text": "NNRTIs"}, {"key": "C", "text": "Protease inhibitors"}, {"key": "D", "text": "INSTIs"}]'::jsonb, 'D', 'Integrase strand transfer inhibitors (INSTIs): dolutegravir, raltegravir, elvitegravir. They block integration of viral DNA into the host genome. Preferred first-line class due to high efficacy, high barrier to resistance, and good tolerability. 📚 Jawetz Medical Microbiology, 28th Ed, Ch.44', 1, 'nucleux-content', '{}'),
  ('Microbiology', 'HIV Virology & Diagnosis', 'Post-exposure prophylaxis (PEP) for HIV should be started within:', '[{"key": "A", "text": "24 hours"}, {"key": "B", "text": "48 hours"}, {"key": "C", "text": "72 hours"}, {"key": "D", "text": "1 week"}]'::jsonb, 'C', 'PEP must be initiated within 72 hours of exposure for efficacy. The 28-day regimen typically uses 3-drug ART (e.g., TDF/FTC + dolutegravir). Earlier initiation = better efficacy. 📚 Ananthanarayan, 11th Ed, Ch.62', 1, 'nucleux-content', '{}'),
  ('Obgyn', 'Ectopic Pregnancy', 'The most common site of ectopic pregnancy is:', '[{"key": "A", "text": "Isthmus of fallopian tube"}, {"key": "B", "text": "Ampulla of fallopian tube"}, {"key": "C", "text": "Interstitial portion of tube"}, {"key": "D", "text": "Ovary"}]'::jsonb, 'B', 'The ampulla is the most common site (70-80%) because fertilization normally occurs here and any delay in tubal transport leads to implantation at this site. 📚 DC Dutta, 9th Ed, Ch.10 (p.117)', 1, 'nucleux-content', '{}'),
  ('Obgyn', 'Ectopic Pregnancy', 'Which of the following is NOT a criterion for medical management of ectopic pregnancy with methotrexate?', '[{"key": "A", "text": "Hemodynamically stable patient"}, {"key": "B", "text": "Unruptured ectopic"}, {"key": "C", "text": "Fetal cardiac activity present"}, {"key": "D", "text": "\u03b2-hCG <5000 mIU/mL"}]'::jsonb, 'C', 'Presence of fetal cardiac activity is a CONTRAINDICATION for methotrexate treatment (lower success rate). Criteria include: stable patient, unruptured, mass <3.5 cm, NO cardiac activity, and preferably β-hCG <5000. Cardiac activity requires surgical management. 📚 Williams Obstetrics, 26th Ed, Ch.19 (p.379)', 2, 'nucleux-content', '{}'),
  ('Obgyn', 'Ectopic Pregnancy', 'In a suspected ectopic pregnancy, the discriminatory zone for transvaginal ultrasound is β-hCG level of:', '[{"key": "A", "text": "500 mIU/mL"}, {"key": "B", "text": "1500-2000 mIU/mL"}, {"key": "C", "text": "5000 mIU/mL"}, {"key": "D", "text": "10,000 mIU/mL"}]'::jsonb, 'B', 'The discriminatory zone is the β-hCG level at which an intrauterine pregnancy should be visible on TVS. If β-hCG is above this level and no IUP is seen, ectopic pregnancy is likely. 📚 Williams Obstetrics, 26th Ed, Ch.19 (p.373)', 1, 'nucleux-content', '{}'),
  ('Obgyn', 'Ectopic Pregnancy', 'Shoulder tip pain in ruptured ectopic pregnancy is due to irritation of:', '[{"key": "A", "text": "Intercostal nerves"}, {"key": "B", "text": "Phrenic nerve (C3-C5)"}, {"key": "C", "text": "Vagus nerve"}, {"key": "D", "text": "Obturator nerve"}]'::jsonb, 'B', 'Blood in the peritoneal cavity irritates the diaphragm, which is innervated by the phrenic nerve (C3-C5). This causes referred pain to the shoulder tip (dermatomal distribution of C3-C5). 📚 DC Dutta, 9th Ed, Ch.10 (p.119)', 2, 'nucleux-content', '{}'),
  ('Obgyn', 'Ectopic Pregnancy', 'A 25-year-old woman with amenorrhea of 7 weeks, vaginal spotting, and β-hCG of 3000 mIU/mL has an empty uterus on TVS with a 2 cm adnexal mass. She is hemodynamically stable. The best management is:', '[{"key": "A", "text": "Expectant management"}, {"key": "B", "text": "Methotrexate single dose"}, {"key": "C", "text": "Laparoscopic salpingectomy"}, {"key": "D", "text": "Repeat \u03b2-hCG after 48 hours"}]'::jsonb, 'B', 'She meets all criteria for medical management: stable, unruptured, mass <3.5 cm (2 cm), β-hCG <5000 (3000). Expectant management requires declining β-hCG. Surgery is reserved for ruptured ectopic or failed medical management. 📚 Williams Obstetrics, 26th Ed, Ch.19 (p.380)', 2, 'nucleux-content', '{}'),
  ('Obgyn', 'Contraception Methods', 'The most effective method of emergency contraception is:', '[{"key": "A", "text": "Levonorgestrel 1.5 mg"}, {"key": "B", "text": "Ulipristal acetate"}, {"key": "C", "text": "Yuzpe regimen"}, {"key": "D", "text": "Copper-T insertion"}]'::jsonb, 'D', 'Cu-T insertion within 5 days of unprotected intercourse has the lowest failure rate (<0.1%) among all emergency contraceptive methods. It also provides ongoing long-term contraception. 📚 DC Dutta, 9th Ed, Ch.30 (p.528)', 1, 'nucleux-content', '{}'),
  ('Obgyn', 'Contraception Methods', 'Combined oral contraceptive pills are absolutely contraindicated in all EXCEPT:', '[{"key": "A", "text": "History of deep vein thrombosis"}, {"key": "B", "text": "Migraine with aura"}, {"key": "C", "text": "Controlled hypertension on medication"}, {"key": "D", "text": "Active breast cancer"}]'::jsonb, 'C', 'Controlled HTN on medication is WHO Category 3 (relative contraindication), not absolute. DVT, migraine with aura, and breast cancer are all Category 4 (absolute contraindications). Uncontrolled HTN (≥160/100) is Category 4. 📚 DC Dutta, 9th Ed, Ch.30 (p.518)', 2, 'nucleux-content', '{}'),
  ('Obgyn', 'Contraception Methods', 'The mechanism of action of Copper-T IUCD is:', '[{"key": "A", "text": "Prevents ovulation"}, {"key": "B", "text": "Creates sterile inflammatory reaction toxic to sperm"}, {"key": "C", "text": "Prevents implantation by hormonal action"}, {"key": "D", "text": "Blocks fallopian tubes"}]'::jsonb, 'B', 'Cu-T causes a sterile foreign body inflammatory reaction with increased prostaglandins, macrophages, and copper ions in the endometrium. These are toxic to sperm and ova, preventing fertilization. It acts primarily BEFORE implantation. 📚 DC Dutta, 9th Ed, Ch.30 (p.509)', 1, 'nucleux-content', '{}'),
  ('Obgyn', 'Contraception Methods', 'Which IUCD is the best choice for a woman with menorrhagia?', '[{"key": "A", "text": "Cu-T 380A"}, {"key": "B", "text": "Multiload 375"}, {"key": "C", "text": "LNG-IUS (Mirena)"}, {"key": "D", "text": "Lippes loop"}]'::jsonb, 'C', 'LNG-IUS releases levonorgestrel locally, causing endometrial atrophy and reducing menstrual blood loss by up to 90%. Cu-T actually increases menstrual bleeding. Mirena is both a contraceptive and therapeutic for menorrhagia. 📚 DC Dutta, 9th Ed, Ch.30 (p.513)', 1, 'nucleux-content', '{}'),
  ('Obgyn', 'Contraception Methods', 'Levonorgestrel emergency contraception is most effective when taken within:', '[{"key": "A", "text": "12 hours"}, {"key": "B", "text": "24 hours"}, {"key": "C", "text": "72 hours"}, {"key": "D", "text": "120 hours"}]'::jsonb, 'B', 'Levonorgestrel''s efficacy is highest when taken within 24 hours (95% effective), decreasing to 85% at 24-48 hours and 58% at 48-72 hours. Ulipristal acetate maintains higher efficacy up to 120 hours. Cu-T can be inserted up to 5 days. 📚 DC Dutta, 9th Ed, Ch.30 (p.528)', 1, 'nucleux-content', '{}'),
  ('Obgyn', 'Cervical Cancer Screening & Management', 'HPV E6 oncoprotein causes cervical carcinogenesis by degrading:', '[{"key": "A", "text": "Rb protein"}, {"key": "B", "text": "p53 protein"}, {"key": "C", "text": "BRCA1 protein"}, {"key": "D", "text": "APC protein"}]'::jsonb, 'B', 'HPV E6 binds to and promotes ubiquitin-mediated degradation of p53, removing a key tumor suppressor. E7 inactivates Rb protein. Together, they disable cell cycle checkpoints. 📚 DC Dutta, 9th Ed, Ch.22 (p.351)', 1, 'nucleux-content', '{}'),
  ('Obgyn', 'Cervical Cancer Screening & Management', 'The most sensitive screening method for cervical cancer is:', '[{"key": "A", "text": "Pap smear"}, {"key": "B", "text": "VIA"}, {"key": "C", "text": "HPV DNA testing"}, {"key": "D", "text": "Colposcopy"}]'::jsonb, 'C', 'HPV DNA testing has sensitivity >95% and the best negative predictive value. WHO (2021) recommends it as the primary screening method. A negative HPV test allows longer screening intervals (5-10 years). 📚 DC Dutta, 9th Ed, Ch.22 (p.355)', 1, 'nucleux-content', '{}'),
  ('Obgyn', 'Cervical Cancer Screening & Management', 'Cervical cancer staging is done by:', '[{"key": "A", "text": "Surgical staging"}, {"key": "B", "text": "Clinical staging"}, {"key": "C", "text": "Pathological staging"}, {"key": "D", "text": "Radiological staging"}]'::jsonb, 'B', 'Cervical cancer follows FIGO clinical staging (exam under anesthesia, cystoscopy, proctoscopy, X-ray, IVP). This allows staging even in resource-limited settings without surgery. Once assigned, the stage does not change. 📚 DC Dutta, 9th Ed, Ch.22 (p.363)', 1, 'nucleux-content', '{}'),
  ('Obgyn', 'Cervical Cancer Screening & Management', 'The treatment of choice for CIN 2/3 is:', '[{"key": "A", "text": "Cryotherapy"}, {"key": "B", "text": "LEEP (Loop Electrosurgical Excision Procedure)"}, {"key": "C", "text": "Radical hysterectomy"}, {"key": "D", "text": "Radiation therapy"}]'::jsonb, 'B', 'LEEP/LLETZ is the most commonly used excisional procedure for CIN 2/3. It provides a tissue specimen for histopathological examination (unlike ablative methods) and can be done as an outpatient procedure under local anesthesia. 📚 DC Dutta, 9th Ed, Ch.22 (p.359)', 1, 'nucleux-content', '{}'),
  ('Obgyn', 'Cervical Cancer Screening & Management', 'A 45-year-old woman with cervical cancer has parametrial involvement bilaterally but has not reached the pelvic wall. Her FIGO stage is:', '[{"key": "A", "text": "Stage IIA"}, {"key": "B", "text": "Stage IIB"}, {"key": "C", "text": "Stage IIIA"}, {"key": "D", "text": "Stage IIIB"}]'::jsonb, 'B', 'Stage II = extends beyond cervix. IIA = no parametrial involvement. IIB = parametrial involvement present but not reaching the pelvic wall. Stage III involves pelvic wall or lower 1/3 vagina. Treatment for IIB is concurrent chemoradiation. 📚 DC Dutta, 9th Ed, Ch.22 (p.364)', 2, 'nucleux-content', '{}'),
  ('Obgyn', 'Antepartum Hemorrhage (Placenta Previa & Abruption)', 'A 32-year-old multigravida at 34 weeks presents with sudden painless bright red vaginal bleeding. Uterus is soft and non-tender. The most likely diagnosis is:', '[{"key": "A", "text": "Placental abruption"}, {"key": "B", "text": "Placenta previa"}, {"key": "C", "text": "Vasa previa"}, {"key": "D", "text": "Cervical polyp"}]'::jsonb, 'B', 'Painless, bright red, recurrent bleeding with a soft non-tender uterus in the third trimester is classic for placenta previa. Abruption would present with pain and tense tender uterus. 📚 DC Dutta, 9th Ed, Ch.18 (p.242)', 1, 'nucleux-content', '{}'),
  ('Obgyn', 'Antepartum Hemorrhage (Placenta Previa & Abruption)', 'The most common predisposing factor for placental abruption is:', '[{"key": "A", "text": "Placenta previa"}, {"key": "B", "text": "Hypertension"}, {"key": "C", "text": "Uterine anomaly"}, {"key": "D", "text": "Gestational diabetes"}]'::jsonb, 'B', 'Hypertension (chronic or pre-eclampsia) is the single most common risk factor for placental abruption, present in ~50% of cases severe enough to cause fetal death. Other risk factors include trauma, cocaine use, smoking, and PPROM. 📚 Williams Obstetrics, 26th Ed, Ch.42 (p.760)', 1, 'nucleux-content', '{}'),
  ('Obgyn', 'Antepartum Hemorrhage (Placenta Previa & Abruption)', 'A pregnant woman at 35 weeks with suspected placenta previa — which investigation is the GOLD STANDARD for diagnosis?', '[{"key": "A", "text": "Transabdominal ultrasound"}, {"key": "B", "text": "Transvaginal ultrasound"}, {"key": "C", "text": "MRI pelvis"}, {"key": "D", "text": "Double setup examination"}]'::jsonb, 'B', 'Transvaginal USG is the gold standard — it is SAFE (probe doesn''t reach the cervical os) and more accurate than transabdominal USG, especially for posterior placenta previa. 📚 Williams Obstetrics, 26th Ed, Ch.41 (p.752)', 1, 'nucleux-content', '{}'),
  ('Obgyn', 'Antepartum Hemorrhage (Placenta Previa & Abruption)', 'Couvelaire uterus is seen in:', '[{"key": "A", "text": "Placenta previa"}, {"key": "B", "text": "Placental abruption"}, {"key": "C", "text": "Uterine rupture"}, {"key": "D", "text": "Vasa previa"}]'::jsonb, 'B', 'Couvelaire uterus (uteroplacental apoplexy) occurs in severe abruption when blood dissects into the myometrium, giving a characteristic purple/blue discoloration. The uterus may become atonic, sometimes requiring hysterectomy. 📚 DC Dutta, 9th Ed, Ch.18 (p.257)', 1, 'nucleux-content', '{}'),
  ('Obgyn', 'Antepartum Hemorrhage (Placenta Previa & Abruption)', 'Which test differentiates fetal blood from maternal blood in vaginal bleeding?', '[{"key": "A", "text": "Kleihauer-Betke test"}, {"key": "B", "text": "Apt test"}, {"key": "C", "text": "Coombs test"}, {"key": "D", "text": "Bubble stability test"}]'::jsonb, 'B', 'The Apt test uses NaOH (alkali denaturation): fetal hemoglobin (HbF) resists denaturation and remains pink, while adult hemoglobin (HbA) denatures and turns yellow-brown. It is used to diagnose vasa previa. Kleihauer-Betke detects fetal cells in MATERNAL blood (for fetomaternal hemorrhage). 📚 DC Dutta, 9th Ed, Ch.18', 2, 'nucleux-content', '{}'),
  ('Obgyn', 'Gestational Diabetes Mellitus', 'The most specific congenital malformation associated with maternal diabetes is:', '[{"key": "A", "text": "Neural tube defect"}, {"key": "B", "text": "Transposition of great arteries"}, {"key": "C", "text": "Caudal regression syndrome"}, {"key": "D", "text": "Ventricular septal defect"}]'::jsonb, 'C', 'Caudal regression syndrome (sacral agenesis) is the most specific (pathognomonic) malformation for pre-gestational diabetes, though it is rare. NTDs and cardiac defects are more common but less specific. 📚 Williams Obstetrics, 26th Ed, Ch.57', 2, 'nucleux-content', '{}'),
  ('Obgyn', 'Gestational Diabetes Mellitus', 'The main diabetogenic hormone in pregnancy is:', '[{"key": "A", "text": "Estrogen"}, {"key": "B", "text": "Progesterone"}, {"key": "C", "text": "Human placental lactogen (hPL)"}, {"key": "D", "text": "Human chorionic gonadotropin (hCG)"}]'::jsonb, 'C', 'hPL is the principal diabetogenic hormone, causing insulin resistance by mobilizing free fatty acids and reducing glucose utilization. It peaks around 30 weeks, coinciding with maximal insulin resistance. Cortisol and progesterone also contribute. 📚 DC Dutta, 9th Ed, Ch.19 (p.278)', 1, 'nucleux-content', '{}'),
  ('Obgyn', 'Gestational Diabetes Mellitus', 'In DIPSI guidelines, GDM is diagnosed when 2-hour plasma glucose after 75g oral glucose (non-fasting) is:', '[{"key": "A", "text": "\u2265120 mg/dL"}, {"key": "B", "text": "\u2265140 mg/dL"}, {"key": "C", "text": "\u2265153 mg/dL"}, {"key": "D", "text": "\u2265200 mg/dL"}]'::jsonb, 'B', 'DIPSI (Diabetes in Pregnancy Study Group India) recommends a single-step, non-fasting 75g OGTT. A 2-hour value ≥140 mg/dL diagnoses GDM. This is practical for Indian settings as it does not require fasting. 📚 DC Dutta, 9th Ed, Ch.19 (p.282)', 1, 'nucleux-content', '{}'),
  ('Obgyn', 'Gestational Diabetes Mellitus', 'The most common neonatal complication of gestational diabetes is:', '[{"key": "A", "text": "Macrosomia"}, {"key": "B", "text": "Hypoglycemia"}, {"key": "C", "text": "Polycythemia"}, {"key": "D", "text": "Respiratory distress syndrome"}]'::jsonb, 'B', 'After delivery, the fetus is cut off from maternal glucose supply but still has high insulin levels (from in-utero hyperinsulinemia) → neonatal hypoglycemia. Blood glucose monitoring is essential in the first 24 hours. Macrosomia is a fetal complication, not neonatal per se. 📚 DC Dutta, 9th Ed, Ch.19 (p.285)', 1, 'nucleux-content', '{}'),
  ('Obgyn', 'Gestational Diabetes Mellitus', 'A woman with GDM is not achieving glycemic targets after 2 weeks of medical nutrition therapy. The next step is:', '[{"key": "A", "text": "Add metformin"}, {"key": "B", "text": "Start insulin"}, {"key": "C", "text": "Increase caloric restriction"}, {"key": "D", "text": "Plan immediate delivery"}]'::jsonb, 'B', 'Insulin is the gold standard when MNT fails. It does not cross the placenta and allows precise dose titration. Metformin can be used as an alternative but crosses the placenta. 📚 Williams Obstetrics, 26th Ed, Ch.57', 1, 'nucleux-content', '{}'),
  ('Obgyn', 'Pre-eclampsia & Eclampsia', 'The drug of choice for prevention and treatment of seizures in eclampsia is:', '[{"key": "A", "text": "Diazepam"}, {"key": "B", "text": "Phenytoin"}, {"key": "C", "text": "Magnesium sulfate"}, {"key": "D", "text": "Levetiracetam"}]'::jsonb, 'C', 'MgSO4 is the gold standard for both prophylaxis and treatment of eclamptic seizures (Magpie trial). It is superior to diazepam and phenytoin with fewer maternal side effects and better neonatal outcomes. 📚 Williams Obstetrics, 26th Ed, Ch.40 (p.735)', 1, 'nucleux-content', '{}'),
  ('Obgyn', 'Pre-eclampsia & Eclampsia', 'The first sign of magnesium sulfate toxicity is:', '[{"key": "A", "text": "Respiratory depression"}, {"key": "B", "text": "Cardiac arrest"}, {"key": "C", "text": "Loss of patellar reflex"}, {"key": "D", "text": "Oliguria"}]'::jsonb, 'C', 'Loss of deep tendon reflexes (patellar reflex) occurs at 9-12 mEq/L and is the earliest clinical sign of MgSO4 toxicity. Respiratory depression occurs at 15-17 mEq/L, and cardiac arrest at >30 mEq/L. Checking reflexes before each dose is mandatory. 📚 DC Dutta, 9th Ed, Ch.17 (p.230)', 1, 'nucleux-content', '{}'),
  ('Obgyn', 'Pre-eclampsia & Eclampsia', 'Which of the following is NOT a severe feature of pre-eclampsia?', '[{"key": "A", "text": "BP \u2265160/110 mmHg"}, {"key": "B", "text": "Platelet count <100,000/\u00b5L"}, {"key": "C", "text": "Proteinuria \u22655 g/24 hours"}, {"key": "D", "text": "Serum creatinine >1.1 mg/dL"}]'::jsonb, 'C', 'As per ACOG 2013 criteria, massive proteinuria (≥5g) is NO longer a criterion for severe pre-eclampsia. Severe features include: BP ≥160/110, thrombocytopenia (<100,000), elevated liver enzymes, renal insufficiency, pulmonary edema, and cerebral/visual symptoms. 📚 Williams Obstetrics, 26th Ed, Ch.40 (p.725)', 2, 'nucleux-content', '{}'),
  ('Obgyn', 'Pre-eclampsia & Eclampsia', 'The antidote for magnesium sulfate toxicity is:', '[{"key": "A", "text": "Calcium chloride"}, {"key": "B", "text": "Calcium gluconate"}, {"key": "C", "text": "Sodium bicarbonate"}, {"key": "D", "text": "Protamine sulfate"}]'::jsonb, 'B', 'Calcium gluconate (10%, 10 mL = 1g IV over 3 minutes) is the specific antidote for MgSO4 toxicity. It antagonizes the neuromuscular blockade caused by excess magnesium. Calcium chloride can also work but is more irritating to veins. 📚 DC Dutta, 9th Ed, Ch.17 (p.231)', 1, 'nucleux-content', '{}'),
  ('Obgyn', 'Pre-eclampsia & Eclampsia', 'A 28-year-old primigravida at 34 weeks presents with BP 170/115, headache, and epigastric pain. Labs show platelets 80,000, AST 250, LDH 800 with schistocytes on peripheral smear. The most likely diagnosis is:', '[{"key": "A", "text": "Acute fatty liver of pregnancy"}, {"key": "B", "text": "HELLP syndrome"}, {"key": "C", "text": "Thrombotic thrombocytopenic purpura"}, {"key": "D", "text": "Hemolytic uremic syndrome"}]'::jsonb, 'B', 'This triad of hemolysis (schistocytes, elevated LDH), elevated liver enzymes (AST 250), and low platelets (80,000) in a hypertensive pregnant woman is classic HELLP syndrome. TTP typically has more severe thrombocytopenia and neurological symptoms without hypertension. 📚 Williams Obstetrics, 26th Ed, Ch.40 (p.747)', 2, 'nucleux-content', '{}'),
  ('Obgyn', 'Infertility (Male & Female)', 'The most common correctable cause of male infertility is:', '[{"key": "A", "text": "Cryptorchidism"}, {"key": "B", "text": "Varicocele"}, {"key": "C", "text": "Ejaculatory duct obstruction"}, {"key": "D", "text": "Klinefelter syndrome"}]'::jsonb, 'B', 'Varicocele (abnormal dilatation of pampiniform plexus) is found in 15% of all males and 40% of infertile males. It is the most common surgically correctable cause. It impairs spermatogenesis through increased scrotal temperature. 📚 DC Dutta, 9th Ed, Ch.15 (p.202)', 1, 'nucleux-content', '{}'),
  ('Obgyn', 'Infertility (Male & Female)', 'The gold standard investigation for tubal patency is:', '[{"key": "A", "text": "Hysterosalpingography"}, {"key": "B", "text": "Sonosalpingography"}, {"key": "C", "text": "Laparoscopy with chromopertubation"}, {"key": "D", "text": "Hysteroscopy"}]'::jsonb, 'C', 'Laparoscopy with chromopertubation (dye test — methylene blue injected through cervix, seen spilling from fimbrial ends) is the gold standard. It also allows visualization and treatment of endometriosis, adhesions. HSG is the first-line screening test. 📚 DC Dutta, 9th Ed, Ch.15 (p.209)', 1, 'nucleux-content', '{}'),
  ('Obgyn', 'Infertility (Male & Female)', 'According to WHO 6th edition (2021), normal sperm concentration is:', '[{"key": "A", "text": "\u226510 million/mL"}, {"key": "B", "text": "\u226515 million/mL"}, {"key": "C", "text": "\u226516 million/mL"}, {"key": "D", "text": "\u226520 million/mL"}]'::jsonb, 'C', 'WHO 6th edition (2021) updated the lower reference limits: concentration ≥16 million/mL (previously 15 million in 5th edition), total count ≥39 million, motility ≥42%. 📚 DC Dutta, 9th Ed, Ch.15', 2, 'nucleux-content', '{}'),
  ('Obgyn', 'Infertility (Male & Female)', 'ICSI is primarily indicated for:', '[{"key": "A", "text": "Tubal factor infertility"}, {"key": "B", "text": "Unexplained infertility"}, {"key": "C", "text": "Severe male factor infertility"}, {"key": "D", "text": "Endometriosis"}]'::jsonb, 'C', 'ICSI bypasses all barriers to fertilization by injecting a single sperm directly into the oocyte. It is the treatment of choice for severe oligoasthenoteratozoospermia, obstructive azoospermia (using TESA/MESA), and previous IVF fertilization failure. 📚 DC Dutta, 9th Ed, Ch.15 (p.219)', 1, 'nucleux-content', '{}'),
  ('Obgyn', 'Infertility (Male & Female)', 'Congenital bilateral absence of vas deferens (CBAVD) is associated with mutations in:', '[{"key": "A", "text": "SRY gene"}, {"key": "B", "text": "CFTR gene"}, {"key": "C", "text": "Androgen receptor gene"}, {"key": "D", "text": "DAZ gene"}]'::jsonb, 'B', 'CBAVD is found in >95% of males with cystic fibrosis and is caused by mutations in the CFTR gene. These men have obstructive azoospermia but normal spermatogenesis. Sperm can be retrieved by MESA/TESA for ICSI. 📚 DC Dutta, 9th Ed, Ch.15 (p.203)', 2, 'nucleux-content', '{}'),
  ('Obgyn', 'Normal Labor & Partograph', 'In the WHO partograph, the action line is drawn:', '[{"key": "A", "text": "At the same position as the alert line"}, {"key": "B", "text": "2 hours to the right of the alert line"}, {"key": "C", "text": "4 hours to the right of the alert line"}, {"key": "D", "text": "4 hours to the left of the alert line"}]'::jsonb, 'C', 'The action line is drawn 4 hours to the right of the alert line. If cervical dilatation crosses the action line, it indicates need for urgent intervention (augmentation or cesarean section). 📚 DC Dutta, 9th Ed, Ch.37 (p.583)', 1, 'nucleux-content', '{}'),
  ('Obgyn', 'Normal Labor & Partograph', 'The smallest anteroposterior diameter of the fetal skull presenting in a well-flexed vertex is:', '[{"key": "A", "text": "Suboccipitofrontal (10 cm)"}, {"key": "B", "text": "Suboccipitobregmatic (9.5 cm)"}, {"key": "C", "text": "Occipitofrontal (11.5 cm)"}, {"key": "D", "text": "Mentovertical (13.5 cm)"}]'::jsonb, 'B', 'In complete flexion, the suboccipitobregmatic diameter (9.5 cm) presents, which is the most favorable for vaginal delivery. Deflexion increases the presenting diameter progressively. 📚 Williams Obstetrics, 26th Ed, Ch.22', 1, 'nucleux-content', '{}'),
  ('Obgyn', 'Normal Labor & Partograph', 'Which cardinal movement of labor involves rotation of the fetal occiput from the transverse to the anteroposterior diameter of the pelvis?', '[{"key": "A", "text": "Engagement"}, {"key": "B", "text": "Flexion"}, {"key": "C", "text": "Internal rotation"}, {"key": "D", "text": "External rotation"}]'::jsonb, 'C', 'Internal rotation occurs as the fetal head descends and the occiput rotates 45° (in LOA) to bring the sagittal suture into the AP diameter of the pelvic outlet. This is necessary because the inlet is widest transversely but the outlet is widest anteroposteriorly. 📚 Williams Obstetrics, 26th Ed, Ch.22 (p.438)', 1, 'nucleux-content', '{}'),
  ('Obgyn', 'Normal Labor & Partograph', 'Active management of the third stage of labor (AMTSL) includes all EXCEPT:', '[{"key": "A", "text": "Prophylactic uterotonic after delivery of anterior shoulder"}, {"key": "B", "text": "Controlled cord traction"}, {"key": "C", "text": "Uterine massage after placental delivery"}, {"key": "D", "text": "Immediate cord clamping within 15 seconds"}]'::jsonb, 'D', 'AMTSL includes: (1) Oxytocin 10 IU IM within 1 min of delivery, (2) controlled cord traction, (3) uterine massage. Current WHO guidelines recommend DELAYED cord clamping (1-3 min) to improve neonatal iron stores, NOT immediate clamping. 📚 Williams Obstetrics, 26th Ed, Ch.24', 2, 'nucleux-content', '{}'),
  ('Obgyn', 'Normal Labor & Partograph', 'A primigravida in labor has been at 5 cm cervical dilatation for the last 3 hours despite adequate uterine contractions. The most likely diagnosis is:', '[{"key": "A", "text": "Prolonged latent phase"}, {"key": "B", "text": "Arrest of active phase"}, {"key": "C", "text": "Prolonged second stage"}, {"key": "D", "text": "Precipitate labor"}]'::jsonb, 'B', 'Arrest of active phase is defined as no cervical dilatation for ≥2 hours in the presence of adequate contractions (active phase starts at 4 cm). This patient is at 5 cm with no change for 3 hours — classic arrest disorder. Causes include CPD, malposition, or inadequate contractions. 📚 DC Dutta, 9th Ed, Ch.26', 2, 'nucleux-content', '{}'),
  ('Obgyn', 'Postpartum Hemorrhage', 'The most common cause of primary postpartum hemorrhage is:', '[{"key": "A", "text": "Genital tract trauma"}, {"key": "B", "text": "Uterine atony"}, {"key": "C", "text": "Retained placental tissue"}, {"key": "D", "text": "Coagulation disorder"}]'::jsonb, 'B', 'Uterine atony accounts for 70-80% of PPH. The uterus fails to contract adequately after placental separation, and the open sinuses at the placental site continue to bleed. 📚 DC Dutta, 9th Ed, Ch.24 (p.410)', 1, 'nucleux-content', '{}'),
  ('Obgyn', 'Postpartum Hemorrhage', 'Carboprost (15-methyl PGF2α) used in PPH is contraindicated in:', '[{"key": "A", "text": "Hypertension"}, {"key": "B", "text": "Asthma"}, {"key": "C", "text": "Diabetes mellitus"}, {"key": "D", "text": "Heart disease"}]'::jsonb, 'B', 'Carboprost causes bronchospasm and is contraindicated in asthma. Methylergometrine is contraindicated in hypertension (causes vasoconstriction). Carboprost also causes diarrhea and can raise body temperature. 📚 Williams Obstetrics, 26th Ed, Ch.41 (p.785)', 1, 'nucleux-content', '{}'),
  ('Obgyn', 'Postpartum Hemorrhage', 'The WOMAN trial demonstrated that which drug reduces mortality from PPH when given within 3 hours?', '[{"key": "A", "text": "Oxytocin"}, {"key": "B", "text": "Tranexamic acid"}, {"key": "C", "text": "Carboprost"}, {"key": "D", "text": "Misoprostol"}]'::jsonb, 'B', 'The WOMAN trial (2017) showed tranexamic acid 1g IV given within 3 hours of delivery significantly reduces death due to bleeding without increasing thromboembolic events. 📚 Williams Obstetrics, 26th Ed, Ch.41', 2, 'nucleux-content', '{}'),
  ('Obgyn', 'Postpartum Hemorrhage', 'B-Lynch suture is used for:', '[{"key": "A", "text": "Cervical cerclage"}, {"key": "B", "text": "Uterine compression in atonic PPH"}, {"key": "C", "text": "Uterine rupture repair"}, {"key": "D", "text": "Vaginal laceration repair"}]'::jsonb, 'B', 'The B-Lynch brace suture compresses the uterus mechanically when uterotonics and tamponade fail. It preserves the uterus and fertility, unlike hysterectomy. It is applied at laparotomy. 📚 DC Dutta, 9th Ed, Ch.24 (p.419)', 1, 'nucleux-content', '{}'),
  ('Obgyn', 'Postpartum Hemorrhage', 'A woman presents with PPH and neurogenic shock disproportionate to visible blood loss. On examination, a mass is felt at the introitus. The most likely diagnosis is:', '[{"key": "A", "text": "Cervical fibroid polyp"}, {"key": "B", "text": "Uterine inversion"}, {"key": "C", "text": "Uterine rupture"}, {"key": "D", "text": "Prolapsed uterus"}]'::jsonb, 'B', 'Neurogenic shock out of proportion to blood loss with a mass at the introitus is classic for acute uterine inversion. Treatment is Johnson''s maneuver (manual repositioning) under anesthesia. The placenta should NOT be removed before repositioning as it may worsen hemorrhage. 📚 DC Dutta, 9th Ed, Ch.24 (p.425)', 2, 'nucleux-content', '{}'),
  ('Obgyn', 'Polycystic Ovary Syndrome (PCOS)', 'Which of the following is the first-line drug for ovulation induction in PCOS?', '[{"key": "A", "text": "Clomiphene citrate"}, {"key": "B", "text": "Letrozole"}, {"key": "C", "text": "Metformin"}, {"key": "D", "text": "Gonadotropins"}]'::jsonb, 'B', 'Letrozole (aromatase inhibitor) is now first-line for ovulation induction in PCOS, as shown by the NEJM 2014 trial — higher ovulation and live birth rates than clomiphene with lower risk of multiple pregnancies. 📚 DC Dutta, 9th Ed, Ch.28 (p.465)', 1, 'nucleux-content', '{}'),
  ('Obgyn', 'Polycystic Ovary Syndrome (PCOS)', 'The Rotterdam criteria for PCOS diagnosis require:', '[{"key": "A", "text": "All 3 criteria must be present"}, {"key": "B", "text": "Any 2 of 3 criteria"}, {"key": "C", "text": "Hyperandrogenism is mandatory"}, {"key": "D", "text": "Polycystic ovaries on USG is mandatory"}]'::jsonb, 'B', 'Rotterdam criteria (2003) require any 2 of 3: (1) oligo/anovulation, (2) hyperandrogenism, (3) polycystic ovaries on USG, after excluding other causes. No single criterion is mandatory. 📚 DC Dutta, 9th Ed, Ch.28 (p.460)', 1, 'nucleux-content', '{}'),
  ('Obgyn', 'Polycystic Ovary Syndrome (PCOS)', 'In PCOS, the risk of endometrial carcinoma is increased due to:', '[{"key": "A", "text": "Excess progesterone"}, {"key": "B", "text": "Unopposed estrogen stimulation"}, {"key": "C", "text": "Elevated FSH levels"}, {"key": "D", "text": "Low insulin levels"}]'::jsonb, 'B', 'Chronic anovulation means no corpus luteum → no progesterone. Peripheral conversion of androgens to estrone provides continuous estrogenic stimulation of the endometrium without progesterone opposition → endometrial hyperplasia → carcinoma risk. 📚 DC Dutta, 9th Ed, Ch.28 (p.459)', 2, 'nucleux-content', '{}'),
  ('Obgyn', 'Polycystic Ovary Syndrome (PCOS)', 'Which hormone is characteristically DECREASED in PCOS?', '[{"key": "A", "text": "LH"}, {"key": "B", "text": "Testosterone"}, {"key": "C", "text": "SHBG"}, {"key": "D", "text": "Insulin"}]'::jsonb, 'C', 'Sex hormone-binding globulin (SHBG) is decreased due to hyperinsulinemia (insulin suppresses hepatic SHBG production). Low SHBG increases free testosterone, worsening hyperandrogenism. 📚 DC Dutta, 9th Ed, Ch.28 (p.458)', 2, 'nucleux-content', '{}'),
  ('Obgyn', 'Polycystic Ovary Syndrome (PCOS)', 'A 24-year-old obese woman with PCOS wants to conceive. Her BMI is 34. The most appropriate first step is:', '[{"key": "A", "text": "Start letrozole immediately"}, {"key": "B", "text": "Lifestyle modification and weight loss"}, {"key": "C", "text": "Laparoscopic ovarian drilling"}, {"key": "D", "text": "In vitro fertilization"}]'::jsonb, 'B', 'Weight loss of 5-10% is the FIRST step in obese PCOS patients — it improves insulin sensitivity, restores ovulation, and improves response to ovulation induction drugs. Letrozole is first-line pharmacotherapy AFTER lifestyle modification. 📚 DC Dutta, 9th Ed, Ch.28 (p.463)', 1, 'nucleux-content', '{}'),
  ('Pathology', 'Inflammation (Acute & Chronic)', 'A 25-year-old IV drug user presents with high fever, right-sided heart murmur, and multiple septic emboli to the lungs. Blood cultures grow Staphylococcus aureus. The abscess cavities in his lungs would show which type of necrosis?', '[{"key": "A", "text": "Coagulative necrosis"}, {"key": "B", "text": "Caseous necrosis"}, {"key": "C", "text": "Liquefactive necrosis"}, {"key": "D", "text": "Fibrinoid necrosis"}]'::jsonb, 'C', 'Abscesses show liquefactive necrosis — complete enzymatic digestion of tissue by neutrophilic enzymes, resulting in pus (a collection of dead neutrophils, debris, and bacteria). This is different from brain infarct liquefaction (which is ischemic). Caseous necrosis would suggest TB. 📚 Robbins, 10th Ed, Ch.3 (p.48-49)', 2, 'nucleux-content', '{}'),
  ('Pathology', 'Inflammation (Acute & Chronic)', 'Which molecule is responsible for the ''rolling'' step of leukocyte recruitment in acute inflammation?', '[{"key": "A", "text": "Integrins (LFA-1)"}, {"key": "B", "text": "Selectins (E-selectin, P-selectin)"}, {"key": "C", "text": "PECAM-1 (CD31)"}, {"key": "D", "text": "Immunoglobulins (IgG)"}]'::jsonb, 'B', 'Rolling is mediated by selectins — P-selectin (stored in Weibel-Palade bodies of endothelium, released by histamine), E-selectin (induced by TNF/IL-1 on endothelium), L-selectin (on leukocytes). Integrins mediate firm adhesion. PECAM-1 mediates transmigration/diapedesis. 📚 Robbins, 10th Ed, Ch.3 (p.78-80)', 1, 'nucleux-content', '{}'),
  ('Pathology', 'Inflammation (Acute & Chronic)', 'A 30-year-old African American woman presents with bilateral hilar lymphadenopathy, erythema nodosum, and elevated ACE levels. Lymph node biopsy would most likely show:', '[{"key": "A", "text": "Caseating granulomas with Langhans giant cells"}, {"key": "B", "text": "Non-caseating granulomas with epithelioid cells"}, {"key": "C", "text": "Necrotizing vasculitis with fibrinoid necrosis"}, {"key": "D", "text": "Reed-Sternberg cells in a mixed inflammatory background"}]'::jsonb, 'B', 'This is classic sarcoidosis — bilateral hilar lymphadenopathy, erythema nodosum, elevated ACE, in a young African American woman. Sarcoidosis shows NON-caseating granulomas. Caseating granulomas would suggest TB. Always rule out TB before diagnosing sarcoidosis. Reed-Sternberg cells indicate Hodgkin lymphoma. 📚 Robbins, 10th Ed, Ch.3 (p.102)', 2, 'nucleux-content', '{}'),
  ('Pathology', 'Inflammation (Acute & Chronic)', 'A child presents with recurrent bacterial infections, delayed separation of umbilical cord, and markedly elevated WBC count but no pus formation. The most likely defect is:', '[{"key": "A", "text": "Myeloperoxidase deficiency"}, {"key": "B", "text": "NADPH oxidase deficiency (CGD)"}, {"key": "C", "text": "CD18 integrin deficiency (LAD-1)"}, {"key": "D", "text": "C5 complement deficiency"}]'::jsonb, 'C', 'LAD-1 (Leukocyte Adhesion Deficiency type 1) is caused by defective CD18 β2-integrins → neutrophils cannot firmly adhere to endothelium → cannot migrate to infection sites → no pus despite leukocytosis, delayed cord separation, recurrent infections. CGD has pus but cannot kill catalase-positive organisms. MPO deficiency is usually clinically mild. 📚 Robbins, 10th Ed, Ch.3 (p.84)', 3, 'nucleux-content', '{}'),
  ('Pathology', 'Inflammation (Acute & Chronic)', 'Which of the following arachidonic acid metabolites is responsible for the bronchospasm seen in asthma?', '[{"key": "A", "text": "PGE2"}, {"key": "B", "text": "PGI2 (Prostacyclin)"}, {"key": "C", "text": "LTB4"}, {"key": "D", "text": "LTC4, LTD4, LTE4"}]'::jsonb, 'D', 'Leukotrienes C4, D4, E4 (the cysteinyl leukotrienes) are the "slow-reacting substances of anaphylaxis" — they cause prolonged bronchospasm, vasoconstriction, and increased vascular permeability. This is why leukotriene receptor antagonists (montelukast) are used in asthma. LTB4 is chemotactic, not bronchospastic. PGE2 causes vasodilation, pain, fever. 📚 Robbins, 10th Ed, Ch.3 (p.89-91)', 1, 'nucleux-content', '{}'),
  ('Pathology', 'Amyloidosis', 'A 60-year-old man with long-standing rheumatoid arthritis develops nephrotic syndrome. Kidney biopsy shows amorphous eosinophilic material in glomeruli that stains positive with Congo red. The amyloid protein deposited is most likely:', '[{"key": "A", "text": "AL (immunoglobulin light chain)"}, {"key": "B", "text": "AA (serum amyloid A)"}, {"key": "C", "text": "ATTR (transthyretin)"}, {"key": "D", "text": "A\u03b22M (\u03b22-microglobulin)"}]'::jsonb, 'B', 'Chronic inflammatory conditions like RA produce sustained elevation of SAA (an acute phase reactant from the liver), which can deposit as AA amyloid. This is secondary (reactive) amyloidosis. AL amyloid would be associated with plasma cell dyscrasias, not RA. ATTR is hereditary or senile. Aβ2M is dialysis-related. 📚 Robbins, 10th Ed, Ch.6 (p.256)', 1, 'nucleux-content', '{}'),
  ('Pathology', 'Amyloidosis', 'Which staining pattern is pathognomonic for amyloid?', '[{"key": "A", "text": "PAS-positive, diastase-resistant granules"}, {"key": "B", "text": "Congo red with apple-green birefringence under polarized light"}, {"key": "C", "text": "Sudan black positivity"}, {"key": "D", "text": "Prussian blue positivity"}]'::jsonb, 'B', 'Congo red binds to the β-pleated sheet structure of amyloid fibrils, producing a salmon-pink color under ordinary light and pathognomonic APPLE-GREEN BIREFRINGENCE under polarized light. PAS-positive = glycogen. Sudan black = lipids/myeloperoxidase. Prussian blue = iron (hemosiderin). 📚 Robbins, 10th Ed, Ch.6 (p.254)', 1, 'nucleux-content', '{}'),
  ('Pathology', 'Amyloidosis', 'A 65-year-old man presents with progressive heart failure with preserved ejection fraction, low-voltage ECG, and thickened ventricular walls on echocardiography. Endomyocardial biopsy is Congo red positive. The most likely type of amyloid is:', '[{"key": "A", "text": "AL amyloid"}, {"key": "B", "text": "AA amyloid"}, {"key": "C", "text": "Wild-type ATTR (senile cardiac)"}, {"key": "D", "text": "A\u03b2 amyloid"}]'::jsonb, 'C', 'Senile cardiac amyloidosis (wild-type ATTR) is caused by deposition of normal (wild-type) transthyretin in the heart of elderly men. It presents as restrictive cardiomyopathy with diastolic dysfunction. While AL can also cause cardiac amyloidosis, in an elderly man without evidence of plasma cell dyscrasia, wild-type ATTR is most common. 📚 Robbins, 10th Ed, Ch.6 (p.257)', 3, 'nucleux-content', '{}'),
  ('Pathology', 'Amyloidosis', 'A patient with multiple myeloma develops nephrotic syndrome, hepatomegaly, and macroglossia. Which amyloid precursor protein is responsible?', '[{"key": "A", "text": "Serum amyloid A"}, {"key": "B", "text": "Immunoglobulin light chains"}, {"key": "C", "text": "Transthyretin"}, {"key": "D", "text": "\u03b22-microglobulin"}]'::jsonb, 'B', 'Multiple myeloma is associated with AL (primary) amyloidosis. Malignant plasma cells produce excess immunoglobulin light chains (usually lambda) that misfold and deposit as amyloid. Macroglossia is almost pathognomonic for AL amyloidosis. AA amyloid is from chronic inflammation, not myeloma. 📚 Robbins, 10th Ed, Ch.6 (p.255)', 1, 'nucleux-content', '{}'),
  ('Pathology', 'Amyloidosis', 'A patient on chronic hemodialysis for 10 years develops carpal tunnel syndrome and joint stiffness. Biopsy of synovium shows amyloid deposition. The precursor protein is:', '[{"key": "A", "text": "AL (light chains)"}, {"key": "B", "text": "AA (SAA)"}, {"key": "C", "text": "A\u03b22M (\u03b22-microglobulin)"}, {"key": "D", "text": "ATTR (transthyretin)"}]'::jsonb, 'C', 'Dialysis-associated amyloidosis is caused by β2-microglobulin (Aβ2M), which is normally filtered by the kidney but accumulates in patients on long-term hemodialysis. It deposits preferentially in joints and periarticular tissues, causing carpal tunnel syndrome and destructive arthropathy. 📚 Robbins, 10th Ed, Ch.6 (p.257)', 2, 'nucleux-content', '{}'),
  ('Pathology', 'Bone Tumors', 'A 15-year-old boy presents with pain and swelling around the knee. X-ray shows a destructive lesion in the distal femoral metaphysis with periosteal elevation (Codman triangle) and a sunburst pattern. Biopsy shows osteoid production by malignant cells. The diagnosis is:', '[{"key": "A", "text": "Ewing sarcoma"}, {"key": "B", "text": "Osteosarcoma"}, {"key": "C", "text": "Chondrosarcoma"}, {"key": "D", "text": "Giant cell tumor"}]'::jsonb, 'B', 'Adolescent + metaphysis of distal femur + Codman triangle + sunburst pattern + malignant osteoid production = osteosarcoma. Ewing sarcoma would be in the diaphysis with onion-skin pattern. Chondrosarcoma is in older adults. Giant cell tumor is in the epiphysis of young adults. 📚 Robbins, 10th Ed, Ch.26 (p.1189)', 1, 'nucleux-content', '{}'),
  ('Pathology', 'Bone Tumors', 'A 12-year-old boy has a painful swelling in the femoral diaphysis. Biopsy shows small round blue cells that are PAS-positive and CD99+. Cytogenetics shows t(11;22). The diagnosis is:', '[{"key": "A", "text": "Osteosarcoma"}, {"key": "B", "text": "Ewing sarcoma"}, {"key": "C", "text": "Lymphoma"}, {"key": "D", "text": "Neuroblastoma"}]'::jsonb, 'B', 'Child + diaphysis + small round blue cells + PAS+ (glycogen) + CD99+ + t(11;22) EWS-FLI1 = Ewing sarcoma. CD99 is highly sensitive (though not specific) for Ewing. The diaphyseal location differentiates it from osteosarcoma (metaphysis). Lymphoma would be CD45+. Neuroblastoma arises from adrenal/sympathetic chain. 📚 Robbins, 10th Ed, Ch.26 (p.1195)', 1, 'nucleux-content', '{}'),
  ('Pathology', 'Bone Tumors', 'A 25-year-old woman has pain around the knee. X-ray shows an eccentric, lytic ''soap bubble'' lesion in the epiphysis of the distal femur. Biopsy shows multinucleated giant cells with mononuclear stromal cells. The diagnosis is:', '[{"key": "A", "text": "Osteosarcoma"}, {"key": "B", "text": "Aneurysmal bone cyst"}, {"key": "C", "text": "Giant cell tumor"}, {"key": "D", "text": "Osteochondroma"}]'::jsonb, 'C', 'Young adult + epiphysis + soap bubble lytic lesion + multinucleated giant cells = giant cell tumor (osteoclastoma). It is locally aggressive with tendency for recurrence. Located in epiphysis (unlike osteosarcoma in metaphysis). The neoplastic cells are the stromal cells, not the giant cells. 📚 Robbins, 10th Ed, Ch.26 (p.1196)', 1, 'nucleux-content', '{}'),
  ('Pathology', 'Bone Tumors', 'A 16-year-old boy complains of severe nocturnal bone pain in the tibia that is completely relieved by aspirin. CT shows a small (<2 cm) radiolucent nidus in the cortex. The diagnosis is:', '[{"key": "A", "text": "Osteosarcoma"}, {"key": "B", "text": "Osteoid osteoma"}, {"key": "C", "text": "Osteoblastoma"}, {"key": "D", "text": "Stress fracture"}]'::jsonb, 'B', 'Nocturnal pain + relief by aspirin/NSAIDs + small cortical nidus (<2 cm) = osteoid osteoma. The pain is prostaglandin-mediated, hence aspirin relief. Osteoblastoma is similar but >2 cm, usually in the spine, and NOT relieved by aspirin. Osteosarcoma would show aggressive features. 📚 Robbins, 10th Ed, Ch.26 (p.1185)', 1, 'nucleux-content', '{}'),
  ('Pathology', 'Bone Tumors', 'Metastatic bone disease from prostate cancer typically produces which type of bone lesion?', '[{"key": "A", "text": "Lytic lesions"}, {"key": "B", "text": "Blastic (sclerotic) lesions"}, {"key": "C", "text": "Mixed lytic and blastic"}, {"key": "D", "text": "Expansile ''soap bubble'' lesions"}]'::jsonb, 'B', 'Prostate cancer produces osteoBLASTIC (sclerotic) metastases — increased bone formation appearing as white/dense lesions on X-ray. Elevated PSA + blastic bone lesions = prostate cancer metastasis. Most other cancers (breast, lung, kidney, thyroid) produce osteolytic lesions. Breast can be mixed. 📚 Robbins, 10th Ed, Ch.26 (p.1200)', 1, 'nucleux-content', '{}'),
  ('Pathology', 'Cell Injury & Adaptation', 'A 55-year-old man with long-standing GERD undergoes endoscopy showing salmon-colored mucosa in the lower esophagus. Biopsy shows columnar epithelium with goblet cells replacing squamous epithelium. Which cellular adaptation is demonstrated?', '[{"key": "A", "text": "Hyperplasia"}, {"key": "B", "text": "Metaplasia"}, {"key": "C", "text": "Dysplasia"}, {"key": "D", "text": "Hypertrophy"}]'::jsonb, 'B', 'Barrett''s esophagus is the classic example of metaplasia — replacement of normal squamous epithelium by columnar epithelium with goblet cells due to chronic acid reflux. This is an adaptive but pre-malignant change. Dysplasia would show disordered, atypical cells. Hyperplasia is increase in cell number. Hypertrophy is increase in cell size. 📚 Robbins, 10th Ed, Ch.2 (p.33)', 1, 'nucleux-content', '{}'),
  ('Pathology', 'Cell Injury & Adaptation', 'A patient with acute myocardial infarction dies 3 days after symptom onset. Histopathology of the infarcted area would most likely show:', '[{"key": "A", "text": "Coagulative necrosis with neutrophilic infiltration"}, {"key": "B", "text": "Liquefactive necrosis with macrophage infiltration"}, {"key": "C", "text": "Granulation tissue with fibroblasts"}, {"key": "D", "text": "Dense fibrous scar"}]'::jsonb, 'A', 'At 1-3 days post-MI, coagulative necrosis is established with heavy neutrophilic infiltration (acute inflammation). Liquefactive necrosis occurs in brain, not heart. Macrophages and granulation tissue appear at 7-10 days. Dense scar forms by 2-3 months. 📚 Robbins, 10th Ed, Ch.2 (p.48) & Ch.12 (p.547)', 2, 'nucleux-content', '{}'),
  ('Pathology', 'Cell Injury & Adaptation', 'Which of the following is the ''point of no return'' in cell injury?', '[{"key": "A", "text": "Cellular swelling and ER dilation"}, {"key": "B", "text": "Mitochondrial dysfunction with membrane damage"}, {"key": "C", "text": "Ribosomal detachment from ER"}, {"key": "D", "text": "Myelin figure formation"}]'::jsonb, 'B', 'The point of no return in cell injury is marked by severe mitochondrial dysfunction (inability to generate ATP, opening of mPTP) and profound membrane damage. Cellular swelling, ER dilation, ribosomal detachment, and myelin figures are all features of REVERSIBLE injury. 📚 Robbins, 10th Ed, Ch.2 (p.38)', 2, 'nucleux-content', '{}'),
  ('Pathology', 'Cell Injury & Adaptation', 'A 40-year-old woman with SLE presents with proteinuria. Renal biopsy shows eosinophilic deposits in arteriolar walls. What type of necrosis is this?', '[{"key": "A", "text": "Coagulative necrosis"}, {"key": "B", "text": "Caseous necrosis"}, {"key": "C", "text": "Fibrinoid necrosis"}, {"key": "D", "text": "Fat necrosis"}]'::jsonb, 'C', 'Fibrinoid necrosis occurs when antigen-antibody complexes deposit in vessel walls, appearing as bright pink (eosinophilic) amorphous material on H&E stain. It is characteristic of immune-mediated vasculitis (SLE, PAN) and malignant hypertension. Caseous necrosis is seen in TB; fat necrosis in pancreatitis. 📚 Robbins, 10th Ed, Ch.2 (p.50)', 2, 'nucleux-content', '{}'),
  ('Pathology', 'Cell Injury & Adaptation', 'Which of the following correctly pairs the cellular adaptation with its example?', '[{"key": "A", "text": "Hypertrophy \u2014 Endometrial thickening in menstrual cycle"}, {"key": "B", "text": "Hyperplasia \u2014 Left ventricular enlargement in hypertension"}, {"key": "C", "text": "Atrophy \u2014 Thymus in elderly"}, {"key": "D", "text": "Metaplasia \u2014 Cervical dysplasia"}]'::jsonb, 'C', 'The thymus undergoes age-related (involution) atrophy with replacement by adipose tissue. Endometrial thickening is hyperplasia (increase in cell number, not size). LVH in HTN is hypertrophy (cardiac myocytes cannot divide). Dysplasia is disordered growth, not metaplasia. 📚 Robbins, 10th Ed, Ch.2 (p.31-34)', 1, 'nucleux-content', '{}'),
  ('Pathology', 'Genetic Disorders', 'A newborn presents with flat facial profile, epicanthal folds, single palmar crease, and an endocardial cushion defect. Karyotype would most likely show:', '[{"key": "A", "text": "47,XXY"}, {"key": "B", "text": "45,X"}, {"key": "C", "text": "47,XX,+21"}, {"key": "D", "text": "47,XX,+18"}]'::jsonb, 'C', 'This is classic Down syndrome (trisomy 21) — flat facies, epicanthal folds, simian crease, and endocardial cushion defect (the most common cardiac anomaly in Down syndrome). Klinefelter (47,XXY) presents in adolescent males. Turner (45,X) has female phenotype with short stature. Edwards (trisomy 18) has clenched fists, rocker-bottom feet. 📚 Robbins, 10th Ed, Ch.5 (p.191)', 1, 'nucleux-content', '{}'),
  ('Pathology', 'Genetic Disorders', 'A 15-year-old boy with intellectual disability has a long face, large ears, and macro-orchidism. His maternal grandfather had mild tremor and cognitive decline. The most likely genetic mechanism is:', '[{"key": "A", "text": "Nondisjunction"}, {"key": "B", "text": "Trinucleotide repeat expansion"}, {"key": "C", "text": "Robertsonian translocation"}, {"key": "D", "text": "Uniparental disomy"}]'::jsonb, 'B', 'This is Fragile X syndrome caused by CGG trinucleotide repeat expansion in FMR1 gene on X chromosome. The maternal grandfather likely had a premutation (55-200 repeats → fragile X tremor-ataxia syndrome). The repeat expanded through the mother to a full mutation (>200) in the grandson. This demonstrates anticipation. 📚 Robbins, 10th Ed, Ch.5 (p.187)', 2, 'nucleux-content', '{}'),
  ('Pathology', 'Genetic Disorders', 'An obese child with hypotonia, hypogonadism, and intellectual disability is found to have a deletion on chromosome 15. This deletion was inherited from:', '[{"key": "A", "text": "Mother"}, {"key": "B", "text": "Father"}, {"key": "C", "text": "Either parent equally"}, {"key": "D", "text": "Cannot be determined without molecular testing"}]'::jsonb, 'B', 'This is Prader-Willi syndrome — obesity, hypotonia, hypogonadism, intellectual disability — caused by deletion of the PATERNAL copy of 15q11-13. The maternal copy is normally imprinted (silenced), so loss of the paternal copy means no functional gene. If the maternal copy were deleted instead, it would cause Angelman syndrome. 📚 Robbins, 10th Ed, Ch.5 (p.189)', 2, 'nucleux-content', '{}'),
  ('Pathology', 'Genetic Disorders', 'A tall 20-year-old male with learning difficulties is found to have small, firm testes, gynecomastia, and azoospermia. Serum FSH and LH are elevated. The karyotype is:', '[{"key": "A", "text": "47,XYY"}, {"key": "B", "text": "47,XXY"}, {"key": "C", "text": "45,X/46,XY mosaic"}, {"key": "D", "text": "46,XX male"}]'::jsonb, 'B', 'This is Klinefelter syndrome (47,XXY) — the most common sex chromosome aneuploidy and most common cause of male hypogonadism. Features: tall stature, gynecomastia, small firm testes, azoospermia, elevated gonadotropins (hypergonadotropic hypogonadism). 47,XYY males are tall but usually fertile. 📚 Robbins, 10th Ed, Ch.5 (p.194)', 1, 'nucleux-content', '{}'),
  ('Pathology', 'Genetic Disorders', 'A child with recurrent pulmonary infections is found to have Pseudomonas colonization of the airways and steatorrhea. Sweat chloride is 75 mEq/L. The most common underlying mutation is:', '[{"key": "A", "text": "CFTR G551D"}, {"key": "B", "text": "CFTR \u0394F508"}, {"key": "C", "text": "CFTR R117H"}, {"key": "D", "text": "CFTR W1282X"}]'::jsonb, 'B', 'This is cystic fibrosis. ΔF508 (deletion of phenylalanine at position 508) is the most common CFTR mutation, accounting for ~70% of CF alleles worldwide. It causes misfolding of the CFTR protein, which is then degraded in the ER (class II mutation). Other mutations are less common. 📚 Robbins, 10th Ed, Ch.5 (p.168)', 2, 'nucleux-content', '{}'),
  ('Pathology', 'Hemodynamic Disorders (Thrombosis, Embolism, Infarction)', 'A 28-year-old woman on oral contraceptives develops sudden-onset dyspnea and pleuritic chest pain after a long flight. CT pulmonary angiogram shows a filling defect in the right pulmonary artery. Where did the embolus most likely originate?', '[{"key": "A", "text": "Right atrium"}, {"key": "B", "text": "Deep veins of the lower extremity"}, {"key": "C", "text": "Superior vena cava"}, {"key": "D", "text": "Portal vein"}]'::jsonb, 'B', '>95% of pulmonary emboli originate from deep vein thrombosis of the lower extremities, most commonly the popliteal, femoral, and iliac veins. This patient has multiple risk factors: OCP use and prolonged immobilization (long flight). Right atrial thrombi are rare. Portal vein thrombi go to the liver, not lungs. 📚 Robbins, 10th Ed, Ch.4 (p.131)', 1, 'nucleux-content', '{}'),
  ('Pathology', 'Hemodynamic Disorders (Thrombosis, Embolism, Infarction)', 'Which of the following findings on autopsy would differentiate an antemortem thrombus from a postmortem clot?', '[{"key": "A", "text": "Red color"}, {"key": "B", "text": "Gelatinous consistency"}, {"key": "C", "text": "Lines of Zahn"}, {"key": "D", "text": "Smooth surface"}]'::jsonb, 'C', 'Lines of Zahn are alternating pale (platelet/fibrin) and dark (RBC) laminations seen only in thrombi formed DURING LIFE (antemortem). They indicate that the thrombus formed in flowing blood. Postmortem clots are homogeneous, rubbery, and lack these lines. 📚 Robbins, 10th Ed, Ch.4 (p.128)', 2, 'nucleux-content', '{}'),
  ('Pathology', 'Hemodynamic Disorders (Thrombosis, Embolism, Infarction)', 'A 70-year-old man with atrial fibrillation suddenly develops left-sided weakness. MRI shows infarction in the right MCA territory. This infarct is most likely:', '[{"key": "A", "text": "White (pale) infarct"}, {"key": "B", "text": "Red (hemorrhagic) infarct"}, {"key": "C", "text": "Septic infarct"}, {"key": "D", "text": "Venous infarct"}]'::jsonb, 'A', 'Brain infarcts from arterial occlusion (thromboembolism from atrial fibrillation) are initially pale infarcts in a solid organ with end-arterial supply. Note: they can become hemorrhagic upon reperfusion. But the primary mechanism in this case is arterial occlusion → pale infarct. Venous infarcts and septic infarcts are different entities. 📚 Robbins, 10th Ed, Ch.4 (p.135)', 2, 'nucleux-content', '{}'),
  ('Pathology', 'Hemodynamic Disorders (Thrombosis, Embolism, Infarction)', 'A patient develops sudden respiratory distress, neurological symptoms, and petechial rash 2 days after a femoral fracture. The most likely diagnosis is:', '[{"key": "A", "text": "Pulmonary thromboembolism"}, {"key": "B", "text": "Fat embolism syndrome"}, {"key": "C", "text": "Air embolism"}, {"key": "D", "text": "Amniotic fluid embolism"}]'::jsonb, 'B', 'The classic triad of fat embolism syndrome = respiratory distress + neurological symptoms + petechial rash, occurring 1-3 days after long bone fracture. Fat globules from bone marrow enter venous circulation and lodge in pulmonary and cerebral vasculature. PE would present immediately and lacks the petechial rash. 📚 Robbins, 10th Ed, Ch.4 (p.133)', 1, 'nucleux-content', '{}'),
  ('Pathology', 'Hemodynamic Disorders (Thrombosis, Embolism, Infarction)', 'Which inherited condition is the MOST COMMON cause of inherited hypercoagulability?', '[{"key": "A", "text": "Antithrombin III deficiency"}, {"key": "B", "text": "Protein C deficiency"}, {"key": "C", "text": "Factor V Leiden mutation"}, {"key": "D", "text": "Prothrombin gene mutation"}]'::jsonb, 'C', 'Factor V Leiden is the most common inherited hypercoagulable state, present in ~5% of Caucasians. The mutation makes Factor V resistant to inactivation by activated Protein C, leading to increased thrombin generation. Heterozygotes have 5x increased risk of DVT; homozygotes have 50x risk. 📚 Robbins, 10th Ed, Ch.4 (p.126)', 1, 'nucleux-content', '{}'),
  ('Pathology', 'Immunopathology (Hypersensitivity & Autoimmune Disorders)', 'A patient develops urticaria, bronchospasm, and hypotension within minutes of a penicillin injection. This reaction is mediated by:', '[{"key": "A", "text": "IgG antibodies against penicillin-modified RBCs"}, {"key": "B", "text": "IgE antibodies on mast cells"}, {"key": "C", "text": "Immune complex deposition"}, {"key": "D", "text": "CD8+ T cell-mediated cytotoxicity"}]'::jsonb, 'B', 'Anaphylaxis is Type I (immediate) hypersensitivity. Prior sensitization produced IgE antibodies that coat mast cells via FcεRI. Re-exposure to penicillin crosslinks IgE → mast cell degranulation → histamine release → vasodilation, bronchospasm, hypotension. Type II penicillin reaction would cause hemolytic anemia (days later). 📚 Robbins, 10th Ed, Ch.6 (p.200)', 1, 'nucleux-content', '{}'),
  ('Pathology', 'Immunopathology (Hypersensitivity & Autoimmune Disorders)', 'A renal biopsy shows granular (''lumpy-bumpy'') deposits of IgG and C3 along the glomerular basement membrane on immunofluorescence. The most likely diagnosis is:', '[{"key": "A", "text": "Goodpasture syndrome"}, {"key": "B", "text": "Lupus nephritis"}, {"key": "C", "text": "Minimal change disease"}, {"key": "D", "text": "IgA nephropathy"}]'::jsonb, 'B', 'Granular (lumpy-bumpy) IF pattern indicates immune complex deposition (Type III hypersensitivity) — classic for SLE/lupus nephritis. Goodpasture shows LINEAR IF (anti-GBM antibodies, Type II). Minimal change disease has normal IF. IgA nephropathy shows mesangial IgA deposits. 📚 Robbins, 10th Ed, Ch.6 (p.211)', 2, 'nucleux-content', '{}'),
  ('Pathology', 'Immunopathology (Hypersensitivity & Autoimmune Disorders)', 'A 35-year-old woman presents with dry eyes, dry mouth, and bilateral parotid enlargement. Which antibodies are most specific?', '[{"key": "A", "text": "Anti-dsDNA and anti-Smith"}, {"key": "B", "text": "Anti-SSA (Ro) and anti-SSB (La)"}, {"key": "C", "text": "Anti-centromere"}, {"key": "D", "text": "Anti-mitochondrial"}]'::jsonb, 'B', 'This is Sjögren syndrome (keratoconjunctivitis sicca + xerostomia). Anti-SSA (Ro) and anti-SSB (La) are characteristic. Anti-SSB (La) is more specific for Sjögren. Anti-SSA is also seen in SLE and neonatal lupus. Anti-dsDNA/Smith = SLE. Anti-centromere = CREST. Anti-mitochondrial = primary biliary cholangitis. 📚 Robbins, 10th Ed, Ch.6 (p.226)', 1, 'nucleux-content', '{}'),
  ('Pathology', 'Immunopathology (Hypersensitivity & Autoimmune Disorders)', 'A tuberculin skin test becomes positive (indurated) 48-72 hours after injection. This is an example of:', '[{"key": "A", "text": "Type I hypersensitivity"}, {"key": "B", "text": "Type II hypersensitivity"}, {"key": "C", "text": "Type III hypersensitivity"}, {"key": "D", "text": "Type IV hypersensitivity"}]'::jsonb, 'D', 'The Mantoux/tuberculin test is the classic example of Type IV (delayed-type/cell-mediated) hypersensitivity. Previously sensitized CD4+ Th1 cells recognize tuberculin antigens → release cytokines → macrophage activation → induration at 48-72 hours. No antibodies are involved. Type I is immediate (minutes); Types II and III involve antibodies. 📚 Robbins, 10th Ed, Ch.6 (p.214)', 1, 'nucleux-content', '{}'),
  ('Pathology', 'Immunopathology (Hypersensitivity & Autoimmune Disorders)', 'A woman with SLE has proteinuria and hematuria. Kidney biopsy shows thickened capillary walls with a ''wire-loop'' appearance. What WHO class of lupus nephritis is this?', '[{"key": "A", "text": "Class II (Mesangial proliferative)"}, {"key": "B", "text": "Class III (Focal proliferative)"}, {"key": "C", "text": "Class IV (Diffuse proliferative)"}, {"key": "D", "text": "Class V (Membranous)"}]'::jsonb, 'C', 'Wire-loop lesion = subendothelial immune complex deposits causing thickened capillary walls, seen in Class IV (diffuse proliferative) lupus nephritis — the MOST COMMON and MOST SEVERE form. It has the worst prognosis among lupus nephritis classes and correlates with high anti-dsDNA titers and low complement. 📚 Robbins, 10th Ed, Ch.6 (p.222)', 3, 'nucleux-content', '{}'),
  ('Pathology', 'Neoplasia (Benign vs Malignant)', 'A 60-year-old smoker has a lung mass. Biopsy shows keratin pearls and intercellular bridges. What is the diagnosis?', '[{"key": "A", "text": "Adenocarcinoma"}, {"key": "B", "text": "Squamous cell carcinoma"}, {"key": "C", "text": "Small cell carcinoma"}, {"key": "D", "text": "Large cell carcinoma"}]'::jsonb, 'B', 'Keratin pearls and intercellular bridges (desmosomes) are hallmarks of squamous cell carcinoma. Adenocarcinoma shows glandular differentiation. Small cell has small round blue cells with crush artifact. Large cell is a diagnosis of exclusion. 📚 Robbins, 10th Ed, Ch.15 (p.697)', 1, 'nucleux-content', '{}'),
  ('Pathology', 'Neoplasia (Benign vs Malignant)', 'A tumor suppressor gene requires inactivation of BOTH alleles to lose function. This is explained by:', '[{"key": "A", "text": "Warburg effect"}, {"key": "B", "text": "Knudson two-hit hypothesis"}, {"key": "C", "text": "Philadelphia chromosome theory"}, {"key": "D", "text": "Oncogene addiction"}]'::jsonb, 'B', 'Knudson''s two-hit hypothesis states that both copies of a tumor suppressor gene must be inactivated for loss of function. In hereditary retinoblastoma, one hit is inherited (germline), the second is somatic. In sporadic cases, both hits are somatic (hence later onset, usually unilateral). 📚 Robbins, 10th Ed, Ch.7 (p.268)', 1, 'nucleux-content', '{}'),
  ('Pathology', 'Neoplasia (Benign vs Malignant)', 'A 45-year-old woman with ovarian cancer presents with progressive abdominal distension and peritoneal studding. This pattern of spread is called:', '[{"key": "A", "text": "Lymphatic metastasis"}, {"key": "B", "text": "Hematogenous metastasis"}, {"key": "C", "text": "Transcoelomic (seeding) spread"}, {"key": "D", "text": "Perineural invasion"}]'::jsonb, 'C', 'Ovarian carcinoma characteristically spreads by seeding the peritoneal cavity (transcoelomic spread), producing widespread peritoneal implants and malignant ascites. This is different from lymphatic or hematogenous spread. Other cancers that seed cavities: mesothelioma, CNS tumors (via CSF). 📚 Robbins, 10th Ed, Ch.7 (p.246)', 2, 'nucleux-content', '{}'),
  ('Pathology', 'Neoplasia (Benign vs Malignant)', 'Which oncogene is associated with the t(9;22) Philadelphia chromosome translocation?', '[{"key": "A", "text": "MYC"}, {"key": "B", "text": "RAS"}, {"key": "C", "text": "BCR-ABL"}, {"key": "D", "text": "RET"}]'::jsonb, 'C', 'The Philadelphia chromosome results from t(9;22) translocation creating the BCR-ABL fusion gene, which produces a constitutively active tyrosine kinase. Found in >95% of CML and some ALL. Targeted by imatinib (Gleevec). MYC is associated with t(8;14) in Burkitt lymphoma. 📚 Robbins, 10th Ed, Ch.7 (p.260)', 1, 'nucleux-content', '{}'),
  ('Pathology', 'Neoplasia (Benign vs Malignant)', 'A tumor is classified as T3N1M0. What does the ''N1'' indicate?', '[{"key": "A", "text": "No lymph node involvement"}, {"key": "B", "text": "Regional lymph node metastasis"}, {"key": "C", "text": "Distant metastasis present"}, {"key": "D", "text": "Tumor is well-differentiated"}]'::jsonb, 'B', 'In TNM staging: T = primary tumor size/extent, N = regional lymph node involvement (N0=none, N1-3=increasing involvement), M = distant metastasis (M0=none, M1=present). N1 indicates regional lymph node metastasis is present. Staging is the most important prognostic factor. 📚 Robbins, 10th Ed, Ch.7 (p.249)', 1, 'nucleux-content', '{}'),
  ('Pathology', 'Nutritional Deficiencies', 'A chronic alcoholic presents with confusion, ataxia, and lateral gaze palsy. Which vitamin deficiency is most likely?', '[{"key": "A", "text": "Vitamin B12"}, {"key": "B", "text": "Vitamin B1 (Thiamine)"}, {"key": "C", "text": "Vitamin B3 (Niacin)"}, {"key": "D", "text": "Vitamin C"}]'::jsonb, 'B', 'This is Wernicke encephalopathy — the classic triad of confusion, ataxia, and ophthalmoplegia (lateral gaze palsy) caused by thiamine (B1) deficiency. Common in alcoholics due to poor diet + impaired absorption. Requires URGENT IV thiamine. If untreated, can progress to irreversible Korsakoff syndrome (confabulation, amnesia). 📚 Robbins, 10th Ed, Ch.9 (p.444)', 1, 'nucleux-content', '{}'),
  ('Pathology', 'Nutritional Deficiencies', 'A 2-year-old child from a developing country has edema, fatty liver, flag sign of hair, and skin depigmentation. Serum albumin is 1.5 g/dL. The diagnosis is:', '[{"key": "A", "text": "Marasmus"}, {"key": "B", "text": "Kwashiorkor"}, {"key": "C", "text": "Scurvy"}, {"key": "D", "text": "Rickets"}]'::jsonb, 'B', 'Kwashiorkor = protein deficiency → hypoalbuminemia → edema, fatty liver (impaired lipoprotein synthesis), flag sign (alternating light/dark hair bands), skin changes. Marasmus is total caloric deficiency with severe wasting but NO edema and relatively preserved albumin. The key differentiator is EDEMA. 📚 Robbins, 10th Ed, Ch.9 (p.438)', 1, 'nucleux-content', '{}'),
  ('Pathology', 'Nutritional Deficiencies', 'A patient with carcinoid syndrome develops dermatitis in sun-exposed areas, diarrhea, and confusion. Which vitamin is deficient?', '[{"key": "A", "text": "Vitamin A"}, {"key": "B", "text": "Vitamin B3 (Niacin)"}, {"key": "C", "text": "Vitamin B6"}, {"key": "D", "text": "Vitamin D"}]'::jsonb, 'B', 'Carcinoid tumors divert tryptophan to serotonin synthesis, reducing its availability for niacin (B3) production. This causes pellagra — the 3 D''s: Dermatitis (photosensitive), Diarrhea, Dementia. The dermatitis characteristically appears in sun-exposed areas (Casal necklace around the neck). 📚 Robbins, 10th Ed, Ch.9 (p.446)', 2, 'nucleux-content', '{}'),
  ('Pathology', 'Nutritional Deficiencies', 'A 6-month-old infant presents with irritability, subperiosteal hemorrhages, and poor wound healing. The mother''s diet lacks fresh fruits and vegetables. Deficiency of which vitamin is most likely?', '[{"key": "A", "text": "Vitamin A"}, {"key": "B", "text": "Vitamin C"}, {"key": "C", "text": "Vitamin D"}, {"key": "D", "text": "Vitamin K"}]'::jsonb, 'B', 'Scurvy (vitamin C deficiency) in infants presents with irritability, subperiosteal hemorrhages (painful swelling of limbs), and poor wound healing. Vitamin C is essential for collagen synthesis (proline/lysine hydroxylation). The mother''s diet lacking fruits/vegetables → deficient breast milk vitamin C. 📚 Robbins, 10th Ed, Ch.9 (p.451)', 1, 'nucleux-content', '{}'),
  ('Pathology', 'Nutritional Deficiencies', 'A patient on isoniazid therapy for tuberculosis develops peripheral neuropathy and sideroblastic anemia. Which vitamin supplementation would prevent this?', '[{"key": "A", "text": "Vitamin B1 (Thiamine)"}, {"key": "B", "text": "Vitamin B6 (Pyridoxine)"}, {"key": "C", "text": "Vitamin B12"}, {"key": "D", "text": "Folic acid"}]'::jsonb, 'B', 'Isoniazid inhibits pyridoxine (B6) metabolism, causing B6 deficiency → peripheral neuropathy and sideroblastic anemia (B6 is a cofactor for ALA synthase, the first step in heme synthesis). Pyridoxine supplementation is routinely given with isoniazid to prevent this complication. 📚 Robbins, 10th Ed, Ch.9 (p.447)', 2, 'nucleux-content', '{}'),
  ('Pathology', 'GI Pathology (IBD, Celiac, Tumors)', 'A 25-year-old man presents with chronic diarrhea, RLQ pain, and perianal fistulas. Colonoscopy shows skip lesions with cobblestone mucosa. Biopsy shows transmural inflammation with non-caseating granulomas. The diagnosis is:', '[{"key": "A", "text": "Ulcerative colitis"}, {"key": "B", "text": "Crohn disease"}, {"key": "C", "text": "Intestinal tuberculosis"}, {"key": "D", "text": "Celiac disease"}]'::jsonb, 'B', 'Skip lesions + cobblestone mucosa + transmural inflammation + non-caseating granulomas + perianal fistulas = Crohn disease. UC would be continuous from rectum, mucosal only, no granulomas, no fistulas. Intestinal TB has caseating granulomas. Celiac affects proximal small bowel with villous atrophy. 📚 Robbins, 10th Ed, Ch.17 (p.795)', 1, 'nucleux-content', '{}'),
  ('Pathology', 'GI Pathology (IBD, Celiac, Tumors)', 'A child with chronic diarrhea and failure to thrive has anti-tTG IgA positive. Duodenal biopsy shows villous atrophy, crypt hyperplasia, and increased intraepithelial lymphocytes. The HLA association is:', '[{"key": "A", "text": "HLA-B27"}, {"key": "B", "text": "HLA-DQ2/DQ8"}, {"key": "C", "text": "HLA-DR4"}, {"key": "D", "text": "HLA-A3"}]'::jsonb, 'B', 'Celiac disease is strongly associated with HLA-DQ2 (>90%) and HLA-DQ8. These MHC class II molecules present deamidated gliadin peptides to CD4+ T cells, initiating the immune response. Anti-tTG IgA with characteristic biopsy findings (villous atrophy, crypt hyperplasia, IELs) confirms the diagnosis. 📚 Robbins, 10th Ed, Ch.17 (p.785)', 1, 'nucleux-content', '{}'),
  ('Pathology', 'GI Pathology (IBD, Celiac, Tumors)', 'A patient with FAP undergoes genetic testing showing APC gene mutation. Which additional finding would classify this as Gardner syndrome?', '[{"key": "A", "text": "CNS medulloblastoma"}, {"key": "B", "text": "Osteomas of the mandible"}, {"key": "C", "text": "Hamartomatous polyps"}, {"key": "D", "text": "Mucocutaneous pigmentation"}]'::jsonb, 'B', 'Gardner syndrome = FAP (APC mutation, >100 adenomatous polyps) + osteomas (jaw/skull) + desmoid tumors + epidermoid cysts + dental abnormalities. CNS tumors with APC = Turcot syndrome (medulloblastoma variant). Hamartomatous polyps + mucocutaneous pigmentation = Peutz-Jeghers (STK11). 📚 Robbins, 10th Ed, Ch.17 (p.818)', 2, 'nucleux-content', '{}'),
  ('Pathology', 'GI Pathology (IBD, Celiac, Tumors)', 'A gastric biopsy shows signet ring cells with intracellular mucin pushing the nucleus to the periphery. The stomach wall is thick and rigid. This is:', '[{"key": "A", "text": "Gastric intestinal-type adenocarcinoma"}, {"key": "B", "text": "Gastric diffuse-type adenocarcinoma (linitis plastica)"}, {"key": "C", "text": "Gastric MALT lymphoma"}, {"key": "D", "text": "GIST"}]'::jsonb, 'B', 'Signet ring cells (mucin displaces nucleus) + rigid thick stomach (linitis plastica/"leather bottle") = diffuse type gastric adenocarcinoma. Associated with E-cadherin (CDH1) loss. Worse prognosis than intestinal type. Can metastasize to ovaries (Krukenberg tumor). Intestinal type has glandular differentiation. 📚 Robbins, 10th Ed, Ch.17 (p.810)', 1, 'nucleux-content', '{}'),
  ('Pathology', 'GI Pathology (IBD, Celiac, Tumors)', 'A 55-year-old woman is diagnosed with right-sided colon cancer. She has a family history of endometrial cancer in her mother and colon cancer in her brother. Tumor shows microsatellite instability. The most likely genetic defect is:', '[{"key": "A", "text": "APC gene mutation"}, {"key": "B", "text": "Mismatch repair gene mutation (MLH1/MSH2)"}, {"key": "C", "text": "KRAS mutation"}, {"key": "D", "text": "STK11 mutation"}]'::jsonb, 'B', 'Right-sided CRC + family history of CRC and endometrial cancer + MSI = Lynch syndrome (HNPCC). Caused by germline mutations in DNA mismatch repair genes (MLH1, MSH2, MSH6, PMS2) → microsatellite instability. APC = FAP (hundreds of polyps). STK11 = Peutz-Jeghers. 📚 Robbins, 10th Ed, Ch.17 (p.820)', 2, 'nucleux-content', '{}'),
  ('Pathology', 'Liver Pathology (Hepatitis, Cirrhosis)', 'A patient''s hepatitis B serology shows: HBsAg negative, Anti-HBs positive, Anti-HBc IgG positive, Anti-HBc IgM negative. This pattern indicates:', '[{"key": "A", "text": "Acute hepatitis B"}, {"key": "B", "text": "Chronic hepatitis B"}, {"key": "C", "text": "Recovered from hepatitis B (immune)"}, {"key": "D", "text": "Vaccinated against hepatitis B"}]'::jsonb, 'C', 'Anti-HBs (immunity) + Anti-HBc IgG (past exposure) + negative HBsAg (cleared virus) + negative IgM (not acute) = recovered from natural infection. Vaccinated individuals have ONLY anti-HBs (no anti-HBc because they were never infected). Chronic would have HBsAg still positive. Acute would have anti-HBc IgM positive. 📚 Robbins, 10th Ed, Ch.18 (p.845)', 1, 'nucleux-content', '{}'),
  ('Pathology', 'Liver Pathology (Hepatitis, Cirrhosis)', 'A chronic alcoholic presents with fever, jaundice, tender hepatomegaly, and leukocytosis. AST is 300, ALT is 100. Liver biopsy shows hepatocyte ballooning, neutrophilic infiltration, and Mallory-Denk bodies. The diagnosis is:', '[{"key": "A", "text": "Alcoholic steatosis"}, {"key": "B", "text": "Alcoholic hepatitis"}, {"key": "C", "text": "Viral hepatitis C"}, {"key": "D", "text": "Primary biliary cholangitis"}]'::jsonb, 'B', 'AST:ALT ratio >2:1 + Mallory-Denk bodies + neutrophilic infiltration + hepatocyte ballooning in an alcoholic = alcoholic hepatitis. AST>ALT because alcohol depletes B6 (pyridoxine), which is needed for ALT synthesis. Viral hepatitis typically has ALT>AST. Steatosis is just fat without inflammation. 📚 Robbins, 10th Ed, Ch.18 (p.857)', 1, 'nucleux-content', '{}'),
  ('Pathology', 'Liver Pathology (Hepatitis, Cirrhosis)', 'Which hepatitis virus can cause infection ONLY in the presence of hepatitis B?', '[{"key": "A", "text": "Hepatitis A"}, {"key": "B", "text": "Hepatitis C"}, {"key": "C", "text": "Hepatitis D"}, {"key": "D", "text": "Hepatitis E"}]'::jsonb, 'C', 'Hepatitis D (delta virus) is a defective RNA virus that requires HBsAg for its envelope. It can only replicate in patients who are also infected with HBV. Coinfection (HBV+HDV simultaneously) is usually self-limited. Superinfection (HDV in chronic HBV carrier) is severe with high risk of fulminant hepatitis and progression to cirrhosis. 📚 Robbins, 10th Ed, Ch.18 (p.848)', 1, 'nucleux-content', '{}'),
  ('Pathology', 'Liver Pathology (Hepatitis, Cirrhosis)', 'A 50-year-old man with known cirrhosis presents with a rapidly enlarging liver mass. AFP is 800 ng/mL. He has a history of chronic hepatitis B. The most likely diagnosis is:', '[{"key": "A", "text": "Liver metastasis from colon cancer"}, {"key": "B", "text": "Hepatocellular carcinoma"}, {"key": "C", "text": "Cholangiocarcinoma"}, {"key": "D", "text": "Hepatic adenoma"}]'::jsonb, 'B', 'Cirrhosis + chronic HBV + rising AFP + liver mass = HCC. AFP >400 ng/mL in the setting of cirrhosis is virtually diagnostic. HBV is unique among hepatitis viruses — it can cause HCC even WITHOUT cirrhosis (due to insertional mutagenesis of HBV DNA). Cholangiocarcinoma is associated with PSC, not HBV. 📚 Robbins, 10th Ed, Ch.18 (p.877)', 1, 'nucleux-content', '{}'),
  ('Pathology', 'Liver Pathology (Hepatitis, Cirrhosis)', 'A middle-aged woman presents with pruritus, fatigue, and elevated alkaline phosphatase. Anti-mitochondrial antibody (AMA) is positive. Liver biopsy shows granulomatous destruction of interlobular bile ducts. The diagnosis is:', '[{"key": "A", "text": "Primary sclerosing cholangitis"}, {"key": "B", "text": "Primary biliary cholangitis"}, {"key": "C", "text": "Autoimmune hepatitis"}, {"key": "D", "text": "Drug-induced cholestasis"}]'::jsonb, 'B', 'Middle-aged woman + pruritus + elevated ALP + positive AMA (anti-mitochondrial antibody, >95% specific) + granulomatous destruction of bile ducts = primary biliary cholangitis (PBC). PSC is associated with UC and shows onion-skin fibrosis, not granulomas. Autoimmune hepatitis has anti-smooth muscle and anti-LKM antibodies. 📚 Robbins, 10th Ed, Ch.18 (p.866)', 2, 'nucleux-content', '{}'),
  ('Pathology', 'Anemia (Iron Deficiency, Megaloblastic, Hemolytic)', 'A 30-year-old vegetarian woman presents with fatigue, glossitis, and numbness in her feet. CBC shows MCV 115 fL, pancytopenia, and hypersegmented neutrophils. Serum methylmalonic acid is elevated. The most likely diagnosis is:', '[{"key": "A", "text": "Folate deficiency"}, {"key": "B", "text": "Vitamin B12 deficiency"}, {"key": "C", "text": "Iron deficiency anemia"}, {"key": "D", "text": "Aplastic anemia"}]'::jsonb, 'B', 'Megaloblastic anemia (MCV >100, hypersegmented neutrophils) with neurological symptoms (numbness = peripheral neuropathy) and elevated methylmalonic acid points to B12 deficiency. Folate deficiency also causes megaloblastic anemia but does NOT elevate MMA and does NOT cause neurological symptoms. Vegetarian diet = risk for B12 deficiency. 📚 Robbins, 10th Ed, Ch.14 (p.644)', 1, 'nucleux-content', '{}'),
  ('Pathology', 'Anemia (Iron Deficiency, Megaloblastic, Hemolytic)', 'A child of African descent develops acute hemolytic anemia after taking an antimalarial drug. Peripheral smear shows bite cells and Heinz body preparation is positive. The most likely diagnosis is:', '[{"key": "A", "text": "Sickle cell disease"}, {"key": "B", "text": "Hereditary spherocytosis"}, {"key": "C", "text": "G6PD deficiency"}, {"key": "D", "text": "Autoimmune hemolytic anemia"}]'::jsonb, 'C', 'G6PD deficiency (X-linked recessive) causes episodic hemolytic anemia triggered by oxidative stress (antimalarials like primaquine, sulfonamides, fava beans, infections). Heinz bodies (denatured hemoglobin inclusions) are removed by splenic macrophages creating "bite cells." Common in African and Mediterranean populations. 📚 Robbins, 10th Ed, Ch.14 (p.654)', 1, 'nucleux-content', '{}'),
  ('Pathology', 'Anemia (Iron Deficiency, Megaloblastic, Hemolytic)', 'A 40-year-old woman with SLE presents with jaundice and anemia. Lab: reticulocyte count elevated, indirect bilirubin elevated, LDH elevated, haptoglobin low. Direct Coombs test is positive. The hemolysis is most likely:', '[{"key": "A", "text": "Intravascular, IgM-mediated"}, {"key": "B", "text": "Extravascular, IgG-mediated (warm AIHA)"}, {"key": "C", "text": "Mechanical (microangiopathic)"}, {"key": "D", "text": "Hereditary spherocytosis"}]'::jsonb, 'B', 'SLE is associated with warm AIHA — IgG antibodies coat RBCs → recognized by splenic macrophages → extravascular hemolysis. Positive DAT (direct Coombs) confirms antibodies on RBCs. Warm AIHA is the most common type of AIHA. Cold AIHA (IgM) is associated with Mycoplasma and EBV, not SLE. 📚 Robbins, 10th Ed, Ch.14 (p.666)', 2, 'nucleux-content', '{}'),
  ('Pathology', 'Anemia (Iron Deficiency, Megaloblastic, Hemolytic)', 'A 3-year-old child presents with sudden pallor and reticulocyte count of 0%. He has known sickle cell disease. The most likely cause of this aplastic crisis is:', '[{"key": "A", "text": "Folate deficiency"}, {"key": "B", "text": "Splenic sequestration"}, {"key": "C", "text": "Parvovirus B19 infection"}, {"key": "D", "text": "G6PD deficiency"}]'::jsonb, 'C', 'Aplastic crisis in sickle cell disease (sudden drop in hemoglobin with reticulocyte count near ZERO) is caused by Parvovirus B19, which infects erythroid precursors and halts RBC production. In patients with chronic hemolysis, this is devastating because they depend on high reticulocyte production. Splenic sequestration would show splenomegaly and reticulocytosis, not aplasia. 📚 Robbins, 10th Ed, Ch.14 (p.660)', 2, 'nucleux-content', '{}'),
  ('Pathology', 'Anemia (Iron Deficiency, Megaloblastic, Hemolytic)', 'A woman with menorrhagia has the following labs: serum iron 30 μg/dL (low), TIBC 450 μg/dL (high), ferritin 8 ng/mL (low). These findings are most consistent with:', '[{"key": "A", "text": "Anemia of chronic disease"}, {"key": "B", "text": "Iron deficiency anemia"}, {"key": "C", "text": "Sideroblastic anemia"}, {"key": "D", "text": "Thalassemia trait"}]'::jsonb, 'B', 'The classic iron profile of IDA: ↓serum iron, ↑TIBC (body tries to absorb more iron), ↓ferritin (depleted stores). Anemia of chronic disease shows ↓iron, ↓TIBC, ↑ferritin (iron trapped in macrophages by hepcidin). Sideroblastic anemia has ↑iron, ↑ferritin, ring sideroblasts. Thalassemia has normal iron studies. 📚 Robbins, 10th Ed, Ch.14 (p.641)', 1, 'nucleux-content', '{}'),
  ('Pathology', 'Bleeding Disorders', 'A 5-year-old boy presents with hemarthrosis of the knee after minor trauma. His aPTT is prolonged but PT and bleeding time are normal. The most likely diagnosis is:', '[{"key": "A", "text": "von Willebrand disease"}, {"key": "B", "text": "Hemophilia A"}, {"key": "C", "text": "ITP"}, {"key": "D", "text": "DIC"}]'::jsonb, 'B', 'Hemarthrosis with isolated prolonged aPTT (normal PT, normal BT) in a young boy = hemophilia A (Factor VIII deficiency, X-linked recessive). vWD would also show prolonged BT and ↓ristocetin activity. ITP has thrombocytopenia + mucosal bleeding, not hemarthrosis. DIC would have abnormal PT, aPTT, and platelets. 📚 Robbins, 10th Ed, Ch.14 (p.681)', 1, 'nucleux-content', '{}'),
  ('Pathology', 'Bleeding Disorders', 'A woman develops massive bleeding after abruptio placentae. Lab: platelets 40,000, PT 22 sec, aPTT 55 sec, fibrinogen 80 mg/dL, D-dimer markedly elevated. Peripheral smear shows schistocytes. The diagnosis is:', '[{"key": "A", "text": "ITP"}, {"key": "B", "text": "TTP"}, {"key": "C", "text": "DIC"}, {"key": "D", "text": "Hemophilia A"}]'::jsonb, 'C', 'DIC = consumptive coagulopathy: ↓platelets + ↑PT + ↑aPTT + ↓fibrinogen + ↑↑D-dimer + schistocytes, triggered by obstetric complication (abruptio placentae). ITP has isolated thrombocytopenia with normal coagulation. TTP has ADAMTS13 deficiency and neuro symptoms. The combination of ALL abnormal values + D-dimer elevation is classic DIC. 📚 Robbins, 10th Ed, Ch.14 (p.687)', 2, 'nucleux-content', '{}'),
  ('Pathology', 'Bleeding Disorders', 'A woman with easy bruising and menorrhagia has a bleeding time of 12 min (prolonged), aPTT 45 sec (prolonged), and ristocetin cofactor activity of 20% (low). Platelet count is normal. The most likely diagnosis is:', '[{"key": "A", "text": "Hemophilia A"}, {"key": "B", "text": "von Willebrand disease"}, {"key": "C", "text": "Bernard-Soulier syndrome"}, {"key": "D", "text": "Glanzmann thrombasthenia"}]'::jsonb, 'B', 'vWD: prolonged BT (platelet adhesion defect due to ↓vWF-GPIb interaction) + prolonged aPTT (vWF carries/stabilizes Factor VIII) + ↓ristocetin cofactor activity (ristocetin requires vWF for platelet agglutination). Normal platelet count. Hemophilia A has normal BT. Bernard-Soulier has large platelets + ↓count. 📚 Robbins, 10th Ed, Ch.14 (p.683)', 2, 'nucleux-content', '{}'),
  ('Pathology', 'Bleeding Disorders', 'A child develops bloody diarrhea followed by acute renal failure, hemolytic anemia, and thrombocytopenia. Peripheral smear shows schistocytes. The most likely causative organism is:', '[{"key": "A", "text": "Staphylococcus aureus"}, {"key": "B", "text": "Escherichia coli O157:H7"}, {"key": "C", "text": "Neisseria meningitidis"}, {"key": "D", "text": "Streptococcus pneumoniae"}]'::jsonb, 'B', 'This is classic HUS (hemolytic uremic syndrome) — the triad of MAHA + thrombocytopenia + acute renal failure following bloody diarrhea. E. coli O157:H7 produces Shiga-like toxin that damages endothelial cells, particularly in glomeruli. HUS is the most common cause of acute renal failure in children. 📚 Robbins, 10th Ed, Ch.14 (p.678)', 1, 'nucleux-content', '{}'),
  ('Pathology', 'Bleeding Disorders', 'Which of the following is the BEST screening test for DIC?', '[{"key": "A", "text": "Prothrombin time (PT)"}, {"key": "B", "text": "Bleeding time"}, {"key": "C", "text": "D-dimer"}, {"key": "D", "text": "Platelet count"}]'::jsonb, 'C', 'D-dimer is the BEST test for DIC. It is a fibrin degradation product formed when cross-linked fibrin is broken down by plasmin. Elevated D-dimer confirms that both coagulation and fibrinolysis are activated simultaneously, which is the hallmark of DIC. PT and platelet count are abnormal in DIC but are less specific. 📚 Robbins, 10th Ed, Ch.14 (p.688)', 1, 'nucleux-content', '{}'),
  ('Pathology', 'Leukemia & Lymphoma', 'A 4-year-old child presents with bone pain, hepatosplenomegaly, and pancytopenia. Bone marrow shows >90% lymphoblasts that are TdT+, CD10+, CD19+. The most likely diagnosis is:', '[{"key": "A", "text": "AML"}, {"key": "B", "text": "ALL"}, {"key": "C", "text": "CLL"}, {"key": "D", "text": "Burkitt lymphoma"}]'::jsonb, 'B', 'Pre-B ALL is the most common childhood cancer. TdT (terminal deoxynucleotidyl transferase) is a marker of lymphoid precursors, CD10 (CALLA) and CD19 mark B-lineage. AML would show myeloid markers (MPO, CD13, CD33). CLL occurs in elderly. Burkitt is mature B-cell (TdT negative). 📚 Robbins, 10th Ed, Ch.13 (p.594)', 1, 'nucleux-content', '{}'),
  ('Pathology', 'Leukemia & Lymphoma', 'A 55-year-old man has WBC count of 150,000/μL with left shift, basophilia, and massive splenomegaly. LAP score is low. Cytogenetics shows t(9;22). The best initial treatment is:', '[{"key": "A", "text": "ATRA (all-trans retinoic acid)"}, {"key": "B", "text": "Imatinib (Gleevec)"}, {"key": "C", "text": "R-CHOP chemotherapy"}, {"key": "D", "text": "Splenectomy"}]'::jsonb, 'B', 'This is CML with the hallmark Philadelphia chromosome t(9;22) → BCR-ABL fusion tyrosine kinase. Imatinib is a targeted BCR-ABL tyrosine kinase inhibitor that has revolutionized CML treatment. ATRA is for APL. R-CHOP is for DLBCL. Low LAP score differentiates CML from leukemoid reaction (high LAP). 📚 Robbins, 10th Ed, Ch.13 (p.604)', 1, 'nucleux-content', '{}'),
  ('Pathology', 'Leukemia & Lymphoma', 'A lymph node biopsy shows large binucleated cells with prominent eosinophilic nucleoli (''owl eyes'') in a background of lymphocytes, eosinophils, and histiocytes. These cells are CD15+, CD30+. The diagnosis is:', '[{"key": "A", "text": "Non-Hodgkin lymphoma"}, {"key": "B", "text": "Hodgkin lymphoma"}, {"key": "C", "text": "Metastatic carcinoma"}, {"key": "D", "text": "Reactive lymphadenopathy"}]'::jsonb, 'B', 'Reed-Sternberg cells (large, binucleated, owl-eye nucleoli) that are CD15+ and CD30+ are pathognomonic for classical Hodgkin lymphoma. The mixed inflammatory background (lymphocytes, eosinophils, histiocytes) is characteristic. RS cells are typically CD45 negative (unlike NHL cells which are CD45+). 📚 Robbins, 10th Ed, Ch.13 (p.607)', 1, 'nucleux-content', '{}'),
  ('Pathology', 'Leukemia & Lymphoma', 'A 70-year-old man presents with back pain, anemia, and renal failure. X-ray shows multiple ''punched-out'' lytic lesions in the skull. SPEP shows an M-spike. The diagnosis is:', '[{"key": "A", "text": "Metastatic prostate cancer"}, {"key": "B", "text": "Multiple myeloma"}, {"key": "C", "text": "Waldenstr\u00f6m macroglobulinemia"}, {"key": "D", "text": "Primary hyperparathyroidism"}]'::jsonb, 'B', 'Classic presentation of multiple myeloma: elderly patient with bone pain (lytic lesions), anemia, renal failure (CRAB criteria), and M-spike on SPEP. Punched-out lytic lesions in skull are characteristic. Prostate cancer causes BLASTIC (not lytic) bone lesions. Waldenström has IgM spike but no bone lesions. 📚 Robbins, 10th Ed, Ch.13 (p.625)', 1, 'nucleux-content', '{}'),
  ('Pathology', 'Leukemia & Lymphoma', 'A child in Africa presents with a rapidly growing jaw mass. Biopsy shows medium-sized lymphoid cells with high mitotic rate and a ''starry sky'' pattern. The characteristic translocation is:', '[{"key": "A", "text": "t(9;22)"}, {"key": "B", "text": "t(14;18)"}, {"key": "C", "text": "t(8;14)"}, {"key": "D", "text": "t(11;14)"}]'::jsonb, 'C', 'Endemic Burkitt lymphoma (jaw mass in African children, strongly EBV-associated) has t(8;14) translocation placing MYC oncogene under control of the IgH promoter → massive cell proliferation. Starry sky pattern = tingible-body macrophages among sheets of tumor cells. It''s the fastest growing human tumor. 📚 Robbins, 10th Ed, Ch.13 (p.617)', 1, 'nucleux-content', '{}'),
  ('Pathology', 'Kidney Pathology (Nephrotic, Nephritic, RCC)', 'A 5-year-old child develops periorbital edema and frothy urine. Urine shows 4+ protein and no RBCs. Serum albumin is 1.8 g/dL. Kidney biopsy shows normal light microscopy. EM shows foot process effacement. The diagnosis is:', '[{"key": "A", "text": "FSGS"}, {"key": "B", "text": "Minimal change disease"}, {"key": "C", "text": "Membranous nephropathy"}, {"key": "D", "text": "IgA nephropathy"}]'::jsonb, 'B', 'Child with nephrotic syndrome + normal LM + negative IF + podocyte foot process effacement on EM = minimal change disease (the most common cause of nephrotic syndrome in children). Responds dramatically to corticosteroids. FSGS would show sclerosis in some glomeruli. Membranous has thick GBM. 📚 Robbins, 10th Ed, Ch.20 (p.917)', 1, 'nucleux-content', '{}'),
  ('Pathology', 'Kidney Pathology (Nephrotic, Nephritic, RCC)', 'A 20-year-old man develops gross hematuria and sore throat simultaneously. Renal biopsy shows mesangial IgA deposits on immunofluorescence. The most likely diagnosis is:', '[{"key": "A", "text": "Post-streptococcal GN"}, {"key": "B", "text": "IgA nephropathy"}, {"key": "C", "text": "Goodpasture syndrome"}, {"key": "D", "text": "Lupus nephritis"}]'::jsonb, 'B', 'Gross hematuria SIMULTANEOUS with URI (synpharyngitic, 1-2 days) + mesangial IgA deposits = IgA nephropathy (Berger disease), the most common GN worldwide. PSGN occurs 2-3 WEEKS after strep infection and shows subepithelial humps, not mesangial IgA. This timing difference is a classic NEET-PG question. 📚 Robbins, 10th Ed, Ch.20 (p.933)', 2, 'nucleux-content', '{}'),
  ('Pathology', 'Kidney Pathology (Nephrotic, Nephritic, RCC)', 'A young man presents with hemoptysis and rapidly progressive renal failure. Renal biopsy shows crescents in >50% of glomeruli and LINEAR IgG deposits along the GBM on immunofluorescence. The diagnosis is:', '[{"key": "A", "text": "IgA nephropathy"}, {"key": "B", "text": "Goodpasture syndrome"}, {"key": "C", "text": "Granulomatosis with polyangiitis (Wegener)"}, {"key": "D", "text": "Lupus nephritis"}]'::jsonb, 'B', 'Hemoptysis + rapidly progressive GN + LINEAR IgG deposits on IF = Goodpasture syndrome (anti-GBM disease, Type II hypersensitivity). Anti-GBM antibodies attack type IV collagen in glomerular and pulmonary basement membranes. Crescents indicate RPGN. GPA would be pauci-immune (negative IF). SLE shows granular deposits. 📚 Robbins, 10th Ed, Ch.20 (p.937)', 2, 'nucleux-content', '{}'),
  ('Pathology', 'Kidney Pathology (Nephrotic, Nephritic, RCC)', 'A 60-year-old smoker presents with painless hematuria, flank mass, and polycythemia. CT shows a renal mass with extension into the renal vein. The most likely diagnosis is:', '[{"key": "A", "text": "Wilms tumor"}, {"key": "B", "text": "Renal cell carcinoma"}, {"key": "C", "text": "Transitional cell carcinoma"}, {"key": "D", "text": "Angiomyolipoma"}]'::jsonb, 'B', 'Older adult + hematuria + flank mass + polycythemia (ectopic EPO) + renal vein invasion = classic RCC. Clear cell type is most common and associated with VHL gene deletion (3p). RCC characteristically invades the renal vein and can extend into IVC. Wilms tumor is in children. TCC involves renal pelvis. 📚 Robbins, 10th Ed, Ch.20 (p.953)', 1, 'nucleux-content', '{}'),
  ('Pathology', 'Kidney Pathology (Nephrotic, Nephritic, RCC)', 'A child with aniridia, genitourinary anomalies, and mental retardation develops an abdominal mass. The genetic locus involved is:', '[{"key": "A", "text": "VHL (3p)"}, {"key": "B", "text": "WT1 (11p13)"}, {"key": "C", "text": "RB (13q)"}, {"key": "D", "text": "APC (5q)"}]'::jsonb, 'B', 'WAGR syndrome = Wilms tumor + Aniridia + Genitourinary anomalies + mental Retardation. Caused by deletion of WT1 gene at chromosome 11p13. Wilms tumor is the most common renal malignancy in children (2-5 years), with triphasic histology (blastema, stroma, epithelium). VHL is associated with adult RCC. 📚 Robbins, 10th Ed, Ch.20 (p.955)', 1, 'nucleux-content', '{}'),
  ('Pathology', 'Breast Pathology', 'A 28-year-old woman presents with a firm, mobile, rubbery 2 cm mass in the upper outer quadrant of the breast. Biopsy shows a well-circumscribed proliferation of stroma and glands. The most likely diagnosis is:', '[{"key": "A", "text": "Invasive ductal carcinoma"}, {"key": "B", "text": "Fibroadenoma"}, {"key": "C", "text": "Phyllodes tumor"}, {"key": "D", "text": "Fat necrosis"}]'::jsonb, 'B', 'Fibroadenoma is the most common benign breast tumor in women under 30. It presents as a firm, mobile, rubbery, well-circumscribed mass ("breast mouse"). Histology shows a mixture of stromal and glandular (epithelial) elements. Phyllodes tumors are similar but occur in older women and have leaf-like projections. 📚 Robbins, 10th Ed, Ch.23 (p.1050)', 1, 'nucleux-content', '{}'),
  ('Pathology', 'Breast Pathology', 'A breast biopsy shows malignant cells infiltrating in a single-file (''Indian file'') pattern. Immunohistochemistry shows E-cadherin NEGATIVE. This is most likely:', '[{"key": "A", "text": "Invasive ductal carcinoma (NST)"}, {"key": "B", "text": "Invasive lobular carcinoma"}, {"key": "C", "text": "Medullary-like carcinoma"}, {"key": "D", "text": "Tubular carcinoma"}]'::jsonb, 'B', 'Invasive lobular carcinoma has a characteristic single-file (Indian file) infiltration pattern and is E-cadherin NEGATIVE (loss of CDH1 gene). This distinguishes it from ductal carcinoma which is E-cadherin positive. Lobular carcinoma has a higher tendency for bilateral involvement and peritoneal metastasis. 📚 Robbins, 10th Ed, Ch.23 (p.1060)', 2, 'nucleux-content', '{}'),
  ('Pathology', 'Breast Pathology', 'A 55-year-old woman presents with eczematous changes of the nipple. Biopsy of the nipple skin shows large cells with clear halos in the epidermis. What is the underlying breast pathology?', '[{"key": "A", "text": "Invasive lobular carcinoma"}, {"key": "B", "text": "DCIS extending to the nipple (Paget disease)"}, {"key": "C", "text": "Eczema"}, {"key": "D", "text": "Intraductal papilloma"}]'::jsonb, 'B', 'Paget disease of the nipple presents as eczematous/crusting changes of the nipple. Biopsy shows Paget cells (large, clear halo cells) in the nipple epidermis. It represents extension of underlying DCIS (or invasive carcinoma) to the nipple skin. Always search for underlying breast carcinoma. 📚 Robbins, 10th Ed, Ch.23 (p.1063)', 2, 'nucleux-content', '{}'),
  ('Pathology', 'Breast Pathology', 'A breast cancer is found to be ER negative, PR negative, and HER2 negative. It is most likely associated with mutation in:', '[{"key": "A", "text": "BRCA2"}, {"key": "B", "text": "BRCA1"}, {"key": "C", "text": "p53 alone"}, {"key": "D", "text": "RB"}]'::jsonb, 'B', 'Triple-negative breast cancers (ER-, PR-, HER2-) are strongly associated with BRCA1 mutations (chr 17). They have the worst prognosis due to lack of targeted therapy options. BRCA2-associated cancers tend to be ER-positive. Triple negative cancers often show a basal-like molecular subtype. 📚 Robbins, 10th Ed, Ch.23 (p.1067)', 2, 'nucleux-content', '{}'),
  ('Pathology', 'Breast Pathology', 'A 45-year-old woman presents with a red, swollen, warm breast with peau d''orange skin changes. Biopsy shows carcinoma cells in dermal lymphatics. This is:', '[{"key": "A", "text": "Acute mastitis"}, {"key": "B", "text": "Inflammatory breast cancer"}, {"key": "C", "text": "Paget disease"}, {"key": "D", "text": "Phyllodes tumor"}]'::jsonb, 'B', 'Inflammatory breast cancer presents with diffuse erythema, warmth, and peau d''orange (resembling mastitis) due to carcinoma cells blocking dermal lymphatics. It is NOT a histologic type but a clinical presentation. It has the worst prognosis of all breast cancers. Must biopsy to differentiate from infection. 📚 Robbins, 10th Ed, Ch.23 (p.1064)', 1, 'nucleux-content', '{}'),
  ('Pathology', 'Lung Tumors', 'A 65-year-old male smoker presents with a central hilar mass, hyponatremia (Na 118), and concentrated urine. Biopsy shows small round blue cells with crush artifact. The paraneoplastic syndrome is:', '[{"key": "A", "text": "Hypercalcemia from PTHrP"}, {"key": "B", "text": "SIADH"}, {"key": "C", "text": "Cushing syndrome"}, {"key": "D", "text": "Carcinoid syndrome"}]'::jsonb, 'B', 'Small cell lung carcinoma (central, small round blue cells, crush artifact) is the most common cause of paraneoplastic SIADH → inappropriate ADH secretion → water retention → dilutional hyponatremia with concentrated urine. PTHrP/hypercalcemia is associated with squamous cell. SCLC can also cause ectopic ACTH. 📚 Robbins, 10th Ed, Ch.15 (p.701)', 1, 'nucleux-content', '{}'),
  ('Pathology', 'Lung Tumors', 'A non-smoking 50-year-old woman has a 3 cm peripheral lung nodule. Biopsy shows glandular differentiation with mucin. Molecular testing shows EGFR mutation. The most likely diagnosis is:', '[{"key": "A", "text": "Squamous cell carcinoma"}, {"key": "B", "text": "Adenocarcinoma"}, {"key": "C", "text": "Small cell carcinoma"}, {"key": "D", "text": "Carcinoid tumor"}]'::jsonb, 'B', 'Peripheral location, non-smoker, female, glandular differentiation with mucin, EGFR mutation = classic lung adenocarcinoma. EGFR mutations are targetable with TKIs (erlotinib, osimertinib). Squamous cell is central and keratin-producing. Small cell is central and neuroendocrine. 📚 Robbins, 10th Ed, Ch.15 (p.698)', 1, 'nucleux-content', '{}'),
  ('Pathology', 'Lung Tumors', 'A patient with lung cancer presents with proximal muscle weakness that improves with repeated use. Antibodies are directed against:', '[{"key": "A", "text": "Acetylcholine receptors"}, {"key": "B", "text": "Presynaptic voltage-gated calcium channels"}, {"key": "C", "text": "Postsynaptic sodium channels"}, {"key": "D", "text": "Muscle-specific kinase (MuSK)"}]'::jsonb, 'B', 'Lambert-Eaton myasthenic syndrome is a paraneoplastic condition associated with small cell lung cancer. Antibodies target presynaptic voltage-gated calcium channels → decreased ACh release. Key distinction: weakness IMPROVES with repeated use (vs myasthenia gravis = worsens). Anti-AChR = myasthenia gravis. 📚 Robbins, 10th Ed, Ch.15 (p.701)', 2, 'nucleux-content', '{}'),
  ('Pathology', 'Lung Tumors', 'A 70-year-old man with 40 years of asbestos exposure presents with pleural thickening and effusion. Biopsy shows biphasic pattern with calretinin-positive cells. The diagnosis is:', '[{"key": "A", "text": "Lung adenocarcinoma with pleural metastasis"}, {"key": "B", "text": "Malignant mesothelioma"}, {"key": "C", "text": "Squamous cell carcinoma"}, {"key": "D", "text": "Pleural fibroma"}]'::jsonb, 'B', 'Asbestos exposure + pleural mass + biphasic pattern + calretinin positivity = malignant mesothelioma. Calretinin and CK5/6 are positive in mesothelioma; TTF-1 and CEA are positive in lung adenocarcinoma. Mesothelioma has 25-45 year latency after asbestos exposure. Poor prognosis. 📚 Robbins, 10th Ed, Ch.15 (p.712)', 2, 'nucleux-content', '{}'),
  ('Pathology', 'Lung Tumors', 'A lung cancer patient has serum calcium of 14 mg/dL. PTH is low. The tumor most likely produces:', '[{"key": "A", "text": "ACTH"}, {"key": "B", "text": "ADH"}, {"key": "C", "text": "PTHrP"}, {"key": "D", "text": "Serotonin"}]'::jsonb, 'C', 'Hypercalcemia with suppressed PTH (low) in a lung cancer patient = paraneoplastic PTHrP production, most commonly from squamous cell carcinoma. PTHrP mimics PTH action on bone and kidney but is not detected by the standard PTH assay (hence low PTH). This is the most common cause of malignancy-associated hypercalcemia (humoral hypercalcemia of malignancy). 📚 Robbins, 10th Ed, Ch.15 (p.701)', 1, 'nucleux-content', '{}'),
  ('Pediatrics', 'Immunization Schedule (NIS India)', 'Which vaccine is the most heat-sensitive?', '[{"key": "A", "text": "BCG"}, {"key": "B", "text": "DPT"}, {"key": "C", "text": "OPV"}, {"key": "D", "text": "Hepatitis B"}]'::jsonb, 'C', 'OPV (Oral Polio Vaccine) is the most heat-sensitive vaccine and must be stored frozen (-20°C) at district level and above. It has a VVM to monitor heat exposure. 📚 OP Ghai, 10th Ed, Ch.12 (p.200)', 1, 'nucleux-content', '{}'),
  ('Pediatrics', 'Immunization Schedule (NIS India)', 'Which of the following vaccines should NEVER be frozen?', '[{"key": "A", "text": "BCG"}, {"key": "B", "text": "OPV"}, {"key": "C", "text": "DPT/Pentavalent"}, {"key": "D", "text": "Measles"}]'::jsonb, 'C', 'Vaccines containing aluminum adjuvant (DPT, Pentavalent, Hepatitis B, Td) are freeze-sensitive. Freezing causes aluminum particles to aggregate, reducing immunogenicity and increasing local reactions. 📚 OP Ghai, 10th Ed, Ch.12 (p.201)', 1, 'nucleux-content', '{}'),
  ('Pediatrics', 'Immunization Schedule (NIS India)', 'A 9-month-old malnourished child presents for vaccination. The correct approach is to:', '[{"key": "A", "text": "Defer vaccination until nutritional recovery"}, {"key": "B", "text": "Give all age-appropriate vaccines"}, {"key": "C", "text": "Give only killed vaccines"}, {"key": "D", "text": "Give half doses"}]'::jsonb, 'B', 'Malnutrition is NOT a contraindication to vaccination. In fact, malnourished children are at higher risk of vaccine-preventable diseases and should receive all vaccines as per schedule. 📚 OP Ghai, 10th Ed, Ch.12 (p.204)', 1, 'nucleux-content', '{}'),
  ('Pediatrics', 'Immunization Schedule (NIS India)', 'In the Vaccine Vial Monitor (VVM), the vaccine should be discarded when:', '[{"key": "A", "text": "Inner square is lighter than outer circle"}, {"key": "B", "text": "Inner square is the same color as outer circle"}, {"key": "C", "text": "Outer circle is lighter than inner square"}, {"key": "D", "text": "Both are colorless"}]'::jsonb, 'B', 'VVM changes color with heat exposure. Usable: inner square lighter than outer circle. Discard point: inner square same color or darker than outer circle (cumulative heat exposure exceeded). 📚 OP Ghai, 10th Ed, Ch.12 (p.201)', 1, 'nucleux-content', '{}'),
  ('Pediatrics', 'Immunization Schedule (NIS India)', 'The minimum interval between two live vaccines if not given on the same day is:', '[{"key": "A", "text": "1 week"}, {"key": "B", "text": "2 weeks"}, {"key": "C", "text": "4 weeks"}, {"key": "D", "text": "8 weeks"}]'::jsonb, 'C', 'If two live vaccines are not given on the same day, a minimum interval of 4 weeks (28 days) is required between them. This prevents interference between immune responses. There is no minimum interval for inactivated vaccines. 📚 OP Ghai, 10th Ed, Ch.12 (p.203)', 2, 'nucleux-content', '{}'),
  ('Pediatrics', 'Nephrotic Syndrome in Children', 'The most common histological type of nephrotic syndrome in children is:', '[{"key": "A", "text": "Focal segmental glomerulosclerosis"}, {"key": "B", "text": "Membranous nephropathy"}, {"key": "C", "text": "Minimal change disease"}, {"key": "D", "text": "Membranoproliferative GN"}]'::jsonb, 'C', 'MCD accounts for ~80% of childhood nephrotic syndrome. It has the best prognosis with >90% response to steroids. Light microscopy is normal; electron microscopy shows fusion of podocyte foot processes. 📚 OP Ghai, 10th Ed, Ch.25 (p.481)', 1, 'nucleux-content', '{}'),
  ('Pediatrics', 'Nephrotic Syndrome in Children', 'Renal biopsy in childhood nephrotic syndrome is indicated for:', '[{"key": "A", "text": "First episode in a 4-year-old"}, {"key": "B", "text": "Steroid-resistant nephrotic syndrome"}, {"key": "C", "text": "First relapse"}, {"key": "D", "text": "Frequently relapsing nephrotic syndrome"}]'::jsonb, 'B', 'Renal biopsy is indicated for: steroid resistance (most important), age <1 year or >12 years, low C3, persistent hypertension/hematuria, renal failure. First episode in typical age (1-8 years) does not require biopsy — empirical steroid therapy is started. 📚 OP Ghai, 10th Ed, Ch.25 (p.488)', 1, 'nucleux-content', '{}'),
  ('Pediatrics', 'Nephrotic Syndrome in Children', 'The most common organism causing spontaneous bacterial peritonitis in nephrotic syndrome is:', '[{"key": "A", "text": "Escherichia coli"}, {"key": "B", "text": "Streptococcus pneumoniae"}, {"key": "C", "text": "Staphylococcus aureus"}, {"key": "D", "text": "Klebsiella pneumoniae"}]'::jsonb, 'B', 'In nephrotic syndrome, SBP is most commonly caused by S. pneumoniae (unlike cirrhotic SBP where E. coli predominates). This is due to urinary loss of complement and opsonins that normally protect against encapsulated organisms. 📚 OP Ghai, 10th Ed, Ch.25 (p.490)', 2, 'nucleux-content', '{}'),
  ('Pediatrics', 'Nephrotic Syndrome in Children', 'Frequently relapsing nephrotic syndrome (FRNS) is defined as:', '[{"key": "A", "text": "\u22651 relapse in 6 months"}, {"key": "B", "text": "\u22652 relapses in first 6 months or \u22654 in any 12 months"}, {"key": "C", "text": "Relapse while on steroids"}, {"key": "D", "text": "No response to 4 weeks of steroids"}]'::jsonb, 'B', 'FRNS: ≥2 relapses in the first 6 months of disease or ≥4 relapses in any 12-month period. SDNS: relapse during taper or within 14 days of stopping steroids. SRNS: no remission after 4 weeks of standard daily prednisolone. 📚 OP Ghai, 10th Ed, Ch.25 (p.487)', 2, 'nucleux-content', '{}'),
  ('Pediatrics', 'Nephrotic Syndrome in Children', 'Thromboembolism in nephrotic syndrome is primarily due to urinary loss of:', '[{"key": "A", "text": "Albumin"}, {"key": "B", "text": "IgG"}, {"key": "C", "text": "Antithrombin III"}, {"key": "D", "text": "Complement C3"}]'::jsonb, 'C', 'Antithrombin III is a natural anticoagulant that is lost in urine along with other proteins in nephrotic syndrome. Its loss, combined with hemoconcentration and hyperlipidemia, creates a hypercoagulable state predisposing to renal vein thrombosis and PE. 📚 Nelson''s, 22nd Ed, Ch.545', 2, 'nucleux-content', '{}'),
  ('Pediatrics', 'Growth & Development Milestones', 'A normal infant doubles its birth weight by:', '[{"key": "A", "text": "3 months"}, {"key": "B", "text": "5 months"}, {"key": "C", "text": "8 months"}, {"key": "D", "text": "12 months"}]'::jsonb, 'B', 'Birth weight doubles by 5 months, triples by 12 months, and quadruples by 2 years. This is one of the most frequently tested growth facts in pediatrics. 📚 OP Ghai, 10th Ed, Ch.3 (p.19)', 1, 'nucleux-content', '{}'),
  ('Pediatrics', 'Growth & Development Milestones', 'The anterior fontanelle normally closes by:', '[{"key": "A", "text": "2-3 months"}, {"key": "B", "text": "6-8 months"}, {"key": "C", "text": "12-18 months"}, {"key": "D", "text": "24-36 months"}]'::jsonb, 'C', 'The anterior fontanelle (diamond-shaped, at junction of sagittal, coronal, and frontal sutures) closes by 12-18 months. Premature closure suggests craniosynostosis; delayed closure suggests hypothyroidism, rickets, or raised ICP. 📚 OP Ghai, 10th Ed, Ch.3 (p.22)', 1, 'nucleux-content', '{}'),
  ('Pediatrics', 'Growth & Development Milestones', 'Stranger anxiety in an infant typically appears at:', '[{"key": "A", "text": "3 months"}, {"key": "B", "text": "6 months"}, {"key": "C", "text": "8 months"}, {"key": "D", "text": "12 months"}]'::jsonb, 'C', 'Stranger anxiety (8-month anxiety) appears when the infant can distinguish familiar from unfamiliar faces, indicating development of object permanence and attachment. It is a normal developmental milestone, not a pathological finding. 📚 OP Ghai, 10th Ed, Ch.4 (p.45)', 1, 'nucleux-content', '{}'),
  ('Pediatrics', 'Growth & Development Milestones', 'A child who can copy a triangle is most likely aged:', '[{"key": "A", "text": "3 years"}, {"key": "B", "text": "4 years"}, {"key": "C", "text": "5 years"}, {"key": "D", "text": "6 years"}]'::jsonb, 'C', 'Geometric copying sequence: circle at 3 years, cross at 4 years, triangle at 5 years, diamond at 6 years. This tests fine motor skills and visuospatial ability. 📚 OP Ghai, 10th Ed, Ch.4 (p.40)', 1, 'nucleux-content', '{}'),
  ('Pediatrics', 'Growth & Development Milestones', 'Which of the following is a RED FLAG requiring immediate developmental evaluation?', '[{"key": "A", "text": "Not walking at 14 months"}, {"key": "B", "text": "Not talking in sentences at 18 months"}, {"key": "C", "text": "Loss of previously acquired milestones"}, {"key": "D", "text": "Stranger anxiety at 10 months"}]'::jsonb, 'C', 'Developmental regression (loss of milestones) at any age is always pathological and suggests neurodegenerative disease, metabolic disorder, or CNS pathology. It requires urgent evaluation. Not walking at 14 months is within normal range. 📚 OP Ghai, 10th Ed, Ch.4', 1, 'nucleux-content', '{}'),
  ('Pediatrics', 'Neonatal Jaundice', 'Jaundice appearing within the first 24 hours of life is most likely due to:', '[{"key": "A", "text": "Physiological jaundice"}, {"key": "B", "text": "Breast milk jaundice"}, {"key": "C", "text": "Hemolytic disease (Rh/ABO incompatibility)"}, {"key": "D", "text": "Neonatal hepatitis"}]'::jsonb, 'C', 'Jaundice within 24 hours is ALWAYS pathological. The most common cause is hemolytic disease (ABO incompatibility > Rh incompatibility in India). Physiological jaundice appears after 24 hours. 📚 OP Ghai, 10th Ed, Ch.10 (p.162)', 1, 'nucleux-content', '{}'),
  ('Pediatrics', 'Neonatal Jaundice', 'The most sensitive neural structure to bilirubin toxicity is:', '[{"key": "A", "text": "Cerebral cortex"}, {"key": "B", "text": "Auditory pathway"}, {"key": "C", "text": "Visual cortex"}, {"key": "D", "text": "Cerebellum"}]'::jsonb, 'B', 'The auditory nerve/brainstem auditory pathway is exquisitely sensitive to bilirubin. Sensorineural hearing loss can occur even at moderate bilirubin levels. BERA (brainstem evoked response audiometry) is used for screening in high-risk neonates. 📚 Nelson''s, 22nd Ed, Ch.123', 2, 'nucleux-content', '{}'),
  ('Pediatrics', 'Neonatal Jaundice', 'Bronze baby syndrome occurs when phototherapy is used in a neonate with:', '[{"key": "A", "text": "Unconjugated hyperbilirubinemia"}, {"key": "B", "text": "Conjugated (direct) hyperbilirubinemia"}, {"key": "C", "text": "G6PD deficiency"}, {"key": "D", "text": "Rh incompatibility"}]'::jsonb, 'B', 'Bronze baby syndrome occurs when phototherapy is administered to a neonate with elevated conjugated bilirubin. The conjugated bilirubin and its photoproducts (copper porphyrins) deposit in skin, giving a grayish-brown discoloration. It is reversible. 📚 OP Ghai, 10th Ed, Ch.10 (p.169)', 2, 'nucleux-content', '{}'),
  ('Pediatrics', 'Neonatal Jaundice', 'In double volume exchange transfusion, the volume exchanged in a term neonate is:', '[{"key": "A", "text": "80 mL/kg"}, {"key": "B", "text": "120 mL/kg"}, {"key": "C", "text": "160 mL/kg"}, {"key": "D", "text": "200 mL/kg"}]'::jsonb, 'C', 'Double volume exchange = 2 × blood volume (80 mL/kg) = 160 mL/kg. This removes approximately 85% of circulating bilirubin and replaces antibody-coated RBCs with donor cells. 📚 OP Ghai, 10th Ed, Ch.10 (p.170)', 1, 'nucleux-content', '{}'),
  ('Pediatrics', 'Neonatal Jaundice', 'A 3-week-old exclusively breastfed infant has jaundice with TSB 14 mg/dL (all unconjugated). The baby is thriving, gaining weight, and passing yellow stools. The most likely diagnosis is:', '[{"key": "A", "text": "Biliary atresia"}, {"key": "B", "text": "Breast milk jaundice"}, {"key": "C", "text": "Neonatal hepatitis"}, {"key": "D", "text": "Hypothyroidism"}]'::jsonb, 'B', 'Breast milk jaundice presents as prolonged unconjugated jaundice in a thriving breastfed infant, peaking at 2 weeks, due to β-glucuronidase in breast milk increasing enterohepatic circulation. It is benign. Biliary atresia causes conjugated hyperbilirubinemia with pale stools. 📚 OP Ghai, 10th Ed, Ch.10 (p.163)', 1, 'nucleux-content', '{}'),
  ('Pediatrics', 'Neonatal Resuscitation', 'The single most important step in neonatal resuscitation is:', '[{"key": "A", "text": "Chest compressions"}, {"key": "B", "text": "Epinephrine administration"}, {"key": "C", "text": "Positive pressure ventilation"}, {"key": "D", "text": "Endotracheal intubation"}]'::jsonb, 'C', 'Effective ventilation is the cornerstone of neonatal resuscitation. Most neonates who require resuscitation respond to adequate ventilation alone. Compressions and drugs are rarely needed. 📚 OP Ghai, 10th Ed, Ch.9 (p.143)', 1, 'nucleux-content', '{}'),
  ('Pediatrics', 'Neonatal Resuscitation', 'In neonatal resuscitation, chest compressions are indicated when heart rate is:', '[{"key": "A", "text": "<100 bpm despite PPV"}, {"key": "B", "text": "<80 bpm despite PPV"}, {"key": "C", "text": "<60 bpm despite 30 seconds of effective PPV"}, {"key": "D", "text": "<60 bpm without PPV"}]'::jsonb, 'C', 'Chest compressions are started only when HR remains <60 bpm after 30 seconds of effective PPV. The emphasis is on ensuring effective ventilation first (MR SOPA corrective steps). 📚 Nelson''s, 22nd Ed, Ch.115', 1, 'nucleux-content', '{}'),
  ('Pediatrics', 'Neonatal Resuscitation', 'The compression to ventilation ratio in neonatal resuscitation is:', '[{"key": "A", "text": "15:2"}, {"key": "B", "text": "5:1"}, {"key": "C", "text": "3:1"}, {"key": "D", "text": "30:2"}]'::jsonb, 'C', 'In neonates, the ratio is 3 compressions to 1 ventilation (3:1), giving 90 compressions and 30 breaths per minute (total 120 events/min). This differs from pediatric/adult ratios because neonatal arrest is almost always respiratory in origin. 📚 OP Ghai, 10th Ed, Ch.9 (p.145)', 1, 'nucleux-content', '{}'),
  ('Pediatrics', 'Neonatal Resuscitation', 'Therapeutic hypothermia for birth asphyxia should be initiated within:', '[{"key": "A", "text": "1 hour of birth"}, {"key": "B", "text": "6 hours of birth"}, {"key": "C", "text": "12 hours of birth"}, {"key": "D", "text": "24 hours of birth"}]'::jsonb, 'B', 'Therapeutic hypothermia (33.5°C for 72 hours) must be initiated within 6 hours of birth for maximum benefit. It is indicated for moderate-severe HIE in term/near-term neonates (≥36 weeks). 📚 Nelson''s, 22nd Ed, Ch.115', 1, 'nucleux-content', '{}'),
  ('Pediatrics', 'Neonatal Resuscitation', 'For a term neonate requiring resuscitation at birth, the initial FiO2 should be:', '[{"key": "A", "text": "100%"}, {"key": "B", "text": "60%"}, {"key": "C", "text": "40%"}, {"key": "D", "text": "21% (room air)"}]'::jsonb, 'D', 'NRP 2020 recommends starting with room air (21% FiO2) for term neonates and titrating based on pre-ductal SpO2. High FiO2 (100%) is associated with oxidative stress and delayed time to first breath. Preterm neonates start with 21-30% blended oxygen. 📚 OP Ghai, 10th Ed, Ch.9 (p.143)', 2, 'nucleux-content', '{}'),
  ('Pediatrics', 'Congenital Heart Disease (Classification)', 'The most common congenital heart disease is:', '[{"key": "A", "text": "Atrial septal defect"}, {"key": "B", "text": "Ventricular septal defect"}, {"key": "C", "text": "Patent ductus arteriosus"}, {"key": "D", "text": "Tetralogy of Fallot"}]'::jsonb, 'B', 'VSD accounts for 25-30% of all CHD, making it the most common congenital heart defect. ASD is second most common. TOF is the most common CYANOTIC CHD. 📚 OP Ghai, 10th Ed, Ch.22 (p.393)', 1, 'nucleux-content', '{}'),
  ('Pediatrics', 'Congenital Heart Disease (Classification)', 'A cyanotic neonate with ''egg-on-a-string'' appearance on chest X-ray most likely has:', '[{"key": "A", "text": "Tetralogy of Fallot"}, {"key": "B", "text": "Transposition of great arteries"}, {"key": "C", "text": "Total anomalous pulmonary venous return"}, {"key": "D", "text": "Tricuspid atresia"}]'::jsonb, 'B', 'The ''egg-on-a-string'' (or ''egg-on-its-side'') appearance is characteristic of TGA, caused by a narrow mediastinum due to the anteroposterior relationship of the great vessels. TOF shows boot-shaped heart. TAPVR shows snowman/figure-of-8. 📚 OP Ghai, 10th Ed, Ch.22 (p.411)', 1, 'nucleux-content', '{}'),
  ('Pediatrics', 'Congenital Heart Disease (Classification)', 'The most important side effect of PGE1 (prostaglandin E1) used in duct-dependent CHD is:', '[{"key": "A", "text": "Hypertension"}, {"key": "B", "text": "Apnea"}, {"key": "C", "text": "Hyperglycemia"}, {"key": "D", "text": "Thrombocytosis"}]'::jsonb, 'B', 'Apnea is the most important and common side effect of PGE1 infusion, occurring in ~12% of neonates. Intubation equipment must be readily available. Other effects include fever, hypotension, and flushing. 📚 Nelson''s, 22nd Ed, Ch.457', 1, 'nucleux-content', '{}'),
  ('Pediatrics', 'Congenital Heart Disease (Classification)', 'Knee-chest position in a child with Tetralogy of Fallot relieves cyanotic spells by:', '[{"key": "A", "text": "Decreasing systemic vascular resistance"}, {"key": "B", "text": "Increasing systemic vascular resistance"}, {"key": "C", "text": "Decreasing pulmonary vascular resistance"}, {"key": "D", "text": "Increasing heart rate"}]'::jsonb, 'B', 'Knee-chest position (or squatting) kinks the femoral arteries, increasing SVR. This increases pressure in the left heart, reducing the right-to-left shunt across the VSD, thus improving pulmonary blood flow and oxygenation. 📚 OP Ghai, 10th Ed, Ch.22 (p.407)', 2, 'nucleux-content', '{}'),
  ('Pediatrics', 'Congenital Heart Disease (Classification)', 'Which congenital heart defect is most commonly associated with Down syndrome?', '[{"key": "A", "text": "VSD"}, {"key": "B", "text": "ASD"}, {"key": "C", "text": "Atrioventricular septal defect (AVSD)"}, {"key": "D", "text": "Tetralogy of Fallot"}]'::jsonb, 'C', 'AVSD (endocardial cushion defect) is the most common CHD in Down syndrome (40-50%). It involves defects in the atrial septum, ventricular septum, and AV valves. VSD is the most common CHD overall but AVSD is specific to Down syndrome. 📚 OP Ghai, 10th Ed, Ch.22 (p.400)', 1, 'nucleux-content', '{}'),
  ('Pediatrics', 'Acute Diarrheal Disease & ORS', 'The osmolarity of WHO low-osmolarity ORS is:', '[{"key": "A", "text": "211 mOsm/L"}, {"key": "B", "text": "245 mOsm/L"}, {"key": "C", "text": "311 mOsm/L"}, {"key": "D", "text": "330 mOsm/L"}]'::jsonb, 'B', 'The current WHO-ORS (2002) has reduced osmolarity of 245 mOsm/L, which is associated with decreased stool output, vomiting, and need for IV fluids compared to the older 311 mOsm/L formula. 📚 OP Ghai, 10th Ed, Ch.18 (p.313)', 1, 'nucleux-content', '{}'),
  ('Pediatrics', 'Acute Diarrheal Disease & ORS', 'In Plan C for severe dehydration, the IV fluid of choice is:', '[{"key": "A", "text": "5% dextrose"}, {"key": "B", "text": "Normal saline"}, {"key": "C", "text": "Ringer''s lactate"}, {"key": "D", "text": "Half-normal saline"}]'::jsonb, 'C', 'Ringer''s lactate is the preferred IV fluid for severe dehydration as its composition most closely resembles plasma. Normal saline is an alternative. Dextrose solutions are NOT appropriate for volume resuscitation. 📚 OP Ghai, 10th Ed, Ch.18 (p.317)', 1, 'nucleux-content', '{}'),
  ('Pediatrics', 'Acute Diarrheal Disease & ORS', 'The duration of zinc supplementation recommended in acute diarrhea is:', '[{"key": "A", "text": "3 days"}, {"key": "B", "text": "7 days"}, {"key": "C", "text": "14 days"}, {"key": "D", "text": "21 days"}]'::jsonb, 'C', 'WHO/UNICEF recommend zinc for 14 days to reduce the duration and severity of diarrhea and to prevent future episodes for 2-3 months. This recommendation applies to ALL children with diarrhea, regardless of dehydration status. 📚 OP Ghai, 10th Ed, Ch.18 (p.318)', 1, 'nucleux-content', '{}'),
  ('Pediatrics', 'Acute Diarrheal Disease & ORS', 'Which drug is CONTRAINDICATED in childhood diarrhea?', '[{"key": "A", "text": "Zinc"}, {"key": "B", "text": "ORS"}, {"key": "C", "text": "Loperamide"}, {"key": "D", "text": "Probiotics"}]'::jsonb, 'C', 'Loperamide (anti-motility agent) is contraindicated in children due to risk of paralytic ileus, abdominal distension, and CNS toxicity (especially in infants). It can also mask fluid loss in the gut lumen. 📚 OP Ghai, 10th Ed, Ch.18 (p.320)', 1, 'nucleux-content', '{}'),
  ('Pediatrics', 'Acute Diarrheal Disease & ORS', 'The most common cause of severe dehydrating diarrhea in children under 5 is:', '[{"key": "A", "text": "Escherichia coli"}, {"key": "B", "text": "Rotavirus"}, {"key": "C", "text": "Shigella"}, {"key": "D", "text": "Vibrio cholerae"}]'::jsonb, 'B', 'Rotavirus is the most common cause of severe dehydrating gastroenteritis in children worldwide. It accounts for ~40% of hospitalizations for diarrhea in under-5s. Rotavirus vaccine is now included in India''s NIS. 📚 Nelson''s, 22nd Ed, Ch.366', 1, 'nucleux-content', '{}'),
  ('Pediatrics', 'Pneumonia in Children', 'Fast breathing in a 3-month-old infant is defined as respiratory rate of:', '[{"key": "A", "text": "\u226540/min"}, {"key": "B", "text": "\u226550/min"}, {"key": "C", "text": "\u226560/min"}, {"key": "D", "text": "\u226570/min"}]'::jsonb, 'B', 'WHO cutoffs for tachypnea: <2 months ≥60, 2-12 months ≥50, 1-5 years ≥40. A 3-month-old falls in the 2-12 month category, so fast breathing is ≥50/min. 📚 OP Ghai, 10th Ed, Ch.20 (p.356)', 1, 'nucleux-content', '{}'),
  ('Pediatrics', 'Pneumonia in Children', 'The most common bacterial cause of community-acquired pneumonia in children aged 3 months to 5 years is:', '[{"key": "A", "text": "Staphylococcus aureus"}, {"key": "B", "text": "Haemophilus influenzae"}, {"key": "C", "text": "Streptococcus pneumoniae"}, {"key": "D", "text": "Klebsiella pneumoniae"}]'::jsonb, 'C', 'S. pneumoniae (pneumococcus) is the most common bacterial cause of pneumonia in children beyond the neonatal period. PCV vaccination has reduced its incidence but it remains the leading bacterial pathogen. 📚 Nelson''s, 22nd Ed, Ch.428', 1, 'nucleux-content', '{}'),
  ('Pediatrics', 'Pneumonia in Children', 'A 4-year-old child with cough, fever, and respiratory rate of 52/min but no chest indrawing should be managed with:', '[{"key": "A", "text": "No antibiotic, only supportive care"}, {"key": "B", "text": "Oral amoxicillin at home"}, {"key": "C", "text": "IV ampicillin + gentamicin in hospital"}, {"key": "D", "text": "Oral azithromycin"}]'::jsonb, 'B', 'This child has pneumonia (fast breathing ≥40 for age 1-5 years) without chest indrawing (not severe). WHO/IMNCI Plan: oral amoxicillin at home for 5 days with follow-up in 2 days. 📚 OP Ghai, 10th Ed, Ch.20 (p.359)', 1, 'nucleux-content', '{}'),
  ('Pediatrics', 'Pneumonia in Children', 'Pneumatoceles on chest X-ray are characteristically seen in pneumonia caused by:', '[{"key": "A", "text": "Streptococcus pneumoniae"}, {"key": "B", "text": "Staphylococcus aureus"}, {"key": "C", "text": "Mycoplasma pneumoniae"}, {"key": "D", "text": "Klebsiella pneumoniae"}]'::jsonb, 'B', 'Staphylococcal pneumonia is characterized by rapid progression with pneumatoceles (thin-walled air cysts), empyema, pyopneumothorax, and abscess formation. It is more common in malnourished children and infants. 📚 OP Ghai, 10th Ed, Ch.20 (p.360)', 1, 'nucleux-content', '{}'),
  ('Pediatrics', 'Pneumonia in Children', 'In IMNCI, a 6-week-old infant with pneumonia is classified as:', '[{"key": "A", "text": "Pneumonia \u2014 treat at home"}, {"key": "B", "text": "Severe pneumonia"}, {"key": "C", "text": "Very severe disease"}, {"key": "D", "text": "No pneumonia"}]'::jsonb, 'B', 'In IMNCI, ANY pneumonia in a young infant (<2 months) is classified as severe disease and requires hospitalization with IV antibiotics. There is no "non-severe pneumonia" category for this age group. 📚 OP Ghai, 10th Ed, Ch.20 (p.357)', 2, 'nucleux-content', '{}'),
  ('Pediatrics', 'Febrile Seizures', 'A simple febrile seizure is characterized by all EXCEPT:', '[{"key": "A", "text": "Generalized tonic-clonic seizure"}, {"key": "B", "text": "Duration less than 15 minutes"}, {"key": "C", "text": "Focal onset"}, {"key": "D", "text": "Does not recur within 24 hours"}]'::jsonb, 'C', 'Simple febrile seizures are generalized (not focal), last <15 minutes, and do not recur within 24 hours. Focal onset makes it a complex febrile seizure with higher risk of future epilepsy. 📚 OP Ghai, 10th Ed, Ch.26 (p.521)', 1, 'nucleux-content', '{}'),
  ('Pediatrics', 'Febrile Seizures', 'The strongest risk factor for recurrence of febrile seizures is:', '[{"key": "A", "text": "Complex febrile seizure"}, {"key": "B", "text": "Age <18 months at first episode"}, {"key": "C", "text": "Family history of epilepsy"}, {"key": "D", "text": "Male gender"}]'::jsonb, 'B', 'Age <18 months at the first febrile seizure is the strongest predictor of recurrence. About 50% of children with first FS before 12 months will have recurrence, compared to ~20% if first FS after 3 years. 📚 Nelson''s, 22nd Ed, Ch.611', 2, 'nucleux-content', '{}'),
  ('Pediatrics', 'Febrile Seizures', 'Which of the following is TRUE about antipyretics and febrile seizures?', '[{"key": "A", "text": "Antipyretics prevent febrile seizures"}, {"key": "B", "text": "Antipyretics reduce the recurrence of febrile seizures"}, {"key": "C", "text": "Antipyretics do NOT prevent febrile seizures"}, {"key": "D", "text": "Ibuprofen is more effective than paracetamol in preventing FS"}]'::jsonb, 'C', 'Multiple randomized controlled trials have shown that antipyretics (paracetamol, ibuprofen) do NOT prevent febrile seizures. They are given for comfort but do not alter seizure risk. 📚 OP Ghai, 10th Ed, Ch.26 (p.524)', 1, 'nucleux-content', '{}'),
  ('Pediatrics', 'Febrile Seizures', 'LP should be strongly considered in a child with first febrile seizure if age is:', '[{"key": "A", "text": "<6 months"}, {"key": "B", "text": "<12 months"}, {"key": "C", "text": "<24 months"}, {"key": "D", "text": "<36 months"}]'::jsonb, 'B', 'LP is strongly recommended for infants <12 months with first febrile seizure because clinical signs of meningitis may be subtle or absent at this age. For 12-18 months, LP should be considered. Above 18 months, LP only if meningeal signs are present. 📚 OP Ghai, 10th Ed, Ch.26 (p.524)', 1, 'nucleux-content', '{}'),
  ('Pediatrics', 'Febrile Seizures', 'The risk of developing epilepsy after a simple febrile seizure is approximately:', '[{"key": "A", "text": "0.1%"}, {"key": "B", "text": "1%"}, {"key": "C", "text": "5%"}, {"key": "D", "text": "10%"}]'::jsonb, 'B', 'Simple febrile seizures carry an epilepsy risk of ~1%, which is nearly the same as the general population risk (1%). Complex febrile seizures carry a higher risk (4-6%). This information is crucial for parental reassurance. 📚 Nelson''s, 22nd Ed, Ch.611', 2, 'nucleux-content', '{}'),
  ('Pediatrics', 'Protein Energy Malnutrition (Kwashiorkor & Marasmus)', 'The hallmark clinical feature that differentiates kwashiorkor from marasmus is:', '[{"key": "A", "text": "Muscle wasting"}, {"key": "B", "text": "Bilateral pedal edema"}, {"key": "C", "text": "Growth retardation"}, {"key": "D", "text": "Anemia"}]'::jsonb, 'B', 'Edema is the defining feature of kwashiorkor. It is caused by hypoalbuminemia leading to decreased oncotic pressure. Marasmus shows severe wasting WITHOUT edema. 📚 OP Ghai, 10th Ed, Ch.7 (p.94)', 1, 'nucleux-content', '{}'),
  ('Pediatrics', 'Protein Energy Malnutrition (Kwashiorkor & Marasmus)', 'In WHO management of SAM, which formula is used during the stabilization phase?', '[{"key": "A", "text": "F-100"}, {"key": "B", "text": "F-75"}, {"key": "C", "text": "Standard infant formula"}, {"key": "D", "text": "High-protein diet"}]'::jsonb, 'B', 'F-75 (75 kcal/100 mL) is used in Phase 1 (stabilization) to prevent refeeding syndrome. It has lower calories and protein. F-100 (100 kcal/100 mL) with higher protein is introduced in Phase 2 (rehabilitation) for catch-up growth. 📚 OP Ghai, 10th Ed, Ch.7 (p.103)', 1, 'nucleux-content', '{}'),
  ('Pediatrics', 'Protein Energy Malnutrition (Kwashiorkor & Marasmus)', 'Iron supplementation in SAM is withheld during Phase 1 because:', '[{"key": "A", "text": "Iron is not absorbed in malnutrition"}, {"key": "B", "text": "Iron increases infection risk and oxidative stress"}, {"key": "C", "text": "Iron causes diarrhea"}, {"key": "D", "text": "Iron stores are adequate"}]'::jsonb, 'B', 'Free iron promotes bacterial growth (bacteria need iron for multiplication) and generates free radicals causing oxidative damage. Iron is started only in Phase 2 when the child is improving, appetite returns, and infection is controlled. 📚 OP Ghai, 10th Ed, Ch.7 (p.104)', 2, 'nucleux-content', '{}'),
  ('Pediatrics', 'Protein Energy Malnutrition (Kwashiorkor & Marasmus)', 'ReSoMal differs from standard ORS mainly by having:', '[{"key": "A", "text": "Higher sodium concentration"}, {"key": "B", "text": "Lower sodium concentration"}, {"key": "C", "text": "Higher glucose concentration"}, {"key": "D", "text": "No potassium"}]'::jsonb, 'B', 'ReSoMal has sodium 45 mEq/L (vs 75 mEq/L in standard ORS) because SAM children have excess body sodium (despite low serum sodium) and are at risk of heart failure from sodium overload. It also has added potassium and sugar. 📚 OP Ghai, 10th Ed, Ch.7 (p.102)', 2, 'nucleux-content', '{}'),
  ('Pediatrics', 'Protein Energy Malnutrition (Kwashiorkor & Marasmus)', 'Flag sign of hair is characteristically seen in:', '[{"key": "A", "text": "Marasmus"}, {"key": "B", "text": "Kwashiorkor"}, {"key": "C", "text": "Rickets"}, {"key": "D", "text": "Scurvy"}]'::jsonb, 'B', 'Flag sign refers to alternating bands of light (depigmented) and dark hair, reflecting alternating periods of adequate and inadequate protein intake. It is pathognomonic of kwashiorkor. Hair is also sparse, easily pluckable, and silky. 📚 OP Ghai, 10th Ed, Ch.7 (p.95)', 1, 'nucleux-content', '{}'),
  ('Pharmacology', 'Antifungal Drugs', 'The drug of choice for invasive aspergillosis is:', '[{"key": "A", "text": "Amphotericin B"}, {"key": "B", "text": "Fluconazole"}, {"key": "C", "text": "Voriconazole"}, {"key": "D", "text": "Caspofungin"}]'::jsonb, 'C', 'Voriconazole is the current DOC for invasive aspergillosis (superior to amphotericin B in a landmark RCT). Fluconazole has no activity against Aspergillus. Caspofungin is second-line/salvage therapy. 📚 KD Tripathi, 8th Ed, Ch.58 (p.839)', 1, 'nucleux-content', '{}'),
  ('Pharmacology', 'Antifungal Drugs', 'Which antifungal class is NOT effective against Cryptococcus neoformans?', '[{"key": "A", "text": "Polyenes"}, {"key": "B", "text": "Azoles"}, {"key": "C", "text": "Echinocandins"}, {"key": "D", "text": "Flucytosine"}]'::jsonb, 'C', 'Echinocandins target β(1,3)-D-glucan in the fungal cell wall. Cryptococcus has a polysaccharide capsule but minimal glucan in its cell wall → echinocandins are ineffective. Treat with AmB + flucytosine (induction) followed by fluconazole (maintenance). 📚 KD Tripathi, 8th Ed, Ch.58 (p.842)', 2, 'nucleux-content', '{}'),
  ('Pharmacology', 'Antifungal Drugs', 'Amphotericin B nephrotoxicity manifests as all of the following EXCEPT:', '[{"key": "A", "text": "Renal tubular acidosis"}, {"key": "B", "text": "Hypokalemia"}, {"key": "C", "text": "Hypermagnesemia"}, {"key": "D", "text": "Decreased GFR"}]'::jsonb, 'C', 'Amphotericin B causes renal tubular damage → K+ and Mg2+ wasting → HYPOkalemia and HYPOmagnesemia (not hypermagnesemia). Also causes distal RTA (type 1) and decreased GFR. Nephrotoxicity is the dose-limiting toxicity. Saline preloading reduces risk. 📚 KD Tripathi, 8th Ed, Ch.58 (p.833)', 2, 'nucleux-content', '{}'),
  ('Pharmacology', 'Antifungal Drugs', 'The DOC for dermatophyte infections (tinea, onychomycosis) is:', '[{"key": "A", "text": "Fluconazole"}, {"key": "B", "text": "Amphotericin B"}, {"key": "C", "text": "Terbinafine"}, {"key": "D", "text": "Caspofungin"}]'::jsonb, 'C', 'Terbinafine inhibits squalene epoxidase, is fungicidal against dermatophytes, and concentrates in keratin (nail, skin, hair). It is the DOC for onychomycosis and dermatophytosis. Oral course for nail infections (6 weeks fingernails, 12 weeks toenails). Well-tolerated with minimal CYP interactions. 📚 KD Tripathi, 8th Ed, Ch.58 (p.844)', 1, 'nucleux-content', '{}'),
  ('Pharmacology', 'Antifungal Drugs', 'Ketoconazole is used off-label in Cushing syndrome because it:', '[{"key": "A", "text": "Blocks ACTH receptors"}, {"key": "B", "text": "Inhibits cortisol synthesis (CYP enzymes in adrenal)"}, {"key": "C", "text": "Increases cortisol metabolism"}, {"key": "D", "text": "Blocks glucocorticoid receptors"}]'::jsonb, 'B', 'Ketoconazole inhibits several CYP enzymes involved in steroidogenesis (CYP17, CYP11B1, CYP11A1) in the adrenal gland → reduces cortisol production. This side effect is exploited therapeutically in Cushing syndrome when surgery is not feasible. 📚 KD Tripathi, 8th Ed, Ch.58 (p.836)', 2, 'nucleux-content', '{}'),
  ('Pharmacology', 'Antimalarial Drugs', 'Which antimalarial drug is essential for preventing relapse of P. vivax malaria?', '[{"key": "A", "text": "Chloroquine"}, {"key": "B", "text": "Artesunate"}, {"key": "C", "text": "Primaquine"}, {"key": "D", "text": "Mefloquine"}]'::jsonb, 'C', 'P. vivax and P. ovale form dormant hypnozoites in the liver that cause relapse. Primaquine is the ONLY drug that kills hypnozoites. Radical cure requires chloroquine (blood stages) + primaquine 14 days (hypnozoites). 📚 KD Tripathi, 8th Ed, Ch.57 (p.824)', 1, 'nucleux-content', '{}'),
  ('Pharmacology', 'Antimalarial Drugs', 'The drug of choice for severe complicated falciparum malaria is:', '[{"key": "A", "text": "Chloroquine IV"}, {"key": "B", "text": "Quinine IV"}, {"key": "C", "text": "Artesunate IV"}, {"key": "D", "text": "Mefloquine oral"}]'::jsonb, 'C', 'IV artesunate is superior to IV quinine for severe malaria (SEAQUAMAT trial — 35% mortality reduction). It acts faster, is better tolerated, and causes less hypoglycemia than quinine. 📚 KD Tripathi, 8th Ed, Ch.57 (p.819)', 1, 'nucleux-content', '{}'),
  ('Pharmacology', 'Antimalarial Drugs', 'Before prescribing primaquine, which test is MANDATORY?', '[{"key": "A", "text": "Complete blood count"}, {"key": "B", "text": "Liver function tests"}, {"key": "C", "text": "G6PD enzyme assay"}, {"key": "D", "text": "Renal function tests"}]'::jsonb, 'C', 'Primaquine causes severe oxidative hemolysis in G6PD-deficient individuals. G6PD testing is mandatory before starting primaquine or tafenoquine. In G6PD deficiency, use weekly primaquine (0.75mg/kg) for 8 weeks instead of daily dosing, or consider no anti-relapse therapy if severe deficiency. 📚 KD Tripathi, 8th Ed, Ch.57 (p.825)', 1, 'nucleux-content', '{}'),
  ('Pharmacology', 'Antimalarial Drugs', 'Chloroquine resistance in P. falciparum is due to:', '[{"key": "A", "text": "Mutation in heme polymerase"}, {"key": "B", "text": "Mutation in PfCRT (chloroquine resistance transporter)"}, {"key": "C", "text": "Increased drug metabolism"}, {"key": "D", "text": "Decreased drug absorption"}]'::jsonb, 'B', 'PfCRT mutation causes efflux of chloroquine from the parasite food vacuole, preventing accumulation to toxic levels. This is the primary mechanism of chloroquine resistance in P. falciparum. 📚 KD Tripathi, 8th Ed, Ch.57 (p.817)', 2, 'nucleux-content', '{}'),
  ('Pharmacology', 'Antimalarial Drugs', 'Which antimalarial drug causes cinchonism and hypoglycemia?', '[{"key": "A", "text": "Chloroquine"}, {"key": "B", "text": "Quinine"}, {"key": "C", "text": "Primaquine"}, {"key": "D", "text": "Artesunate"}]'::jsonb, 'B', 'Quinine causes cinchonism (tinnitus, headache, nausea, visual disturbance) and hypoglycemia (stimulates pancreatic β-cell insulin release). Hypoglycemia is particularly dangerous in severe malaria and pregnancy. Artesunate has largely replaced quinine for severe malaria. 📚 KD Tripathi, 8th Ed, Ch.57 (p.820)', 1, 'nucleux-content', '{}'),
  ('Pharmacology', 'Antitubercular Drugs', 'A patient on anti-TB therapy develops peripheral neuropathy. The most likely causative drug and its prevention is:', '[{"key": "A", "text": "Rifampicin \u2014 Vitamin K"}, {"key": "B", "text": "Isoniazid \u2014 Pyridoxine (Vitamin B6)"}, {"key": "C", "text": "Ethambutol \u2014 Vitamin A"}, {"key": "D", "text": "Pyrazinamide \u2014 Folic acid"}]'::jsonb, 'B', 'INH inhibits pyridoxal phosphokinase → ↓active pyridoxine → peripheral neuropathy. Prevention: co-administer pyridoxine (B6) 10mg/day. High-risk groups: malnourished, diabetics, HIV, alcoholics, slow acetylators. 📚 KD Tripathi, 8th Ed, Ch.55 (p.786)', 1, 'nucleux-content', '{}'),
  ('Pharmacology', 'Antitubercular Drugs', 'Ethambutol toxicity manifests as:', '[{"key": "A", "text": "Ototoxicity"}, {"key": "B", "text": "Optic neuritis with red-green color blindness"}, {"key": "C", "text": "Peripheral neuropathy"}, {"key": "D", "text": "Hepatotoxicity"}]'::jsonb, 'B', 'Ethambutol causes dose-dependent retrobulbar optic neuritis. Earliest sign is loss of red-green color discrimination, followed by decreased visual acuity. Usually reversible if detected early and drug stopped. Monthly visual acuity testing is recommended. 📚 KD Tripathi, 8th Ed, Ch.55 (p.793)', 1, 'nucleux-content', '{}'),
  ('Pharmacology', 'Antitubercular Drugs', 'MDR-TB is defined as resistance to:', '[{"key": "A", "text": "Isoniazid only"}, {"key": "B", "text": "Isoniazid + Rifampicin"}, {"key": "C", "text": "All first-line drugs"}, {"key": "D", "text": "Isoniazid + Ethambutol"}]'::jsonb, 'B', 'MDR-TB is defined as Mycobacterium tuberculosis resistant to at least Isoniazid AND Rifampicin (the two most important first-line drugs). XDR-TB is MDR-TB plus resistance to a fluoroquinolone and at least one injectable agent. 📚 KD Tripathi, 8th Ed, Ch.55 (p.798)', 1, 'nucleux-content', '{}'),
  ('Pharmacology', 'Antitubercular Drugs', 'Which anti-TB drug is most likely to cause hyperuricemia?', '[{"key": "A", "text": "Isoniazid"}, {"key": "B", "text": "Rifampicin"}, {"key": "C", "text": "Pyrazinamide"}, {"key": "D", "text": "Ethambutol"}]'::jsonb, 'C', 'Pyrazinamide inhibits renal tubular secretion of uric acid → hyperuricemia → may precipitate gout. This is a common and expected side effect. Asymptomatic hyperuricemia does not require treatment cessation. 📚 KD Tripathi, 8th Ed, Ch.55 (p.791)', 1, 'nucleux-content', '{}'),
  ('Pharmacology', 'Antitubercular Drugs', 'A TB patient on oral contraceptive pills should be counseled about potential OCP failure due to which anti-TB drug?', '[{"key": "A", "text": "Isoniazid"}, {"key": "B", "text": "Rifampicin"}, {"key": "C", "text": "Pyrazinamide"}, {"key": "D", "text": "Ethambutol"}]'::jsonb, 'B', 'Rifampicin is the most potent CYP450 inducer → increases metabolism of OCPs → reduces estrogen/progestin levels → risk of unplanned pregnancy. Patients must use barrier contraception concurrently. 📚 KD Tripathi, 8th Ed, Ch.55 (p.789)', 1, 'nucleux-content', '{}'),
  ('Pharmacology', 'Antibiotics — Fluoroquinolones & Aminoglycosides', 'Fluoroquinolones are contraindicated in children because of:', '[{"key": "A", "text": "Hepatotoxicity"}, {"key": "B", "text": "Nephrotoxicity"}, {"key": "C", "text": "Cartilage/tendon damage"}, {"key": "D", "text": "Bone marrow suppression"}]'::jsonb, 'C', 'Fluoroquinolones cause damage to developing cartilage (shown in juvenile animal studies). They are contraindicated in children <18 and pregnant women. In adults, tendon damage (especially Achilles) is a recognized complication. 📚 KD Tripathi, 8th Ed, Ch.52 (p.752)', 1, 'nucleux-content', '{}'),
  ('Pharmacology', 'Antibiotics — Fluoroquinolones & Aminoglycosides', 'Which aminoglycoside is most resistant to bacterial modifying enzymes?', '[{"key": "A", "text": "Gentamicin"}, {"key": "B", "text": "Streptomycin"}, {"key": "C", "text": "Amikacin"}, {"key": "D", "text": "Neomycin"}]'::jsonb, 'C', 'Amikacin has structural protection against most aminoglycoside-modifying enzymes (acetyltransferases, phosphotransferases, nucleotidyltransferases). It is often effective against gentamicin-resistant organisms and is reserved for resistant Gram-negative infections. 📚 KD Tripathi, 8th Ed, Ch.50 (p.736)', 1, 'nucleux-content', '{}'),
  ('Pharmacology', 'Antibiotics — Fluoroquinolones & Aminoglycosides', 'Aminoglycosides are ineffective against anaerobes because:', '[{"key": "A", "text": "They cannot penetrate anaerobic cell walls"}, {"key": "B", "text": "Anaerobes lack 30S ribosomes"}, {"key": "C", "text": "Oxygen-dependent transport is required for drug uptake"}, {"key": "D", "text": "Anaerobes produce beta-lactamases"}]'::jsonb, 'C', 'Aminoglycoside uptake into bacterial cells requires an oxygen-dependent energy-dependent transport mechanism (electron transport chain). Anaerobes lack this aerobic transport → drug cannot enter → no effect. 📚 KD Tripathi, 8th Ed, Ch.50 (p.732)', 2, 'nucleux-content', '{}'),
  ('Pharmacology', 'Antibiotics — Fluoroquinolones & Aminoglycosides', 'Which fluoroquinolone is NOT useful for urinary tract infections?', '[{"key": "A", "text": "Ciprofloxacin"}, {"key": "B", "text": "Norfloxacin"}, {"key": "C", "text": "Levofloxacin"}, {"key": "D", "text": "Moxifloxacin"}]'::jsonb, 'D', 'Moxifloxacin is primarily metabolized hepatically with minimal renal excretion — it does not achieve adequate urinary concentrations for treating UTIs. Ciprofloxacin, norfloxacin, and levofloxacin are all renally excreted and effective for UTIs. 📚 KD Tripathi, 8th Ed, Ch.52 (p.750)', 2, 'nucleux-content', '{}'),
  ('Pharmacology', 'Antibiotics — Fluoroquinolones & Aminoglycosides', 'A 70-year-old patient on gentamicin develops hearing loss. This ototoxicity is:', '[{"key": "A", "text": "Dose-dependent and reversible"}, {"key": "B", "text": "Idiosyncratic and reversible"}, {"key": "C", "text": "Dose-dependent and irreversible"}, {"key": "D", "text": "Immune-mediated"}]'::jsonb, 'C', 'Aminoglycoside ototoxicity results from destruction of cochlear hair cells (hearing loss) or vestibular hair cells (vertigo). Hair cells do not regenerate → damage is IRREVERSIBLE. Risk increases with dose, duration, concurrent ototoxic drugs (loop diuretics), and renal impairment. 📚 KD Tripathi, 8th Ed, Ch.50 (p.738)', 1, 'nucleux-content', '{}'),
  ('Pharmacology', 'Antibiotics — Penicillins & Cephalosporins', 'The only cephalosporin effective against MRSA is:', '[{"key": "A", "text": "Ceftriaxone"}, {"key": "B", "text": "Cefepime"}, {"key": "C", "text": "Ceftaroline"}, {"key": "D", "text": "Ceftazidime"}]'::jsonb, 'C', 'Ceftaroline is a 5th generation cephalosporin with unique affinity for PBP2a (the altered PBP in MRSA). All other cephalosporins are inactive against MRSA. Ceftaroline also covers common Gram-negative organisms. 📚 KD Tripathi, 8th Ed, Ch.49 (p.726)', 2, 'nucleux-content', '{}'),
  ('Pharmacology', 'Antibiotics — Penicillins & Cephalosporins', 'Which beta-lactam antibiotic can safely be given to a patient with confirmed penicillin allergy who needs Gram-negative coverage?', '[{"key": "A", "text": "Amoxicillin-clavulanate"}, {"key": "B", "text": "Ceftriaxone"}, {"key": "C", "text": "Aztreonam"}, {"key": "D", "text": "Imipenem"}]'::jsonb, 'C', 'Aztreonam (a monobactam) has NO cross-reactivity with penicillins. It covers only Gram-negative bacteria including Pseudomonas. Cephalosporins have ~1-2% cross-reactivity; carbapenems <1%. 📚 KD Tripathi, 8th Ed, Ch.49 (p.729)', 2, 'nucleux-content', '{}'),
  ('Pharmacology', 'Antibiotics — Penicillins & Cephalosporins', 'Ceftriaxone-associated biliary sludge (''pseudolithiasis'') occurs because:', '[{"key": "A", "text": "It inhibits bile acid synthesis"}, {"key": "B", "text": "It is excreted in bile and precipitates with calcium"}, {"key": "C", "text": "It causes gallbladder inflammation"}, {"key": "D", "text": "It induces cholesterol supersaturation"}]'::jsonb, 'B', 'Ceftriaxone has significant biliary excretion (~40%). It can form insoluble calcium-ceftriaxone complexes in the gallbladder → biliary sludge/pseudolithiasis. Usually reversible after stopping the drug. 📚 KD Tripathi, 8th Ed, Ch.49 (p.722)', 2, 'nucleux-content', '{}'),
  ('Pharmacology', 'Antibiotics — Penicillins & Cephalosporins', 'Imipenem is co-administered with cilastatin because:', '[{"key": "A", "text": "Cilastatin enhances absorption"}, {"key": "B", "text": "Cilastatin prevents renal metabolism by DHP-1"}, {"key": "C", "text": "Cilastatin has synergistic antibacterial activity"}, {"key": "D", "text": "Cilastatin prevents seizures"}]'::jsonb, 'B', 'Imipenem is rapidly degraded by renal dehydropeptidase-1 (DHP-1). Cilastatin inhibits DHP-1, preventing imipenem breakdown and also reducing nephrotoxicity from toxic metabolites. Meropenem does NOT need cilastatin (stable to DHP-1). 📚 KD Tripathi, 8th Ed, Ch.49 (p.727)', 1, 'nucleux-content', '{}'),
  ('Pharmacology', 'Antibiotics — Penicillins & Cephalosporins', 'A patient receiving amoxicillin for pharyngitis develops a diffuse maculopapular rash. He is later found to have EBV infection. This rash is:', '[{"key": "A", "text": "Type I hypersensitivity"}, {"key": "B", "text": "Type III hypersensitivity"}, {"key": "C", "text": "Non-allergic ampicillin/amoxicillin rash"}, {"key": "D", "text": "Stevens-Johnson syndrome"}]'::jsonb, 'C', 'EBV (infectious mononucleosis) causes a characteristic non-allergic maculopapular rash when aminopenicillins are given (~70-100% incidence). This is NOT a true penicillin allergy and does not predict future reactions. The mechanism involves polyclonal B-cell activation by EBV. 📚 KD Tripathi, 8th Ed, Ch.49 (p.714)', 1, 'nucleux-content', '{}'),
  ('Pharmacology', 'NSAIDs & Analgesics', 'Aspirin is unique among NSAIDs because it:', '[{"key": "A", "text": "Is the most potent anti-inflammatory"}, {"key": "B", "text": "Selectively inhibits COX-2"}, {"key": "C", "text": "Irreversibly inhibits COX by acetylation"}, {"key": "D", "text": "Does not cause GI side effects"}]'::jsonb, 'C', 'Aspirin covalently acetylates a serine residue in the COX enzyme, causing IRREVERSIBLE inhibition. All other NSAIDs are reversible competitive inhibitors. This is why aspirin''s antiplatelet effect lasts for the entire platelet lifespan (7-10 days). 📚 KD Tripathi, 8th Ed, Ch.14 (p.192)', 1, 'nucleux-content', '{}'),
  ('Pharmacology', 'NSAIDs & Analgesics', 'The most dangerous side effect of morphine that requires monitoring is:', '[{"key": "A", "text": "Constipation"}, {"key": "B", "text": "Nausea"}, {"key": "C", "text": "Respiratory depression"}, {"key": "D", "text": "Miosis"}]'::jsonb, 'C', 'Respiratory depression is the most life-threatening effect of opioids, caused by depression of the brainstem respiratory center (↓sensitivity to CO2). It is dose-dependent and the primary cause of opioid overdose deaths. Constipation, while universal, is not life-threatening. 📚 KD Tripathi, 8th Ed, Ch.15 (p.213)', 1, 'nucleux-content', '{}'),
  ('Pharmacology', 'NSAIDs & Analgesics', 'A child with chickenpox should NOT receive aspirin because of the risk of:', '[{"key": "A", "text": "Stevens-Johnson syndrome"}, {"key": "B", "text": "Reye syndrome"}, {"key": "C", "text": "Aplastic anemia"}, {"key": "D", "text": "Nephrotic syndrome"}]'::jsonb, 'B', 'Reye syndrome is a rare but potentially fatal condition of acute hepatic encephalopathy associated with aspirin use during viral infections (varicella, influenza) in children. Use paracetamol/ibuprofen instead. 📚 KD Tripathi, 8th Ed, Ch.14 (p.205)', 1, 'nucleux-content', '{}'),
  ('Pharmacology', 'NSAIDs & Analgesics', 'COX-2 selective inhibitors increase cardiovascular risk because they:', '[{"key": "A", "text": "Increase platelet aggregation via TXA2"}, {"key": "B", "text": "Inhibit PGI2 without inhibiting TXA2 \u2192 prothrombotic state"}, {"key": "C", "text": "Directly damage myocardium"}, {"key": "D", "text": "Cause fluid retention and hypertension only"}]'::jsonb, 'B', 'COX-2 inhibitors block endothelial PGI2 (antithrombotic, COX-2 derived) but do NOT block platelet TXA2 (prothrombotic, COX-1 derived). This creates a prothrombotic imbalance → increased MI/stroke risk. 📚 KD Tripathi, 8th Ed, Ch.14 (p.203)', 2, 'nucleux-content', '{}'),
  ('Pharmacology', 'NSAIDs & Analgesics', 'The opioid antagonist used in emergency management of opioid overdose is:', '[{"key": "A", "text": "Naltrexone"}, {"key": "B", "text": "Naloxone"}, {"key": "C", "text": "Buprenorphine"}, {"key": "D", "text": "Methadone"}]'::jsonb, 'B', 'Naloxone is a competitive μ-opioid antagonist given IV/IM/IN for acute opioid overdose. It has rapid onset (1-2 min IV) but short duration (30-60 min) — may need repeated doses for long-acting opioids. Naltrexone is oral, long-acting — used for relapse prevention, not emergencies. 📚 KD Tripathi, 8th Ed, Ch.15 (p.218)', 1, 'nucleux-content', '{}'),
  ('Pharmacology', 'Autonomic Nervous System Drugs — Cholinergic & Adrenergic', 'A 30-year-old farmer is brought unconscious with pinpoint pupils, excessive salivation, and muscle fasciculations. The antidote that reactivates acetylcholinesterase is:', '[{"key": "A", "text": "Atropine"}, {"key": "B", "text": "Pralidoxime"}, {"key": "C", "text": "Physostigmine"}, {"key": "D", "text": "Neostigmine"}]'::jsonb, 'B', 'This is organophosphate poisoning. Pralidoxime (2-PAM) reactivates phosphorylated AChE by cleaving the organophosphate-enzyme bond (before aging). Atropine blocks muscarinic effects but does NOT reactivate AChE. Physostigmine and neostigmine are anticholinesterases — would worsen toxicity. 📚 KD Tripathi, 8th Ed, Ch.7 (p.92)', 1, 'nucleux-content', '{}'),
  ('Pharmacology', 'Autonomic Nervous System Drugs — Cholinergic & Adrenergic', 'Which anticholinergic drug is preferred as preanesthetic medication because it does NOT cross the blood-brain barrier?', '[{"key": "A", "text": "Atropine"}, {"key": "B", "text": "Scopolamine"}, {"key": "C", "text": "Glycopyrrolate"}, {"key": "D", "text": "Benztropine"}]'::jsonb, 'C', 'Glycopyrrolate is a quaternary ammonium compound that cannot cross the BBB, avoiding CNS side effects. It is preferred over atropine for preanesthetic use. Atropine and scopolamine cross the BBB. Benztropine crosses the BBB (used for Parkinsonism). 📚 KD Tripathi, 8th Ed, Ch.8 (p.107)', 2, 'nucleux-content', '{}'),
  ('Pharmacology', 'Autonomic Nervous System Drugs — Cholinergic & Adrenergic', 'A patient with pheochromocytoma is being prepared for surgery. Which drug should be started FIRST?', '[{"key": "A", "text": "Propranolol"}, {"key": "B", "text": "Phenoxybenzamine"}, {"key": "C", "text": "Atenolol"}, {"key": "D", "text": "Prazosin"}]'::jsonb, 'B', 'In pheochromocytoma, α-blockade MUST be established before β-blockade (to prevent unopposed α-mediated vasoconstriction causing hypertensive crisis). Phenoxybenzamine (irreversible α-blocker) is the classic choice. β-blocker is added only AFTER adequate α-blockade to control reflex tachycardia. 📚 KD Tripathi, 8th Ed, Ch.10 (p.136)', 2, 'nucleux-content', '{}'),
  ('Pharmacology', 'Autonomic Nervous System Drugs — Cholinergic & Adrenergic', 'Dopamine at low doses (1-3 μg/kg/min) acts primarily on which receptors?', '[{"key": "A", "text": "\u03b11-adrenergic receptors"}, {"key": "B", "text": "\u03b21-adrenergic receptors"}, {"key": "C", "text": "D1 dopaminergic receptors"}, {"key": "D", "text": "D2 dopaminergic receptors"}]'::jsonb, 'C', 'Dopamine''s effects are dose-dependent: Low dose (1-3 μg/kg/min) → D1 receptors → renal and mesenteric vasodilation. Moderate dose (3-10 μg/kg/min) → β1 → ↑cardiac output. High dose (>10 μg/kg/min) → α1 → vasoconstriction. 📚 KD Tripathi, 8th Ed, Ch.9 (p.120)', 1, 'nucleux-content', '{}'),
  ('Pharmacology', 'Autonomic Nervous System Drugs — Cholinergic & Adrenergic', 'Which β-blocker has additional nitric oxide-releasing vasodilatory property?', '[{"key": "A", "text": "Carvedilol"}, {"key": "B", "text": "Labetalol"}, {"key": "C", "text": "Nebivolol"}, {"key": "D", "text": "Esmolol"}]'::jsonb, 'C', 'Nebivolol is a highly β1-selective blocker that also stimulates endothelial NO synthase (eNOS), causing NO-mediated vasodilation. This gives it a unique hemodynamic profile. Carvedilol and labetalol have α-blocking (not NO-mediated) vasodilatory properties. Esmolol is ultra-short-acting β1-selective without vasodilation. 📚 Goodman & Gilman''s, 14th Ed, Ch.12', 2, 'nucleux-content', '{}'),
  ('Pharmacology', 'Antianginal Drugs', 'A patient on sublingual nitroglycerin is prescribed sildenafil for erectile dysfunction. This combination is dangerous because:', '[{"key": "A", "text": "Both drugs cause tachycardia"}, {"key": "B", "text": "Sildenafil inhibits nitrate metabolism"}, {"key": "C", "text": "Both increase cGMP causing severe hypotension"}, {"key": "D", "text": "Sildenafil causes coronary steal"}]'::jsonb, 'C', 'Nitrates release NO → ↑cGMP via guanylyl cyclase. Sildenafil inhibits PDE5 which breaks down cGMP. Together → massive cGMP accumulation → profound vasodilation → potentially fatal hypotension. 📚 KD Tripathi, 8th Ed, Ch.38 (p.536)', 1, 'nucleux-content', '{}'),
  ('Pharmacology', 'Antianginal Drugs', 'The drug of choice for Prinzmetal (variant) angina is:', '[{"key": "A", "text": "Propranolol"}, {"key": "B", "text": "Amlodipine"}, {"key": "C", "text": "Digoxin"}, {"key": "D", "text": "Aspirin"}]'::jsonb, 'B', 'Variant angina is caused by coronary vasospasm. CCBs (amlodipine, nifedipine, diltiazem) are DOC as they cause coronary vasodilation. β-blockers (propranolol) are CONTRAINDICATED — they can worsen vasospasm by allowing unopposed α-adrenergic coronary constriction. 📚 KD Tripathi, 8th Ed, Ch.38 (p.541)', 1, 'nucleux-content', '{}'),
  ('Pharmacology', 'Antianginal Drugs', 'Nitrate tolerance can be prevented by:', '[{"key": "A", "text": "Increasing the dose progressively"}, {"key": "B", "text": "Adding a \u03b2-blocker"}, {"key": "C", "text": "Providing a 10-12 hour nitrate-free interval"}, {"key": "D", "text": "Switching from oral to transdermal route"}]'::jsonb, 'C', 'Continuous nitrate exposure depletes sulfhydryl groups needed for NO release, causing tolerance. A 10-12 hour daily nitrate-free period (usually overnight) restores responsiveness. 📚 KD Tripathi, 8th Ed, Ch.38 (p.535)', 1, 'nucleux-content', '{}'),
  ('Pharmacology', 'Antianginal Drugs', 'Ivabradine reduces heart rate by blocking:', '[{"key": "A", "text": "\u03b21-adrenergic receptors"}, {"key": "B", "text": "L-type calcium channels"}, {"key": "C", "text": "If (funny) current channels"}, {"key": "D", "text": "Sodium channels"}]'::jsonb, 'C', 'Ivabradine selectively inhibits the If (funny) current in the SA node, which is responsible for spontaneous diastolic depolarization (phase 4). This produces pure HR reduction without affecting contractility, BP, or conduction velocity. Visual phosphenes occur due to If channels in the retina. 📚 KD Tripathi, 8th Ed, Ch.38 (p.543)', 1, 'nucleux-content', '{}'),
  ('Pharmacology', 'Antianginal Drugs', 'Which antianginal drug acts as a metabolic modulator without hemodynamic effects?', '[{"key": "A", "text": "Ranolazine"}, {"key": "B", "text": "Trimetazidine"}, {"key": "C", "text": "Nicorandil"}, {"key": "D", "text": "Ivabradine"}]'::jsonb, 'B', 'Trimetazidine shifts myocardial metabolism from fatty acid β-oxidation to glucose oxidation, which is more oxygen-efficient. It has no effect on HR, BP, or coronary blood flow — purely metabolic anti-ischemic action. 📚 KD Tripathi, 8th Ed, Ch.38 (p.543)', 2, 'nucleux-content', '{}'),
  ('Pharmacology', 'Antiarrhythmic Drugs', 'A patient presents with acute SVT. The drug of choice for immediate termination is:', '[{"key": "A", "text": "Amiodarone"}, {"key": "B", "text": "Lidocaine"}, {"key": "C", "text": "Adenosine"}, {"key": "D", "text": "Verapamil"}]'::jsonb, 'C', 'Adenosine (6mg rapid IV push, followed by 12mg if needed) is the DOC for acute SVT (AVNRT/AVRT). Its ultra-short half-life (<10 sec) makes it safe. Verapamil is second-line. Lidocaine is for ventricular arrhythmias only. 📚 KD Tripathi, 8th Ed, Ch.39 (p.558)', 1, 'nucleux-content', '{}'),
  ('Pharmacology', 'Antiarrhythmic Drugs', 'Amiodarone-induced thyroid dysfunction is due to:', '[{"key": "A", "text": "Direct thyroid cell destruction"}, {"key": "B", "text": "High iodine content (37%)"}, {"key": "C", "text": "CYP450 inhibition"}, {"key": "D", "text": "Autoimmune thyroiditis"}]'::jsonb, 'B', 'Amiodarone contains 37% iodine by weight. Each 200mg tablet releases ~6mg iodine (50x daily requirement). Can cause hypothyroidism (Wolff-Chaikoff effect, especially in iodine-sufficient areas) or hyperthyroidism (Jod-Basedow effect, especially in iodine-deficient areas). Monitor TFTs every 6 months. 📚 KD Tripathi, 8th Ed, Ch.39 (p.555)', 2, 'nucleux-content', '{}'),
  ('Pharmacology', 'Antiarrhythmic Drugs', 'Which antiarrhythmic drug is CONTRAINDICATED in patients with structural heart disease/post-MI?', '[{"key": "A", "text": "Amiodarone"}, {"key": "B", "text": "Flecainide"}, {"key": "C", "text": "Metoprolol"}, {"key": "D", "text": "Sotalol"}]'::jsonb, 'B', 'The CAST trial demonstrated increased mortality with Class IC drugs (flecainide, encainide) in post-MI patients. These drugs are only safe in structurally normal hearts. Amiodarone and β-blockers are safe post-MI. 📚 KD Tripathi, 8th Ed, Ch.39 (p.553)', 1, 'nucleux-content', '{}'),
  ('Pharmacology', 'Antiarrhythmic Drugs', 'The drug of choice for Torsades de Pointes is:', '[{"key": "A", "text": "Lidocaine"}, {"key": "B", "text": "Amiodarone"}, {"key": "C", "text": "IV Magnesium sulfate"}, {"key": "D", "text": "Procainamide"}]'::jsonb, 'C', 'MgSO4 is the first-line treatment for Torsades de Pointes regardless of serum Mg levels. It stabilizes cardiac membrane and shortens QT interval. Amiodarone and procainamide would further prolong QT and worsen TdP. 📚 KD Tripathi, 8th Ed, Ch.39 (p.559)', 1, 'nucleux-content', '{}'),
  ('Pharmacology', 'Antiarrhythmic Drugs', 'Procainamide on long-term use can cause:', '[{"key": "A", "text": "Pulmonary fibrosis"}, {"key": "B", "text": "SLE-like syndrome"}, {"key": "C", "text": "Corneal deposits"}, {"key": "D", "text": "Thyroid dysfunction"}]'::jsonb, 'B', 'Procainamide causes drug-induced SLE (anti-histone antibodies positive) in up to 30% of patients on long-term therapy, especially slow acetylators. Pulmonary fibrosis, corneal deposits, and thyroid dysfunction are amiodarone side effects. 📚 KD Tripathi, 8th Ed, Ch.39 (p.549)', 1, 'nucleux-content', '{}'),
  ('Pharmacology', 'Anticoagulants & Antiplatelets', 'A patient on heparin develops thrombocytopenia on day 7 with a new DVT. The most likely diagnosis and next step is:', '[{"key": "A", "text": "HIT Type I \u2014 continue heparin"}, {"key": "B", "text": "HIT Type II \u2014 switch to argatroban"}, {"key": "C", "text": "DIC \u2014 give FFP"}, {"key": "D", "text": "ITP \u2014 give steroids"}]'::jsonb, 'B', 'HIT Type II occurs 5-10 days after heparin, with >50% platelet drop and paradoxical thrombosis (new DVT). It is immune-mediated (anti-PF4-heparin antibodies). Stop ALL heparin immediately and switch to a direct thrombin inhibitor (argatroban or bivalirudin). Do NOT give warfarin yet. 📚 KD Tripathi, 8th Ed, Ch.44 (p.632)', 2, 'nucleux-content', '{}'),
  ('Pharmacology', 'Anticoagulants & Antiplatelets', 'Warfarin-induced skin necrosis occurs due to early depletion of:', '[{"key": "A", "text": "Factor VII"}, {"key": "B", "text": "Factor X"}, {"key": "C", "text": "Protein C"}, {"key": "D", "text": "Antithrombin III"}]'::jsonb, 'C', 'Protein C has the shortest half-life (~8h) among vitamin K-dependent factors. Warfarin depletes it first, creating a transient hypercoagulable state → microvascular thrombosis → skin necrosis. More common in Protein C deficiency. Prevented by bridging with heparin. 📚 KD Tripathi, 8th Ed, Ch.44 (p.638)', 2, 'nucleux-content', '{}'),
  ('Pharmacology', 'Anticoagulants & Antiplatelets', 'Which anticoagulant is safe during pregnancy?', '[{"key": "A", "text": "Warfarin"}, {"key": "B", "text": "Enoxaparin"}, {"key": "C", "text": "Dabigatran"}, {"key": "D", "text": "Rivaroxaban"}]'::jsonb, 'B', 'Heparin (UFH and LMWH like enoxaparin) does NOT cross the placenta — safe in pregnancy. Warfarin crosses the placenta → teratogenic (nasal hypoplasia, stippled epiphyses). DOACs are contraindicated in pregnancy (insufficient safety data + potential teratogenicity). 📚 KD Tripathi, 8th Ed, Ch.44 (p.633)', 1, 'nucleux-content', '{}'),
  ('Pharmacology', 'Anticoagulants & Antiplatelets', 'Clopidogrel resistance is most commonly due to:', '[{"key": "A", "text": "Poor compliance"}, {"key": "B", "text": "CYP2C19 poor metabolizer status"}, {"key": "C", "text": "Drug interaction with aspirin"}, {"key": "D", "text": "High platelet count"}]'::jsonb, 'B', 'Clopidogrel is a prodrug requiring CYP2C19 for conversion to active metabolite. Poor metabolizers (CYP2C19*2/*3 polymorphisms) generate less active drug → reduced antiplatelet effect. This is why ticagrelor (active drug) or prasugrel (less CYP-dependent) may be preferred. Also, PPIs (omeprazole) inhibit CYP2C19, potentially reducing clopidogrel efficacy. 📚 KD Tripathi, 8th Ed, Ch.44 (p.644)', 2, 'nucleux-content', '{}'),
  ('Pharmacology', 'Anticoagulants & Antiplatelets', 'The thrombolytic agent of choice for acute ischemic stroke is:', '[{"key": "A", "text": "Streptokinase"}, {"key": "B", "text": "Alteplase (tPA)"}, {"key": "C", "text": "Urokinase"}, {"key": "D", "text": "Aminocaproic acid"}]'::jsonb, 'B', 'Alteplase (recombinant tPA) is fibrin-specific and the DOC for acute ischemic stroke (within 4.5h window). Streptokinase is NOT used for stroke (non-fibrin-specific, higher bleeding risk, antigenic). Aminocaproic acid is an antifibrinolytic (opposite effect). 📚 KD Tripathi, 8th Ed, Ch.44 (p.648)', 1, 'nucleux-content', '{}'),
  ('Pharmacology', 'Antihypertensive Drugs', 'A 28-year-old pregnant woman at 20 weeks gestation presents with BP 160/100 mmHg. Which antihypertensive is MOST appropriate?', '[{"key": "A", "text": "Enalapril"}, {"key": "B", "text": "Losartan"}, {"key": "C", "text": "Methyldopa"}, {"key": "D", "text": "Atenolol"}]'::jsonb, 'C', 'Methyldopa is the first-line antihypertensive in pregnancy — most extensively studied and proven safe. ACEIs (enalapril) and ARBs (losartan) are absolutely contraindicated in pregnancy (teratogenic — renal agenesis). Atenolol is associated with IUGR. 📚 KD Tripathi, 8th Ed, Ch.40 (p.583)', 1, 'nucleux-content', '{}'),
  ('Pharmacology', 'Antihypertensive Drugs', 'A patient on enalapril develops persistent dry cough. The mechanism is:', '[{"key": "A", "text": "Increased angiotensin II levels"}, {"key": "B", "text": "Accumulation of bradykinin"}, {"key": "C", "text": "Direct bronchial irritation"}, {"key": "D", "text": "Histamine release"}]'::jsonb, 'B', 'ACE also degrades bradykinin. ACE inhibition → bradykinin accumulation → stimulates prostaglandin and substance P production in lungs → cough. This occurs in 10-15% of patients. ARBs do not cause cough (no effect on bradykinin). 📚 KD Tripathi, 8th Ed, Ch.40 (p.566)', 1, 'nucleux-content', '{}'),
  ('Pharmacology', 'Antihypertensive Drugs', 'Which calcium channel blocker should be AVOIDED in combination with β-blockers?', '[{"key": "A", "text": "Amlodipine"}, {"key": "B", "text": "Nifedipine"}, {"key": "C", "text": "Verapamil"}, {"key": "D", "text": "Felodipine"}]'::jsonb, 'C', 'Verapamil has significant cardiac depressant effects (↓HR, ↓conduction, ↓contractility). Combined with β-blockers, it can cause severe bradycardia, heart block, and cardiac failure. DHPs (amlodipine, nifedipine, felodipine) can be safely combined with β-blockers. 📚 KD Tripathi, 8th Ed, Ch.40 (p.576)', 2, 'nucleux-content', '{}'),
  ('Pharmacology', 'Antihypertensive Drugs', 'Sodium nitroprusside toxicity on prolonged use is due to release of:', '[{"key": "A", "text": "Nitric oxide"}, {"key": "B", "text": "Cyanide"}, {"key": "C", "text": "Carbon monoxide"}, {"key": "D", "text": "Free radicals"}]'::jsonb, 'B', 'Sodium nitroprusside releases NO (therapeutic) and cyanide ions. Cyanide is normally detoxified to thiocyanate by rhodanese (using thiosulfate). Prolonged use or high doses → cyanide accumulation → metabolic acidosis, confusion, seizures. Treatment: sodium thiosulfate, hydroxocobalamin. 📚 KD Tripathi, 8th Ed, Ch.40 (p.581)', 2, 'nucleux-content', '{}'),
  ('Pharmacology', 'Antihypertensive Drugs', 'Which ARB has additional uricosuric properties?', '[{"key": "A", "text": "Valsartan"}, {"key": "B", "text": "Telmisartan"}, {"key": "C", "text": "Losartan"}, {"key": "D", "text": "Candesartan"}]'::jsonb, 'C', 'Losartan is the only ARB with significant uricosuric action — it inhibits URAT1 transporter in renal tubules, increasing uric acid excretion. This makes it particularly useful in hypertensive patients with hyperuricemia/gout. 📚 KD Tripathi, 8th Ed, Ch.40 (p.570)', 2, 'nucleux-content', '{}'),
  ('Pharmacology', 'Diuretics', 'A patient with recurrent calcium oxalate kidney stones should be prescribed:', '[{"key": "A", "text": "Furosemide"}, {"key": "B", "text": "Hydrochlorothiazide"}, {"key": "C", "text": "Spironolactone"}, {"key": "D", "text": "Mannitol"}]'::jsonb, 'B', 'Thiazides decrease urinary calcium excretion, reducing the risk of calcium stone recurrence. Loop diuretics (furosemide) INCREASE urinary calcium and would worsen stone risk. 📚 KD Tripathi, 8th Ed, Ch.41 (p.596)', 1, 'nucleux-content', '{}'),
  ('Pharmacology', 'Diuretics', 'Which diuretic causes ototoxicity as a significant side effect?', '[{"key": "A", "text": "Hydrochlorothiazide"}, {"key": "B", "text": "Spironolactone"}, {"key": "C", "text": "Ethacrynic acid"}, {"key": "D", "text": "Acetazolamide"}]'::jsonb, 'C', 'All loop diuretics can cause ototoxicity, but ethacrynic acid has the highest risk. It is the only non-sulfonamide loop diuretic, making it the choice in sulfa-allergic patients despite ototoxicity risk. 📚 KD Tripathi, 8th Ed, Ch.41 (p.593)', 2, 'nucleux-content', '{}'),
  ('Pharmacology', 'Diuretics', 'Acetazolamide is used in acute mountain sickness because it causes:', '[{"key": "A", "text": "Metabolic alkalosis \u2192 hyperventilation"}, {"key": "B", "text": "Metabolic acidosis \u2192 compensatory hyperventilation"}, {"key": "C", "text": "Respiratory alkalosis \u2192 vasodilation"}, {"key": "D", "text": "Direct stimulation of respiratory center"}]'::jsonb, 'B', 'Acetazolamide inhibits carbonic anhydrase → bicarbonaturia → metabolic acidosis. This acidosis stimulates compensatory hyperventilation, improving O2 saturation at high altitude. Also reduces CSF formation. 📚 KD Tripathi, 8th Ed, Ch.41 (p.589)', 2, 'nucleux-content', '{}'),
  ('Pharmacology', 'Diuretics', 'Gynecomastia is a side effect of:', '[{"key": "A", "text": "Furosemide"}, {"key": "B", "text": "Spironolactone"}, {"key": "C", "text": "Amiloride"}, {"key": "D", "text": "Hydrochlorothiazide"}]'::jsonb, 'B', 'Spironolactone is a non-selective mineralocorticoid receptor antagonist that also blocks androgen receptors and inhibits testosterone synthesis → gynecomastia, impotence, menstrual irregularities. Eplerenone is selective and does not cause anti-androgen effects. 📚 KD Tripathi, 8th Ed, Ch.41 (p.599)', 1, 'nucleux-content', '{}'),
  ('Pharmacology', 'Diuretics', 'Which diuretic is effective even in severe renal insufficiency (GFR <10 mL/min) and is synergistic with loop diuretics?', '[{"key": "A", "text": "Hydrochlorothiazide"}, {"key": "B", "text": "Metolazone"}, {"key": "C", "text": "Amiloride"}, {"key": "D", "text": "Acetazolamide"}]'::jsonb, 'B', 'Metolazone is a thiazide-like diuretic that retains efficacy in low GFR states (unlike true thiazides). When combined with loop diuretics, it blocks compensatory Na+ reabsorption in DCT, producing synergistic diuresis — "sequential nephron blockade." Monitor potassium closely. 📚 KD Tripathi, 8th Ed, Ch.41 (p.597)', 2, 'nucleux-content', '{}'),
  ('Pharmacology', 'Heart Failure Drugs', 'Digoxin toxicity is most commonly precipitated by:', '[{"key": "A", "text": "Hyperkalemia"}, {"key": "B", "text": "Hypokalemia"}, {"key": "C", "text": "Hypernatremia"}, {"key": "D", "text": "Hypocalcemia"}]'::jsonb, 'B', 'K+ and digoxin compete for the same binding site on Na+/K+ ATPase. Hypokalemia → more digoxin binds → toxicity even at ''therapeutic'' levels. Common scenario: patient on digoxin + furosemide (causes K+ loss). 📚 KD Tripathi, 8th Ed, Ch.37 (p.518)', 1, 'nucleux-content', '{}'),
  ('Pharmacology', 'Heart Failure Drugs', 'Which of the following drugs reduces mortality in heart failure with reduced ejection fraction?', '[{"key": "A", "text": "Digoxin"}, {"key": "B", "text": "Furosemide"}, {"key": "C", "text": "Carvedilol"}, {"key": "D", "text": "Dobutamine"}]'::jsonb, 'C', 'Among listed drugs, only carvedilol reduces mortality in HFrEF. Digoxin reduces hospitalization but NOT mortality. Furosemide provides symptom relief without mortality benefit. Dobutamine is for acute HF and may increase mortality long-term. 📚 KD Tripathi, 8th Ed, Ch.37 (p.521)', 1, 'nucleux-content', '{}'),
  ('Pharmacology', 'Heart Failure Drugs', 'Sacubitril-valsartan should NOT be combined with:', '[{"key": "A", "text": "Metoprolol"}, {"key": "B", "text": "Enalapril"}, {"key": "C", "text": "Spironolactone"}, {"key": "D", "text": "Furosemide"}]'::jsonb, 'B', 'ARNI (sacubitril-valsartan) must NOT be given with ACEIs due to high risk of angioedema. Sacubitril inhibits neprilysin which also degrades bradykinin; combined with ACEI (which also ↑bradykinin), excessive bradykinin causes angioedema. A 36-hour washout from ACEI is mandatory before starting ARNI. 📚 KD Tripathi, 8th Ed, Ch.37 (p.523)', 2, 'nucleux-content', '{}'),
  ('Pharmacology', 'Heart Failure Drugs', 'The specific antidote for severe digoxin toxicity is:', '[{"key": "A", "text": "Atropine"}, {"key": "B", "text": "Phenytoin"}, {"key": "C", "text": "Digoxin-specific antibody fragments (Digibind)"}, {"key": "D", "text": "Calcium gluconate"}]'::jsonb, 'C', 'Digibind/DigiFab binds free digoxin, rendering it inactive. Indicated for life-threatening arrhythmias, K+ >5 mEq/L, or digoxin level >10 ng/mL. Atropine is used for bradycardia but is not specific. Calcium is CONTRAINDICATED (potentiates digoxin toxicity — "stone heart"). 📚 KD Tripathi, 8th Ed, Ch.37 (p.519)', 1, 'nucleux-content', '{}'),
  ('Pharmacology', 'Heart Failure Drugs', 'An inotropic agent that works by calcium sensitization without increasing intracellular calcium is:', '[{"key": "A", "text": "Dobutamine"}, {"key": "B", "text": "Milrinone"}, {"key": "C", "text": "Levosimendan"}, {"key": "D", "text": "Digoxin"}]'::jsonb, 'C', 'Levosimendan binds to troponin C and sensitizes the contractile apparatus to existing Ca2+, increasing contractility WITHOUT raising intracellular Ca2+ (unlike dobutamine, milrinone, digoxin). This avoids increased oxygen demand and arrhythmia risk. 📚 KD Tripathi, 8th Ed, Ch.37 (p.527)', 2, 'nucleux-content', '{}'),
  ('Pharmacology', 'Corticosteroids', 'Which corticosteroid has the HIGHEST anti-inflammatory potency with NO mineralocorticoid activity?', '[{"key": "A", "text": "Hydrocortisone"}, {"key": "B", "text": "Prednisolone"}, {"key": "C", "text": "Dexamethasone"}, {"key": "D", "text": "Fludrocortisone"}]'::jsonb, 'C', 'Dexamethasone has 30x the anti-inflammatory potency of hydrocortisone with virtually zero mineralocorticoid activity. This makes it ideal when salt/water retention must be avoided (cerebral edema, diagnostic testing). 📚 KD Tripathi, 8th Ed, Ch.32 (p.474)', 1, 'nucleux-content', '{}'),
  ('Pharmacology', 'Corticosteroids', 'Antenatal corticosteroids for fetal lung maturity are given at:', '[{"key": "A", "text": "16-20 weeks"}, {"key": "B", "text": "24-34 weeks"}, {"key": "C", "text": "35-37 weeks"}, {"key": "D", "text": "After 37 weeks"}]'::jsonb, 'B', 'Betamethasone/dexamethasone given to mothers at 24-34 weeks with anticipated preterm delivery accelerates fetal surfactant production, reducing respiratory distress syndrome (RDS) by ~50%. 📚 KD Tripathi, 8th Ed, Ch.32 (p.481)', 1, 'nucleux-content', '{}'),
  ('Pharmacology', 'Corticosteroids', 'The most common cause of drug-induced osteoporosis is:', '[{"key": "A", "text": "Methotrexate"}, {"key": "B", "text": "Heparin"}, {"key": "C", "text": "Corticosteroids"}, {"key": "D", "text": "Phenytoin"}]'::jsonb, 'C', 'Chronic corticosteroid use is the most common cause of drug-induced and secondary osteoporosis. Mechanisms: ↓osteoblast function, ↑osteoclast activity, ↓Ca2+ absorption, ↓sex steroids. Bisphosphonates recommended for prevention if steroids used ≥3 months. 📚 KD Tripathi, 8th Ed, Ch.32 (p.486)', 1, 'nucleux-content', '{}'),
  ('Pharmacology', 'Corticosteroids', 'A patient on long-term prednisolone develops oral white patches. The most likely cause is:', '[{"key": "A", "text": "Leukoplakia"}, {"key": "B", "text": "Oral candidiasis"}, {"key": "C", "text": "Lichen planus"}, {"key": "D", "text": "Aphthous ulcers"}]'::jsonb, 'B', 'Immunosuppression from corticosteroids predisposes to opportunistic infections including oral candidiasis (thrush). Especially common with inhaled steroids — prevented by rinsing mouth after inhalation. Systemic steroids also increase risk. 📚 KD Tripathi, 8th Ed, Ch.32 (p.488)', 1, 'nucleux-content', '{}'),
  ('Pharmacology', 'Corticosteroids', 'Abrupt withdrawal of chronic corticosteroid therapy can cause:', '[{"key": "A", "text": "Cushing syndrome"}, {"key": "B", "text": "Acute adrenal insufficiency"}, {"key": "C", "text": "Diabetes mellitus"}, {"key": "D", "text": "Osteoporosis"}]'::jsonb, 'B', 'Chronic exogenous corticosteroids suppress the HPA axis → adrenal cortex atrophies. Abrupt withdrawal → inability to mount cortisol response → acute adrenal crisis (hypotension, shock, hypoglycemia, hyperkalemia). Always taper steroids gradually after >2 weeks of supraphysiologic use. 📚 KD Tripathi, 8th Ed, Ch.32 (p.489)', 1, 'nucleux-content', '{}'),
  ('Pharmacology', 'Pharmacodynamics — Drug-Receptor Interactions', 'A drug produces a parallel rightward shift of the dose-response curve of an agonist without reducing the maximum response. This drug is a:', '[{"key": "A", "text": "Non-competitive antagonist"}, {"key": "B", "text": "Competitive antagonist"}, {"key": "C", "text": "Partial agonist"}, {"key": "D", "text": "Inverse agonist"}]'::jsonb, 'B', 'Competitive antagonists compete with the agonist at the same binding site. Their effect can be overcome by increasing agonist concentration, producing a parallel rightward shift with preserved Emax. Non-competitive antagonists reduce Emax. 📚 KD Tripathi, 8th Ed, Ch.4 (p.46)', 1, 'nucleux-content', '{}'),
  ('Pharmacology', 'Pharmacodynamics — Drug-Receptor Interactions', 'Which receptor type mediates the action of insulin?', '[{"key": "A", "text": "Ligand-gated ion channel"}, {"key": "B", "text": "G-protein coupled receptor"}, {"key": "C", "text": "Enzyme-linked (tyrosine kinase) receptor"}, {"key": "D", "text": "Nuclear receptor"}]'::jsonb, 'C', 'Insulin receptor is a receptor tyrosine kinase. Insulin binding activates intrinsic tyrosine kinase activity → autophosphorylation → IRS-1 → PI3K/Akt pathway → GLUT4 translocation. Response occurs in minutes. 📚 KD Tripathi, 8th Ed, Ch.4 (p.41)', 1, 'nucleux-content', '{}'),
  ('Pharmacology', 'Pharmacodynamics — Drug-Receptor Interactions', 'Aripiprazole is classified as a partial agonist at D2 receptors. In the presence of high dopaminergic activity, it will act as:', '[{"key": "A", "text": "Full agonist"}, {"key": "B", "text": "Antagonist"}, {"key": "C", "text": "Inverse agonist"}, {"key": "D", "text": "Allosteric modulator"}]'::jsonb, 'B', 'A partial agonist has submaximal intrinsic activity. In the presence of a full agonist (or high endogenous ligand), it occupies receptors and produces a LOWER response than the full agonist, effectively acting as a functional antagonist. This is why aripiprazole is useful in schizophrenia (blocks excess dopamine) and depression (augments low dopamine). 📚 Goodman & Gilman''s, 14th Ed, Ch.3', 2, 'nucleux-content', '{}'),
  ('Pharmacology', 'Pharmacodynamics — Drug-Receptor Interactions', 'A patient on chronic propranolol therapy abruptly stops the medication and develops severe tachycardia and hypertension. This is due to:', '[{"key": "A", "text": "Receptor downregulation"}, {"key": "B", "text": "Receptor upregulation"}, {"key": "C", "text": "Enzyme induction"}, {"key": "D", "text": "Tachyphylaxis"}]'::jsonb, 'B', 'Chronic β-blocker use leads to upregulation (increased number) of β-adrenergic receptors. Abrupt discontinuation unmasks these extra receptors, causing supersensitivity to catecholamines → rebound tachycardia, hypertension, angina. Always taper β-blockers gradually. 📚 KD Tripathi, 8th Ed, Ch.5 (p.57)', 2, 'nucleux-content', '{}'),
  ('Pharmacology', 'Pharmacodynamics — Drug-Receptor Interactions', 'Which of the following G-protein subtypes is correctly paired with its second messenger system?', '[{"key": "A", "text": "Gs \u2014 Increased IP3/DAG"}, {"key": "B", "text": "Gi \u2014 Increased cAMP"}, {"key": "C", "text": "Gq \u2014 Increased IP3/DAG"}, {"key": "D", "text": "Gs \u2014 Decreased cAMP"}]'::jsonb, 'C', 'Gq activates phospholipase C → PIP2 hydrolysis → IP3 (releases Ca2+ from ER) + DAG (activates PKC). Gs activates adenylyl cyclase → ↑cAMP. Gi inhibits adenylyl cyclase → ↓cAMP. 📚 KD Tripathi, 8th Ed, Ch.4 (p.39)', 1, 'nucleux-content', '{}'),
  ('Pharmacology', 'General Pharmacology — Pharmacokinetics', 'A drug has a volume of distribution of 500L. This most likely indicates that the drug is:', '[{"key": "A", "text": "Highly plasma protein bound and confined to vascular compartment"}, {"key": "B", "text": "Extensively distributed and bound to tissue proteins"}, {"key": "C", "text": "Primarily excreted unchanged by the kidneys"}, {"key": "D", "text": "Metabolized entirely by first-pass effect"}]'::jsonb, 'B', 'A Vd of 500L (far exceeding total body water of ~42L) indicates the drug is extensively sequestered in tissues. Examples include chloroquine (Vd ~13,000L) and digoxin (Vd ~500L). High plasma protein binding would give LOW Vd. 📚 KD Tripathi, 8th Ed, Ch.2 (p.16)', 2, 'nucleux-content', '{}'),
  ('Pharmacology', 'General Pharmacology — Pharmacokinetics', 'Which of the following drugs follows zero-order elimination kinetics at therapeutic doses?', '[{"key": "A", "text": "Amoxicillin"}, {"key": "B", "text": "Phenytoin"}, {"key": "C", "text": "Metformin"}, {"key": "D", "text": "Atenolol"}]'::jsonb, 'B', 'Phenytoin shows zero-order (saturation) kinetics at therapeutic doses because its metabolizing enzymes become saturated. Small dose increases can cause disproportionate rises in plasma levels → toxicity. Other zero-order drugs: ethanol, aspirin (high dose). 📚 KD Tripathi, 8th Ed, Ch.3 (p.30)', 1, 'nucleux-content', '{}'),
  ('Pharmacology', 'General Pharmacology — Pharmacokinetics', 'A patient on warfarin is started on rifampicin for tuberculosis. What is the expected effect on INR?', '[{"key": "A", "text": "INR increases due to CYP450 inhibition"}, {"key": "B", "text": "INR decreases due to CYP450 induction"}, {"key": "C", "text": "No change in INR"}, {"key": "D", "text": "INR increases due to protein binding displacement"}]'::jsonb, 'B', 'Rifampicin is the most potent CYP450 inducer, increasing metabolism of warfarin via CYP2C9 induction. This leads to decreased warfarin levels → decreased INR → risk of thrombosis. Warfarin dose needs to be increased. 📚 KD Tripathi, 8th Ed, Ch.3 (p.25)', 2, 'nucleux-content', '{}'),
  ('Pharmacology', 'General Pharmacology — Pharmacokinetics', 'Steady-state plasma concentration is achieved after approximately:', '[{"key": "A", "text": "1-2 half-lives"}, {"key": "B", "text": "3-4 half-lives"}, {"key": "C", "text": "4-5 half-lives"}, {"key": "D", "text": "7-8 half-lives"}]'::jsonb, 'C', 'At steady state, rate of drug input equals rate of elimination. This is achieved at ~4-5 half-lives (>93.75% of steady state at 4 half-lives, >96.9% at 5 half-lives). This is independent of dose or dosing interval. 📚 Goodman & Gilman''s, 14th Ed, Ch.2', 1, 'nucleux-content', '{}'),
  ('Pharmacology', 'General Pharmacology — Pharmacokinetics', 'Which route of drug administration bypasses first-pass metabolism?', '[{"key": "A", "text": "Oral"}, {"key": "B", "text": "Sublingual"}, {"key": "C", "text": "Rectal (upper 1/3)"}, {"key": "D", "text": "Portal vein injection"}]'::jsonb, 'B', 'Sublingual absorption drains into the superior vena cava, bypassing the portal circulation and liver. Oral and upper rectal routes undergo first-pass metabolism. Lower 1/3 of rectum drains to inferior rectal vein → IVC (bypasses first-pass). Nitroglycerin is given sublingually for this reason. 📚 KD Tripathi, 8th Ed, Ch.1 (p.6-7)', 1, 'nucleux-content', '{}'),
  ('Physiology', 'Blood Pressure Regulation (Baroreceptors, RAAS)', 'A patient with acute blood loss shows tachycardia, vasoconstriction, and increased renin secretion. The initial tachycardia is primarily mediated by:', '[{"key": "A", "text": "RAAS activation"}, {"key": "B", "text": "ADH release"}, {"key": "C", "text": "Baroreceptor reflex"}, {"key": "D", "text": "Chemoreceptor activation"}]'::jsonb, 'C', 'Acute blood loss → ↓BP → ↓baroreceptor firing → ↓vagal tone + ↑sympathetic tone → tachycardia (within seconds). RAAS takes minutes-hours. The baroreceptor reflex is the fastest compensatory mechanism. 📚 Guyton & Hall, 14th Ed, Ch.18 (p.220)', 1, 'nucleux-content', '{}'),
  ('Physiology', 'Blood Pressure Regulation (Baroreceptors, RAAS)', 'Which of the following is NOT an action of angiotensin II?', '[{"key": "A", "text": "Vasoconstriction"}, {"key": "B", "text": "Aldosterone secretion from zona glomerulosa"}, {"key": "C", "text": "Inhibition of ADH release"}, {"key": "D", "text": "Stimulation of thirst"}]'::jsonb, 'C', 'Angiotensin II STIMULATES ADH release (not inhibits). Its actions include vasoconstriction, aldosterone secretion, ADH release, thirst, Na+ reabsorption in PCT, and cardiac remodeling — all aimed at increasing blood pressure and volume. 📚 Guyton & Hall, 14th Ed, Ch.19 (p.234)', 1, 'nucleux-content', '{}'),
  ('Physiology', 'Blood Pressure Regulation (Baroreceptors, RAAS)', 'The cough associated with ACE inhibitors is due to accumulation of:', '[{"key": "A", "text": "Angiotensin II"}, {"key": "B", "text": "Aldosterone"}, {"key": "C", "text": "Bradykinin"}, {"key": "D", "text": "Substance P"}]'::jsonb, 'C', 'ACE (kininase II) normally degrades bradykinin. ACE inhibitors prevent this degradation → bradykinin accumulates in airways → stimulates C fibers → cough. ARBs don''t cause this because they block AT1 receptors without affecting bradykinin metabolism. 📚 Ganong''s, 26th Ed, Ch.32', 1, 'nucleux-content', '{}'),
  ('Physiology', 'Blood Pressure Regulation (Baroreceptors, RAAS)', 'Cushing triad (hypertension, bradycardia, irregular breathing) is a sign of:', '[{"key": "A", "text": "Cardiac tamponade"}, {"key": "B", "text": "Raised intracranial pressure"}, {"key": "C", "text": "Pulmonary embolism"}, {"key": "D", "text": "Aortic dissection"}]'::jsonb, 'B', 'Cushing triad results from brainstem ischemia due to raised ICP. The CNS ischemic response causes massive sympathetic discharge → hypertension. Baroreceptor-mediated reflex bradycardia follows. Irregular breathing indicates brainstem compression. This is a neurosurgical emergency. 📚 Guyton & Hall, 14th Ed, Ch.18', 1, 'nucleux-content', '{}'),
  ('Physiology', 'Blood Pressure Regulation (Baroreceptors, RAAS)', 'According to Guyton''s concept, the ultimate long-term regulator of blood pressure is:', '[{"key": "A", "text": "Baroreceptor reflex"}, {"key": "B", "text": "RAAS"}, {"key": "C", "text": "Renal pressure natriuresis"}, {"key": "D", "text": "Autonomic nervous system"}]'::jsonb, 'C', 'Guyton demonstrated that the kidney''s ability to excrete sodium and water in response to elevated pressure (pressure natriuresis) is the only mechanism with infinite gain for long-term BP control. All forms of chronic hypertension involve a rightward shift in the pressure-natriuresis curve. 📚 Guyton & Hall, 14th Ed, Ch.19 (p.239)', 2, 'nucleux-content', '{}'),
  ('Physiology', 'Cardiac Cycle & Heart Sounds', 'During which phase of the cardiac cycle are ALL cardiac valves closed?', '[{"key": "A", "text": "Rapid ejection and rapid filling"}, {"key": "B", "text": "Isovolumetric contraction and isovolumetric relaxation"}, {"key": "C", "text": "Atrial systole and reduced ejection"}, {"key": "D", "text": "Rapid filling and slow filling"}]'::jsonb, 'B', 'During isovolumetric contraction (after AV valve closure, before semilunar valve opening) and isovolumetric relaxation (after semilunar closure, before AV valve opening), all four valves are closed. Volume remains constant while pressure changes. 📚 Guyton & Hall, 14th Ed, Ch.9 (p.111)', 1, 'nucleux-content', '{}'),
  ('Physiology', 'Cardiac Cycle & Heart Sounds', 'A 65-year-old hypertensive patient has a fourth heart sound (S4). This indicates:', '[{"key": "A", "text": "Volume overload with dilated ventricle"}, {"key": "B", "text": "Atrial contraction against a stiff, non-compliant ventricle"}, {"key": "C", "text": "Rapid ventricular filling in early diastole"}, {"key": "D", "text": "Aortic valve closure"}]'::jsonb, 'B', 'S4 is a late diastolic (presystolic) sound caused by forceful atrial contraction against a stiff, hypertrophied ventricle (decreased compliance). Always pathologic. Common in HTN with LVH, HOCM, and aortic stenosis. S3 (not S4) indicates volume overload in early diastole. 📚 Ganong''s, 26th Ed, Ch.30', 1, 'nucleux-content', '{}'),
  ('Physiology', 'Cardiac Cycle & Heart Sounds', 'Fixed splitting of S2 is characteristic of:', '[{"key": "A", "text": "Left bundle branch block"}, {"key": "B", "text": "Atrial septal defect"}, {"key": "C", "text": "Pulmonary hypertension"}, {"key": "D", "text": "Aortic stenosis"}]'::jsonb, 'B', 'In ASD, left-to-right shunt equalizes filling of both ventricles regardless of respiration. Both RV and LV empty at similar rates → A2-P2 interval remains constant (fixed) during inspiration and expiration. LBBB and aortic stenosis cause paradoxical splitting. 📚 Ganong''s, 26th Ed, Ch.30', 1, 'nucleux-content', '{}'),
  ('Physiology', 'Cardiac Cycle & Heart Sounds', 'In the Wiggers diagram, the ''v'' wave in the left atrial pressure tracing corresponds to:', '[{"key": "A", "text": "Atrial contraction"}, {"key": "B", "text": "Venous filling of atrium during ventricular systole"}, {"key": "C", "text": "Rapid ventricular filling"}, {"key": "D", "text": "Isovolumetric contraction"}]'::jsonb, 'B', 'The ''v'' wave represents blood filling the atria from pulmonary veins while the mitral valve is closed during ventricular systole. The ''a'' wave = atrial contraction, ''c'' wave = AV valve bulging. Giant ''v'' waves are seen in mitral/tricuspid regurgitation. 📚 Guyton & Hall, 14th Ed, Ch.9 (p.110)', 2, 'nucleux-content', '{}'),
  ('Physiology', 'Cardiac Cycle & Heart Sounds', 'What percentage of ventricular filling occurs during the rapid filling phase?', '[{"key": "A", "text": "10-15%"}, {"key": "B", "text": "30-40%"}, {"key": "C", "text": "70-80%"}, {"key": "D", "text": "90-100%"}]'::jsonb, 'C', 'Rapid filling phase accounts for approximately 70-80% of ventricular filling passively due to the pressure gradient between atria and ventricles. Atrial systole (atrial kick) contributes only 20-30%. This is why cardiac output is maintained in atrial fibrillation at rest (loss of atrial kick). 📚 Guyton & Hall, 14th Ed, Ch.9 (p.113)', 2, 'nucleux-content', '{}'),
  ('Physiology', 'ECG Basics & Interpretation', 'A patient''s ECG shows absent P waves, irregularly irregular rhythm, and normal QRS complexes. The diagnosis is:', '[{"key": "A", "text": "Atrial flutter"}, {"key": "B", "text": "Atrial fibrillation"}, {"key": "C", "text": "Complete heart block"}, {"key": "D", "text": "Ventricular tachycardia"}]'::jsonb, 'B', 'Atrial fibrillation is characterized by absent P waves (replaced by fibrillatory baseline), irregularly irregular RR intervals, and normal narrow QRS complexes (unless pre-existing BBB). Atrial flutter shows sawtooth flutter waves. Complete heart block shows regular but dissociated P waves and QRS. 📚 Guyton & Hall, 14th Ed, Ch.13', 1, 'nucleux-content', '{}'),
  ('Physiology', 'ECG Basics & Interpretation', 'An ECG shows peaked T waves, widened QRS, and absent P waves. The most likely electrolyte abnormality is:', '[{"key": "A", "text": "Hypocalcemia"}, {"key": "B", "text": "Hyperkalemia"}, {"key": "C", "text": "Hypokalemia"}, {"key": "D", "text": "Hypomagnesemia"}]'::jsonb, 'B', 'Progressive hyperkalemia produces: peaked T waves (K+ 6-7) → widened QRS and flattened P waves (K+ 7-8) → loss of P waves → sine wave pattern → VF/asystole. This is a medical emergency requiring emergent treatment with calcium gluconate, insulin/glucose, and dialysis. 📚 Guyton & Hall, 14th Ed, Ch.13 (p.157)', 1, 'nucleux-content', '{}'),
  ('Physiology', 'ECG Basics & Interpretation', 'rsR'' pattern in V1 with wide QRS (>0.12s) and wide S wave in Lead I indicates:', '[{"key": "A", "text": "Left bundle branch block"}, {"key": "B", "text": "Right bundle branch block"}, {"key": "C", "text": "Left anterior fascicular block"}, {"key": "D", "text": "WPW syndrome"}]'::jsonb, 'B', 'RBBB shows rsR'' (M-shaped) pattern in V1-V2 and wide slurred S wave in lateral leads (I, V6) with QRS >0.12s. Remember "MaRRoW" — M in V1 (right), W in V6 (left). LBBB shows the opposite: W in V1, M in V6 ("WiLLiaM"). 📚 Guyton & Hall, 14th Ed, Ch.12 (p.148)', 1, 'nucleux-content', '{}'),
  ('Physiology', 'ECG Basics & Interpretation', 'Which ECG finding is associated with hypocalcemia?', '[{"key": "A", "text": "Shortened QT interval"}, {"key": "B", "text": "Prolonged QT interval"}, {"key": "C", "text": "Peaked T waves"}, {"key": "D", "text": "U waves"}]'::jsonb, 'B', 'Hypocalcemia prolongs the QT interval by lengthening the ST segment (Phase 2 of cardiac AP depends on Ca2+). Hypercalcemia shortens QT. Peaked T waves = hyperkalemia. U waves = hypokalemia. 📚 Guyton & Hall, 14th Ed, Ch.13', 1, 'nucleux-content', '{}'),
  ('Physiology', 'ECG Basics & Interpretation', 'A young patient with recurrent palpitations has ECG showing short PR interval and delta wave. Which drug is CONTRAINDICATED if this patient develops atrial fibrillation?', '[{"key": "A", "text": "Procainamide"}, {"key": "B", "text": "Amiodarone"}, {"key": "C", "text": "Verapamil"}, {"key": "D", "text": "Flecainide"}]'::jsonb, 'C', 'WPW with atrial fibrillation: AV nodal blockers (verapamil, diltiazem, digoxin, adenosine) are contraindicated because blocking the AV node forces conduction down the accessory pathway, which has no decremental conduction → rapid ventricular rate → VF. Procainamide or amiodarone are preferred. 📚 Ganong''s, 26th Ed, Ch.29', 2, 'nucleux-content', '{}'),
  ('Physiology', 'Endocrine — Hypothalamic-Pituitary Axis', 'After pituitary stalk transection, which hormone level INCREASES?', '[{"key": "A", "text": "GH"}, {"key": "B", "text": "ACTH"}, {"key": "C", "text": "Prolactin"}, {"key": "D", "text": "TSH"}]'::jsonb, 'C', 'Prolactin is under tonic inhibition by dopamine from the hypothalamus. Stalk transection interrupts dopamine delivery → loss of inhibition → prolactin increases. All other anterior pituitary hormones decrease because they depend on stimulatory hypothalamic releasing hormones. 📚 Guyton & Hall, 14th Ed, Ch.76 (p.968)', 1, 'nucleux-content', '{}'),
  ('Physiology', 'Endocrine — Hypothalamic-Pituitary Axis', 'ACTH is derived from the precursor molecule:', '[{"key": "A", "text": "Preproenkephalin"}, {"key": "B", "text": "Proopiomelanocortin (POMC)"}, {"key": "C", "text": "Preproglucagon"}, {"key": "D", "text": "Progonadotropin"}]'::jsonb, 'B', 'POMC is a large precursor protein cleaved to produce ACTH, β-lipotropin, MSH (melanocyte-stimulating hormone), and β-endorphin. This explains hyperpigmentation in ACTH excess (e.g., Addison''s disease) — excess POMC cleavage produces excess MSH, which stimulates melanocytes. 📚 Ganong''s, 26th Ed, Ch.18', 1, 'nucleux-content', '{}'),
  ('Physiology', 'Endocrine — Hypothalamic-Pituitary Axis', 'A woman fails to lactate after a complicated delivery with massive hemorrhage. The most likely diagnosis is:', '[{"key": "A", "text": "Prolactinoma"}, {"key": "B", "text": "Sheehan syndrome"}, {"key": "C", "text": "Empty sella syndrome"}, {"key": "D", "text": "Craniopharyngioma"}]'::jsonb, 'B', 'Sheehan syndrome is postpartum pituitary necrosis due to hemorrhagic shock. The enlarged pituitary of pregnancy is vulnerable to ischemia. Failure to lactate (prolactin deficiency) is the earliest sign, followed by progressive loss of other pituitary hormones. 📚 Guyton & Hall, 14th Ed, Ch.77', 1, 'nucleux-content', '{}'),
  ('Physiology', 'Endocrine — Hypothalamic-Pituitary Axis', 'The positive feedback of estrogen leading to the LH surge occurs during which phase of the menstrual cycle?', '[{"key": "A", "text": "Early follicular phase"}, {"key": "B", "text": "Late follicular phase"}, {"key": "C", "text": "Luteal phase"}, {"key": "D", "text": "Menstrual phase"}]'::jsonb, 'B', 'Rising estrogen from the dominant follicle reaches a critical threshold in the late follicular phase → switches from negative to POSITIVE feedback on GnRH/LH release → LH surge → ovulation. This is the only significant positive feedback mechanism in the HPG axis. 📚 Ganong''s, 26th Ed, Ch.17', 2, 'nucleux-content', '{}'),
  ('Physiology', 'Endocrine — Hypothalamic-Pituitary Axis', 'ADH is synthesized primarily in which hypothalamic nucleus?', '[{"key": "A", "text": "Paraventricular nucleus"}, {"key": "B", "text": "Supraoptic nucleus"}, {"key": "C", "text": "Arcuate nucleus"}, {"key": "D", "text": "Ventromedial nucleus"}]'::jsonb, 'B', 'ADH is primarily synthesized in the supraoptic nucleus (though some is produced in paraventricular). Oxytocin is primarily from the paraventricular nucleus. Both are transported along axons to the posterior pituitary (neurohypophysis) for storage and release. 📚 Guyton & Hall, 14th Ed, Ch.76 (p.970)', 1, 'nucleux-content', '{}'),
  ('Physiology', 'Thyroid Physiology', 'Propylthiouracil (PTU) has an advantage over methimazole in thyroid storm because it additionally:', '[{"key": "A", "text": "Blocks NIS-mediated iodide trapping"}, {"key": "B", "text": "Inhibits peripheral conversion of T4 to T3"}, {"key": "C", "text": "Destroys thyroid tissue permanently"}, {"key": "D", "text": "Blocks \u03b2-adrenergic receptors"}]'::jsonb, 'B', 'Both PTU and methimazole block TPO (organification/coupling). PTU additionally inhibits 5''-deiodinase, blocking peripheral T4→T3 conversion. This provides faster reduction of active T3 levels, making PTU preferred in thyroid storm. 📚 Guyton & Hall, 14th Ed, Ch.77', 1, 'nucleux-content', '{}'),
  ('Physiology', 'Thyroid Physiology', 'A pregnant woman has elevated total T4 but normal free T4 and TSH. The explanation is:', '[{"key": "A", "text": "Subclinical hyperthyroidism"}, {"key": "B", "text": "Increased TBG due to estrogen"}, {"key": "C", "text": "Graves'' disease"}, {"key": "D", "text": "Central hypothyroidism"}]'::jsonb, 'B', 'Pregnancy increases estrogen → ↑TBG synthesis by liver → ↑total T4 (more bound T4). However, free T4 and TSH remain normal (euthyroid state maintained by feedback). This is why free T4 (not total T4) should be used for thyroid assessment. 📚 Ganong''s, 26th Ed, Ch.19', 1, 'nucleux-content', '{}'),
  ('Physiology', 'Thyroid Physiology', 'The Wolff-Chaikoff effect refers to:', '[{"key": "A", "text": "Increased thyroid hormone synthesis with iodide loading"}, {"key": "B", "text": "Transient inhibition of organification by excess iodide"}, {"key": "C", "text": "Increased vascularity of thyroid with iodide deficiency"}, {"key": "D", "text": "Stimulation of NIS by TSH"}]'::jsonb, 'B', 'Excess iodide transiently inhibits TPO-mediated organification (Wolff-Chaikoff effect). This is the basis for using iodide (Lugol''s solution) in thyroid storm and pre-operatively. The effect is transient due to "escape" phenomenon (downregulation of NIS). 📚 Guyton & Hall, 14th Ed, Ch.77 (p.991)', 2, 'nucleux-content', '{}'),
  ('Physiology', 'Thyroid Physiology', 'Thyroid hormones increase BMR in all tissues EXCEPT:', '[{"key": "A", "text": "Heart and liver"}, {"key": "B", "text": "Brain, spleen, and testes"}, {"key": "C", "text": "Skeletal muscle and adipose tissue"}, {"key": "D", "text": "Kidney and skin"}]'::jsonb, 'B', 'Thyroid hormones increase O2 consumption and BMR in virtually all tissues EXCEPT the adult brain, spleen, testes, and anterior pituitary. However, thyroid hormones ARE essential for brain development in the fetal/neonatal period (cretinism if deficient). 📚 Guyton & Hall, 14th Ed, Ch.77 (p.994)', 2, 'nucleux-content', '{}'),
  ('Physiology', 'Thyroid Physiology', 'The coupling reaction DIT + DIT produces:', '[{"key": "A", "text": "T3 (triiodothyronine)"}, {"key": "B", "text": "T4 (thyroxine)"}, {"key": "C", "text": "Reverse T3"}, {"key": "D", "text": "MIT"}]'::jsonb, 'B', 'DIT + DIT = T4 (4 iodine atoms). MIT + DIT = T3 (3 iodine atoms). These coupling reactions occur on thyroglobulin within the colloid and are catalyzed by TPO. T4 is produced in much greater quantity than T3 by the thyroid gland. 📚 Guyton & Hall, 14th Ed, Ch.77 (p.989)', 1, 'nucleux-content', '{}'),
  ('Physiology', 'Action Potential & Nerve Conduction', 'During the absolute refractory period of an action potential, which of the following is true?', '[{"key": "A", "text": "Voltage-gated K+ channels are closed"}, {"key": "B", "text": "Na+ channels are in the inactivated state with h-gate closed"}, {"key": "C", "text": "The membrane is hyperpolarized beyond resting potential"}, {"key": "D", "text": "A stronger-than-normal stimulus can generate an action potential"}]'::jsonb, 'B', 'During the ARP, Na+ channel inactivation gates (h-gates) are closed. No stimulus can reopen them until they recover (reset to resting state). A stronger stimulus generating AP describes the relative refractory period. 📚 Guyton & Hall, 14th Ed, Ch.5 (p.72)', 1, 'nucleux-content', '{}'),
  ('Physiology', 'Action Potential & Nerve Conduction', 'A nerve conduction study shows markedly reduced conduction velocity in a patient with progressive limb weakness. Which pathological process best explains this finding?', '[{"key": "A", "text": "Axonal degeneration"}, {"key": "B", "text": "Demyelination"}, {"key": "C", "text": "Neuromuscular junction block"}, {"key": "D", "text": "Anterior horn cell loss"}]'::jsonb, 'B', 'Demyelination reduces conduction velocity because saltatory conduction is impaired. Axonal degeneration reduces amplitude (fewer fibers conducting) but velocity in surviving fibers remains normal. NMJ block and anterior horn cell loss affect different parts of the motor unit. 📚 Ganong''s, 26th Ed, Ch.4', 2, 'nucleux-content', '{}'),
  ('Physiology', 'Action Potential & Nerve Conduction', 'Which nerve fiber type carries slow pain and is unmyelinated?', '[{"key": "A", "text": "A\u03b1 fibers"}, {"key": "B", "text": "A\u03b4 fibers"}, {"key": "C", "text": "B fibers"}, {"key": "D", "text": "C fibers"}]'::jsonb, 'D', 'C fibers are unmyelinated, smallest diameter (0.4-1.2 μm), slowest conduction (0.5-2 m/s), and carry slow/burning pain and postganglionic autonomic signals. Aδ fibers carry fast/sharp pain and are myelinated. 📚 Guyton & Hall, 14th Ed, Ch.5', 1, 'nucleux-content', '{}'),
  ('Physiology', 'Action Potential & Nerve Conduction', 'Resting membrane potential is closest to the equilibrium potential of which ion?', '[{"key": "A", "text": "Na+"}, {"key": "B", "text": "K+"}, {"key": "C", "text": "Ca2+"}, {"key": "D", "text": "Cl-"}]'::jsonb, 'B', 'RMP (~-70 mV) is closest to E_K (-94 mV) because the resting membrane is most permeable to K+. E_Na is +61 mV. The difference between RMP and E_K is due to slight Na+ permeability and electrogenic Na+/K+ ATPase contribution. 📚 Guyton & Hall, 14th Ed, Ch.5 (p.65)', 1, 'nucleux-content', '{}'),
  ('Physiology', 'Action Potential & Nerve Conduction', 'A patient with hypocalcemia develops carpopedal spasm. The mechanism is:', '[{"key": "A", "text": "Decreased K+ permeability"}, {"key": "B", "text": "Increased Na+ channel permeability at resting state"}, {"key": "C", "text": "Blockade of voltage-gated Ca2+ channels"}, {"key": "D", "text": "Increased Na+/K+ ATPase activity"}]'::jsonb, 'B', 'Ca2+ normally stabilizes Na+ channels by screening surface charges. Hypocalcemia removes this stabilization, increasing Na+ channel opening probability → threshold is lowered → spontaneous firing → tetany/carpopedal spasm. This is different from Ca2+''s role in neurotransmitter release. 📚 Ganong''s, 26th Ed, Ch.4', 2, 'nucleux-content', '{}'),
  ('Physiology', 'Gastric Acid Secretion & Regulation', 'The MOST potent stimulant of acid secretion by parietal cells is:', '[{"key": "A", "text": "Acetylcholine alone"}, {"key": "B", "text": "Gastrin alone"}, {"key": "C", "text": "Histamine potentiated by ACh and gastrin"}, {"key": "D", "text": "Secretin"}]'::jsonb, 'C', 'Histamine from ECL cells acts via H2 receptors (cAMP pathway) and potentiates the effects of both ACh and gastrin. All three stimulants together produce maximal acid output. This is why H2 blockers reduce acid secretion stimulated by all three pathways. 📚 Guyton & Hall, 14th Ed, Ch.65 (p.845)', 2, 'nucleux-content', '{}'),
  ('Physiology', 'Gastric Acid Secretion & Regulation', 'The ''alkaline tide'' after a meal refers to:', '[{"key": "A", "text": "Increased HCO3- in gastric lumen"}, {"key": "B", "text": "Increased HCO3- in blood due to parietal cell H+ secretion"}, {"key": "C", "text": "Increased pH of pancreatic secretion"}, {"key": "D", "text": "Alkaline saliva production"}]'::jsonb, 'B', 'When parietal cells secrete H+ into the lumen, the HCO3- generated intracellularly exits into blood via basolateral Cl-/HCO3- exchanger → transient postprandial alkalemia ("alkaline tide"). This is balanced by pancreatic HCO3- secretion into the duodenum. 📚 Ganong''s, 26th Ed, Ch.25', 2, 'nucleux-content', '{}'),
  ('Physiology', 'Gastric Acid Secretion & Regulation', 'A patient on long-term NSAIDs develops a gastric ulcer. The mechanism is:', '[{"key": "A", "text": "Increased acid secretion"}, {"key": "B", "text": "H. pylori infection"}, {"key": "C", "text": "Decreased prostaglandin-mediated mucosal defense"}, {"key": "D", "text": "Increased gastrin secretion"}]'::jsonb, 'C', 'NSAIDs inhibit COX-1 → decreased PGE2 and PGI2 → reduced mucus secretion, reduced HCO3- secretion, reduced mucosal blood flow → weakened mucosal defense → ulcer formation. NSAIDs cause gastric ulcers through mucosal defense failure, not acid hypersecretion. 📚 Guyton & Hall, 14th Ed, Ch.65', 1, 'nucleux-content', '{}'),
  ('Physiology', 'Gastric Acid Secretion & Regulation', 'Intrinsic factor is secreted by:', '[{"key": "A", "text": "Chief cells"}, {"key": "B", "text": "Parietal cells"}, {"key": "C", "text": "G cells"}, {"key": "D", "text": "Mucous neck cells"}]'::jsonb, 'B', 'Parietal (oxyntic) cells secrete both HCl and intrinsic factor. IF is essential for vitamin B12 absorption in the terminal ileum. Autoimmune destruction of parietal cells → loss of both HCl (achlorhydria) and IF (pernicious anemia). 📚 Guyton & Hall, 14th Ed, Ch.65 (p.842)', 1, 'nucleux-content', '{}'),
  ('Physiology', 'Gastric Acid Secretion & Regulation', 'The gastric phase of acid secretion accounts for what percentage of total acid output?', '[{"key": "A", "text": "10%"}, {"key": "B", "text": "30%"}, {"key": "C", "text": "60%"}, {"key": "D", "text": "90%"}]'::jsonb, 'C', 'The gastric phase is the largest contributor (~60%) triggered by food distension and amino acids in the stomach. Cephalic phase contributes ~30% (vagal). Intestinal phase ~10% and is predominantly inhibitory (enterogastric reflex via secretin, CCK, GIP). 📚 Ganong''s, 26th Ed, Ch.25', 1, 'nucleux-content', '{}'),
  ('Physiology', 'GI Motility & Secretions', 'The migrating motor complex (MMC) during fasting is primarily mediated by:', '[{"key": "A", "text": "Gastrin"}, {"key": "B", "text": "CCK"}, {"key": "C", "text": "Motilin"}, {"key": "D", "text": "Secretin"}]'::jsonb, 'C', 'Motilin triggers Phase III of the MMC, the strong propulsive contractions that sweep through the GI tract every 90-120 minutes during fasting. This "housekeeper" function clears residual food and bacteria. Erythromycin acts as a motilin receptor agonist and can be used as a prokinetic. 📚 Guyton & Hall, 14th Ed, Ch.63', 1, 'nucleux-content', '{}'),
  ('Physiology', 'GI Motility & Secretions', 'Enterokinase (enteropeptidase) in the duodenal brush border activates:', '[{"key": "A", "text": "Pepsinogen"}, {"key": "B", "text": "Trypsinogen"}, {"key": "C", "text": "Lipase"}, {"key": "D", "text": "Amylase"}]'::jsonb, 'B', 'Enterokinase specifically cleaves trypsinogen → trypsin. Trypsin then autocatalytically activates more trypsinogen and activates all other pancreatic zymogens (chymotrypsinogen, proelastase, procarboxypeptidase). Pepsinogen is activated by HCl in the stomach, not enterokinase. 📚 Ganong''s, 26th Ed, Ch.26', 1, 'nucleux-content', '{}'),
  ('Physiology', 'GI Motility & Secretions', 'Which GI hormone stimulates pancreatic bicarbonate secretion?', '[{"key": "A", "text": "Gastrin"}, {"key": "B", "text": "CCK"}, {"key": "C", "text": "Secretin"}, {"key": "D", "text": "Motilin"}]'::jsonb, 'C', 'Secretin is released by S cells in the duodenum in response to acid (pH <4.5). It stimulates ductal cells to secrete HCO3--rich fluid, neutralizing gastric acid. CCK stimulates pancreatic enzyme (not bicarbonate) secretion from acinar cells. 📚 Guyton & Hall, 14th Ed, Ch.65', 1, 'nucleux-content', '{}'),
  ('Physiology', 'GI Motility & Secretions', 'The pacemaker cells of the GI tract that generate slow waves are:', '[{"key": "A", "text": "Enteric neurons"}, {"key": "B", "text": "Interstitial cells of Cajal"}, {"key": "C", "text": "Smooth muscle cells"}, {"key": "D", "text": "Enterochromaffin cells"}]'::jsonb, 'B', 'ICC are mesenchymal cells located between nerve endings and smooth muscle that generate the basic electrical rhythm (slow waves). They set the maximum frequency of contractions in each GI segment. Actual contractions occur when action potentials are superimposed on slow waves. 📚 Ganong''s, 26th Ed, Ch.25', 1, 'nucleux-content', '{}'),
  ('Physiology', 'GI Motility & Secretions', 'Saliva is hypotonic because of:', '[{"key": "A", "text": "Active secretion of water by acinar cells"}, {"key": "B", "text": "Ductal reabsorption of Na+ and Cl- exceeding secretion of K+ and HCO3-"}, {"key": "C", "text": "Absence of any electrolytes in saliva"}, {"key": "D", "text": "Salivary amylase diluting the electrolytes"}]'::jsonb, 'B', 'Primary acinar secretion is isotonic. As it passes through ducts, Na+ and Cl- are reabsorbed while K+ and HCO3- are secreted. Since the duct is relatively impermeable to water and more solute is removed than added, the final saliva becomes hypotonic. 📚 Guyton & Hall, 14th Ed, Ch.65 (p.840)', 2, 'nucleux-content', '{}'),
  ('Physiology', 'Liver Functions & Bilirubin Metabolism', 'A patient with obstructive jaundice due to pancreatic head tumor will have:', '[{"key": "A", "text": "Increased unconjugated bilirubin, increased urine urobilinogen"}, {"key": "B", "text": "Increased conjugated bilirubin, dark urine, pale stools"}, {"key": "C", "text": "Normal bilirubin, increased AST/ALT"}, {"key": "D", "text": "Increased unconjugated bilirubin, absent bilirubinuria"}]'::jsonb, 'B', 'Obstruction prevents CB from reaching intestine → CB regurgitates into blood → bilirubinuria (dark urine). No CB in intestine → no urobilinogen → pale/clay-colored stools. ALP and GGT are elevated (cholestatic pattern). 📚 Guyton & Hall, 14th Ed, Ch.70 (p.909)', 1, 'nucleux-content', '{}'),
  ('Physiology', 'Liver Functions & Bilirubin Metabolism', 'Gilbert syndrome is caused by deficiency of:', '[{"key": "A", "text": "Heme oxygenase"}, {"key": "B", "text": "UDP-glucuronosyltransferase (UGT1A1)"}, {"key": "C", "text": "MRP2 canalicular transporter"}, {"key": "D", "text": "Ligandin (Y protein)"}]'::jsonb, 'B', 'Gilbert syndrome results from reduced (not absent) UGT1A1 activity → mild unconjugated hyperbilirubinemia, especially triggered by fasting or stress. Benign condition affecting 5-10% of the population. Absent UGT1A1 = Crigler-Najjar Type I (severe). MRP2 defect = Dubin-Johnson (conjugated). 📚 Ganong''s, 26th Ed, Ch.28', 1, 'nucleux-content', '{}'),
  ('Physiology', 'Liver Functions & Bilirubin Metabolism', 'Which clotting factor is NOT synthesized by the liver?', '[{"key": "A", "text": "Factor II (prothrombin)"}, {"key": "B", "text": "Factor VII"}, {"key": "C", "text": "Factor VIII"}, {"key": "D", "text": "Factor IX"}]'::jsonb, 'C', 'Factor VIII is primarily synthesized by vascular endothelial cells and sinusoidal cells, not hepatocytes. All other clotting factors (I, II, V, VII, IX, X, XI, XII, XIII) are synthesized by the liver. This is why Factor VIII levels may be normal or elevated in liver failure. 📚 Guyton & Hall, 14th Ed, Ch.70', 1, 'nucleux-content', '{}'),
  ('Physiology', 'Liver Functions & Bilirubin Metabolism', 'The rate-limiting enzyme in bile acid synthesis from cholesterol is:', '[{"key": "A", "text": "HMG-CoA reductase"}, {"key": "B", "text": "7\u03b1-hydroxylase"}, {"key": "C", "text": "Cholesterol esterase"}, {"key": "D", "text": "Lecithin-cholesterol acyltransferase"}]'::jsonb, 'B', '7α-hydroxylase (CYP7A1) catalyzes the first and rate-limiting step in bile acid synthesis. It converts cholesterol to 7α-hydroxycholesterol. HMG-CoA reductase is rate-limiting for cholesterol synthesis (target of statins), not bile acid synthesis. 📚 Ganong''s, 26th Ed, Ch.28', 2, 'nucleux-content', '{}'),
  ('Physiology', 'Liver Functions & Bilirubin Metabolism', 'In pre-hepatic (hemolytic) jaundice, which of the following is TRUE?', '[{"key": "A", "text": "Urine bilirubin is positive"}, {"key": "B", "text": "Stool color is pale"}, {"key": "C", "text": "Urine urobilinogen is increased"}, {"key": "D", "text": "Conjugated bilirubin is predominantly elevated"}]'::jsonb, 'C', 'In hemolytic jaundice: ↑RBC breakdown → ↑UCB → liver conjugates more → ↑CB in bile → ↑urobilinogen in gut. More urobilinogen reabsorbed → ↑urine urobilinogen. No bilirubinuria (UCB is albumin-bound, not filtered). Stools are dark (excess stercobilin). CB is not predominantly elevated. 📚 Guyton & Hall, 14th Ed, Ch.70', 2, 'nucleux-content', '{}'),
  ('Physiology', 'Neuromuscular Junction', 'A patient with ptosis and diplopia that worsen with repeated use is found to have anti-acetylcholine receptor antibodies. Repetitive nerve stimulation will most likely show:', '[{"key": "A", "text": "Incremental response"}, {"key": "B", "text": "Decremental response"}, {"key": "C", "text": "No change in amplitude"}, {"key": "D", "text": "Fibrillation potentials"}]'::jsonb, 'B', 'Myasthenia gravis shows decremental response on repetitive nerve stimulation because progressive depletion of ACh vesicles with repeated stimulation, combined with fewer available receptors, causes progressive failure of EPP to reach threshold. Incremental response is seen in Lambert-Eaton syndrome. 📚 Guyton & Hall, 14th Ed, Ch.7', 1, 'nucleux-content', '{}'),
  ('Physiology', 'Neuromuscular Junction', 'Botulinum toxin produces paralysis by:', '[{"key": "A", "text": "Blocking nicotinic ACh receptors"}, {"key": "B", "text": "Inhibiting acetylcholinesterase"}, {"key": "C", "text": "Cleaving SNARE proteins to prevent ACh vesicle exocytosis"}, {"key": "D", "text": "Blocking voltage-gated Ca2+ channels"}]'::jsonb, 'C', 'Botulinum toxin is a zinc-dependent endopeptidase that cleaves SNARE proteins (synaptobrevin, SNAP-25, or syntaxin depending on serotype), preventing vesicle fusion and ACh release. This is different from blocking receptors (curare) or Ca2+ channels (Lambert-Eaton antibodies). 📚 Ganong''s, 26th Ed, Ch.4', 1, 'nucleux-content', '{}'),
  ('Physiology', 'Neuromuscular Junction', 'Which of the following best differentiates Lambert-Eaton syndrome from myasthenia gravis?', '[{"key": "A", "text": "Weakness improves with repeated stimulation in Lambert-Eaton"}, {"key": "B", "text": "Lambert-Eaton involves antibodies against ACh receptors"}, {"key": "C", "text": "Lambert-Eaton shows decremental response on nerve stimulation"}, {"key": "D", "text": "Thymoma is commonly associated with Lambert-Eaton"}]'::jsonb, 'A', 'In LEMS, antibodies target pre-synaptic Ca2+ channels reducing ACh release. With repeated stimulation, Ca2+ accumulates in the terminal → increased ACh release → improvement (incremental response/facilitation). In MG, repeated stimulation depletes ACh further → worsening (decremental response). 📚 Guyton & Hall, 14th Ed, Ch.7', 2, 'nucleux-content', '{}'),
  ('Physiology', 'Neuromuscular Junction', 'A patient develops prolonged apnea after succinylcholine administration during surgery. The most likely cause is:', '[{"key": "A", "text": "Myasthenia gravis"}, {"key": "B", "text": "Malignant hyperthermia"}, {"key": "C", "text": "Pseudocholinesterase (butyrylcholinesterase) deficiency"}, {"key": "D", "text": "Hyperkalemia"}]'::jsonb, 'C', 'Succinylcholine is normally rapidly hydrolyzed by plasma pseudocholinesterase (butyrylcholinesterase). Genetic deficiency (atypical enzyme) results in prolonged paralysis and apnea. Detected by dibucaine number (low dibucaine number = atypical enzyme = prolonged block). 📚 Ganong''s, 26th Ed, Ch.4', 2, 'nucleux-content', '{}'),
  ('Physiology', 'Neuromuscular Junction', 'The minimum number of ACh molecules that must bind to the nicotinic receptor for channel opening is:', '[{"key": "A", "text": "1"}, {"key": "B", "text": "2"}, {"key": "C", "text": "3"}, {"key": "D", "text": "4"}]'::jsonb, 'B', 'The nicotinic ACh receptor has 5 subunits (α2βδε in adult). Two ACh molecules must bind simultaneously to the two α subunits for conformational change and channel opening. This is a key structural feature that ensures adequate neurotransmitter concentration for activation. 📚 Guyton & Hall, 14th Ed, Ch.7 (p.91)', 1, 'nucleux-content', '{}'),
  ('Physiology', 'Acid-Base Physiology', 'A patient with DKA has pH 7.25, HCO3- 10 mEq/L, PCO2 25 mmHg. Using Winter''s formula, is the respiratory compensation appropriate?', '[{"key": "A", "text": "Yes, compensation is appropriate"}, {"key": "B", "text": "No, there is concurrent respiratory acidosis"}, {"key": "C", "text": "No, there is concurrent respiratory alkalosis"}, {"key": "D", "text": "Cannot determine from given data"}]'::jsonb, 'A', 'Winter''s formula: expected PCO2 = 1.5(10) + 8 ± 2 = 23 ± 2 mmHg (range 21-25). Actual PCO2 = 25, which is within the expected range. Therefore, compensation is appropriate and this is a simple metabolic acidosis with appropriate respiratory compensation. 📚 Guyton & Hall, 14th Ed, Ch.31', 2, 'nucleux-content', '{}'),
  ('Physiology', 'Acid-Base Physiology', 'Which type of Renal Tubular Acidosis is associated with HYPERKALEMIA?', '[{"key": "A", "text": "Type 1 (Distal)"}, {"key": "B", "text": "Type 2 (Proximal)"}, {"key": "C", "text": "Type 3 (Mixed)"}, {"key": "D", "text": "Type 4 (Hyperkalemic)"}]'::jsonb, 'D', 'Type 4 RTA is caused by aldosterone deficiency or resistance → decreased K+ secretion → hyperkalemia. Also decreases NH4+ excretion → metabolic acidosis. Types 1 and 2 RTA cause HYPOkalemia (increased distal Na+ delivery and K+ wasting). 📚 Ganong''s, 26th Ed, Ch.39', 1, 'nucleux-content', '{}'),
  ('Physiology', 'Acid-Base Physiology', 'The most important buffer system in the body is the bicarbonate system because:', '[{"key": "A", "text": "It has the highest pKa"}, {"key": "B", "text": "Both components are independently regulated by lungs and kidneys"}, {"key": "C", "text": "It is the most concentrated buffer in ICF"}, {"key": "D", "text": "It has the fastest reaction time"}]'::jsonb, 'B', 'Although bicarbonate''s pKa (6.1) is far from blood pH (7.4), making it a poor chemical buffer, it is the most important physiological buffer because CO2 is regulated by lungs (ventilation) and HCO3- by kidneys (reabsorption/generation). This open system gives it virtually infinite buffering capacity. 📚 Guyton & Hall, 14th Ed, Ch.31 (p.401)', 2, 'nucleux-content', '{}'),
  ('Physiology', 'Acid-Base Physiology', 'A patient with chronic vomiting has pH 7.52, HCO3- 38, PCO2 48. The acid-base disorder is:', '[{"key": "A", "text": "Metabolic alkalosis with respiratory compensation"}, {"key": "B", "text": "Respiratory acidosis"}, {"key": "C", "text": "Mixed metabolic alkalosis and respiratory acidosis"}, {"key": "D", "text": "Metabolic alkalosis without compensation"}]'::jsonb, 'A', 'Chronic vomiting → loss of H+/Cl- → metabolic alkalosis (↑pH, ↑HCO3-). Expected PCO2 = 0.7(38) + 21 = 47.6 ≈ 48. Actual PCO2 matches expected → appropriate respiratory compensation (hypoventilation to retain CO2). 📚 Ganong''s, 26th Ed, Ch.39', 2, 'nucleux-content', '{}'),
  ('Physiology', 'Acid-Base Physiology', 'MUDPILES is a mnemonic for causes of:', '[{"key": "A", "text": "Normal anion gap metabolic acidosis"}, {"key": "B", "text": "High anion gap metabolic acidosis"}, {"key": "C", "text": "Metabolic alkalosis"}, {"key": "D", "text": "Respiratory acidosis"}]'::jsonb, 'B', 'MUDPILES: Methanol, Uremia, DKA, Propylene glycol, Isoniazid/Iron, Lactic acidosis, Ethylene glycol, Salicylates. These unmeasured anions replace HCO3- → high AG. Normal AG causes include diarrhea and RTA. 📚 Guyton & Hall, 14th Ed, Ch.31', 1, 'nucleux-content', '{}'),
  ('Physiology', 'Renal Physiology (GFR, Clearance, Countercurrent)', 'Which substance''s clearance is used as the gold standard for measuring GFR?', '[{"key": "A", "text": "Creatinine"}, {"key": "B", "text": "Inulin"}, {"key": "C", "text": "PAH"}, {"key": "D", "text": "Urea"}]'::jsonb, 'B', 'Inulin is freely filtered at the glomerulus, not reabsorbed, not secreted, and not metabolized by the kidney. Therefore, inulin clearance exactly equals GFR. Creatinine overestimates slightly (tubular secretion). PAH measures renal plasma flow, not GFR. 📚 Guyton & Hall, 14th Ed, Ch.27 (p.348)', 1, 'nucleux-content', '{}'),
  ('Physiology', 'Renal Physiology (GFR, Clearance, Countercurrent)', 'The thick ascending limb of the loop of Henle is the site of action of:', '[{"key": "A", "text": "Thiazide diuretics"}, {"key": "B", "text": "Furosemide (loop diuretics)"}, {"key": "C", "text": "Spironolactone"}, {"key": "D", "text": "Amiloride"}]'::jsonb, 'B', 'Furosemide blocks the NKCC2 (Na+/K+/2Cl- cotransporter) in the thick ascending limb, preventing NaCl reabsorption and abolishing the corticomedullary osmotic gradient → impaired concentrating ability. Thiazides act on DCT (NCC). Spironolactone and amiloride act on collecting duct. 📚 Guyton & Hall, 14th Ed, Ch.29 (p.370)', 1, 'nucleux-content', '{}'),
  ('Physiology', 'Renal Physiology (GFR, Clearance, Countercurrent)', 'A patient with polyuria and dilute urine is given desmopressin. Urine osmolality increases to 800 mOsm/kg. The diagnosis is:', '[{"key": "A", "text": "Nephrogenic diabetes insipidus"}, {"key": "B", "text": "Central diabetes insipidus"}, {"key": "C", "text": "Primary polydipsia"}, {"key": "D", "text": "SIADH"}]'::jsonb, 'B', 'Central DI = ADH deficiency. Desmopressin (ADH analog) replaces missing hormone → collecting duct responds → urine concentrates. In nephrogenic DI, kidneys are resistant to ADH → desmopressin has no effect. Primary polydipsia: urine concentrates even without desmopressin after water deprivation. 📚 Guyton & Hall, 14th Ed, Ch.29', 1, 'nucleux-content', '{}'),
  ('Physiology', 'Renal Physiology (GFR, Clearance, Countercurrent)', 'Filtration fraction (FF) is calculated as:', '[{"key": "A", "text": "GFR \u00d7 RPF"}, {"key": "B", "text": "RPF / GFR"}, {"key": "C", "text": "GFR / RPF"}, {"key": "D", "text": "GFR / RBF"}]'::jsonb, 'C', 'Filtration Fraction = GFR/RPF = 125/625 = 0.20 (20%). This means 20% of plasma flowing through the kidney is filtered at the glomerulus. Increased FF (efferent constriction by Ang II) → increased peritubular oncotic pressure → increased PCT reabsorption. 📚 Ganong''s, 26th Ed, Ch.37', 1, 'nucleux-content', '{}'),
  ('Physiology', 'Renal Physiology (GFR, Clearance, Countercurrent)', 'Which part of the loop of Henle is permeable to water but NOT to NaCl?', '[{"key": "A", "text": "Thick ascending limb"}, {"key": "B", "text": "Thin ascending limb"}, {"key": "C", "text": "Thin descending limb"}, {"key": "D", "text": "Macula densa"}]'::jsonb, 'C', 'The thin descending limb is highly permeable to water (via AQP1) but relatively impermeable to NaCl and urea. Water exits passively down the osmotic gradient → tubular fluid concentrates. The ascending limb (both thin and thick) is impermeable to water. 📚 Guyton & Hall, 14th Ed, Ch.29 (p.368)', 2, 'nucleux-content', '{}'),
  ('Physiology', 'Renal Tubular Function', 'A patient on furosemide develops muscle cramps and tetany. Serum calcium is low. The mechanism is:', '[{"key": "A", "text": "Increased calcium reabsorption in PCT"}, {"key": "B", "text": "Decreased paracellular calcium reabsorption in thick ascending limb"}, {"key": "C", "text": "Increased calcium secretion in collecting duct"}, {"key": "D", "text": "Decreased PTH secretion"}]'::jsonb, 'B', 'Furosemide blocks NKCC2 → abolishes lumen-positive potential in TAL → decreased paracellular Ca2+ and Mg2+ reabsorption → hypocalcemia and hypomagnesemia. This is opposite to thiazides, which increase Ca2+ reabsorption in DCT. 📚 Guyton & Hall, 14th Ed, Ch.28', 2, 'nucleux-content', '{}'),
  ('Physiology', 'Renal Tubular Function', 'Which transporter is the target of SGLT2 inhibitors used in diabetes mellitus?', '[{"key": "A", "text": "GLUT2 in PCT basolateral membrane"}, {"key": "B", "text": "SGLT2 in PCT apical membrane"}, {"key": "C", "text": "SGLT1 in PCT S3 segment"}, {"key": "D", "text": "Na+/glucose transporter in loop of Henle"}]'::jsonb, 'B', 'SGLT2 (sodium-glucose cotransporter 2) is located on the apical membrane of PCT S1/S2 segments and reabsorbs 90% of filtered glucose. SGLT2 inhibitors (empagliflozin, dapagliflozin) block this → glucosuria → lower blood glucose + cardiorenal benefits. 📚 Ganong''s, 26th Ed, Ch.37', 1, 'nucleux-content', '{}'),
  ('Physiology', 'Renal Tubular Function', 'Aldosterone increases sodium reabsorption in the collecting duct by upregulating:', '[{"key": "A", "text": "NKCC2"}, {"key": "B", "text": "NCC"}, {"key": "C", "text": "ENaC"}, {"key": "D", "text": "SGLT2"}]'::jsonb, 'C', 'Aldosterone binds mineralocorticoid receptors in principal cells → upregulates ENaC (apical Na+ channel) and Na+/K+ ATPase (basolateral) → increased Na+ reabsorption and K+ secretion. NKCC2 is in TAL (loop diuretic target), NCC in DCT (thiazide target). 📚 Guyton & Hall, 14th Ed, Ch.28 (p.362)', 1, 'nucleux-content', '{}'),
  ('Physiology', 'Renal Tubular Function', 'A child with hypokalemic metabolic alkalosis, hypocalciuria, and hypomagnesemia most likely has:', '[{"key": "A", "text": "Bartter syndrome"}, {"key": "B", "text": "Gitelman syndrome"}, {"key": "C", "text": "Liddle syndrome"}, {"key": "D", "text": "Fanconi syndrome"}]'::jsonb, 'B', 'Gitelman syndrome = loss-of-function NCC in DCT (mimics chronic thiazide use): hypokalemic metabolic alkalosis + HYPOcalciuria + hypomagnesemia. Bartter syndrome (TAL defect) causes HYPERcalciuria. Liddle syndrome causes HTN with hypokalemia. Fanconi = proximal tubule dysfunction. 📚 Ganong''s, 26th Ed, Ch.37', 2, 'nucleux-content', '{}'),
  ('Physiology', 'Renal Tubular Function', 'The ''diluting segment'' of the nephron refers to:', '[{"key": "A", "text": "Proximal convoluted tubule"}, {"key": "B", "text": "Thin descending limb"}, {"key": "C", "text": "Thick ascending limb of loop of Henle"}, {"key": "D", "text": "Collecting duct"}]'::jsonb, 'C', 'The TAL actively reabsorbs NaCl (via NKCC2) but is impermeable to water → tubular fluid becomes progressively dilute (hypotonic, ~100 mOsm/kg at the end). This is the primary diluting segment. The early DCT continues dilution. The PCT reabsorbs iso-osmotically (not diluting). 📚 Guyton & Hall, 14th Ed, Ch.28 (p.358)', 1, 'nucleux-content', '{}'),
  ('Physiology', 'Respiratory Physiology (Volumes, Capacities, Gas Exchange)', 'Which of the following lung volumes CANNOT be measured by simple spirometry?', '[{"key": "A", "text": "Tidal volume"}, {"key": "B", "text": "Inspiratory reserve volume"}, {"key": "C", "text": "Residual volume"}, {"key": "D", "text": "Expiratory reserve volume"}]'::jsonb, 'C', 'Residual volume is the air remaining in lungs after maximal expiration — it cannot be exhaled and therefore cannot be measured by spirometry. It requires helium dilution, nitrogen washout, or body plethysmography. Consequently, FRC and TLC (which contain RV) also cannot be measured by spirometry. 📚 Guyton & Hall, 14th Ed, Ch.38 (p.499)', 1, 'nucleux-content', '{}'),
  ('Physiology', 'Respiratory Physiology (Volumes, Capacities, Gas Exchange)', 'A patient''s arterial blood gas shows PaO2 55 mmHg. After breathing 100% O2, PaO2 rises to only 65 mmHg. This suggests:', '[{"key": "A", "text": "V/Q mismatch"}, {"key": "B", "text": "Right-to-left shunt"}, {"key": "C", "text": "Hypoventilation"}, {"key": "D", "text": "Diffusion impairment"}]'::jsonb, 'B', 'Shunt (V/Q = 0) blood bypasses ventilated alveoli and does not contact inhaled O2, so supplemental O2 has minimal effect. V/Q mismatch and diffusion impairment respond partially to 100% O2. Hypoventilation responds well to supplemental O2. 📚 Guyton & Hall, 14th Ed, Ch.40 (p.528)', 2, 'nucleux-content', '{}'),
  ('Physiology', 'Respiratory Physiology (Volumes, Capacities, Gas Exchange)', 'In an upright lung, tuberculosis preferentially affects the apex because:', '[{"key": "A", "text": "Blood flow is highest at the apex"}, {"key": "B", "text": "Ventilation is lowest at the apex"}, {"key": "C", "text": "PO2 is highest at the apex due to high V/Q ratio"}, {"key": "D", "text": "Lymphatic drainage is poor at the apex"}]'::jsonb, 'C', 'The apex has high V/Q ratio (≈3) → high alveolar PO2 → favorable environment for the obligate aerobe Mycobacterium tuberculosis. The base has lower V/Q and lower PO2. 📚 Ganong''s, 26th Ed, Ch.34', 2, 'nucleux-content', '{}'),
  ('Physiology', 'Respiratory Physiology (Volumes, Capacities, Gas Exchange)', 'DLCO is INCREASED in which of the following conditions?', '[{"key": "A", "text": "Emphysema"}, {"key": "B", "text": "Pulmonary fibrosis"}, {"key": "C", "text": "Pulmonary hemorrhage"}, {"key": "D", "text": "Anemia"}]'::jsonb, 'C', 'In pulmonary hemorrhage (e.g., Goodpasture syndrome), hemoglobin in alveoli absorbs CO, falsely increasing DLCO. Emphysema (↓surface area), fibrosis (↑thickness), and anemia (↓Hb) all decrease DLCO. 📚 Ganong''s, 26th Ed, Ch.34', 2, 'nucleux-content', '{}'),
  ('Physiology', 'Respiratory Physiology (Volumes, Capacities, Gas Exchange)', 'Functional Residual Capacity (FRC) is the sum of:', '[{"key": "A", "text": "Tidal volume + Inspiratory reserve volume"}, {"key": "B", "text": "Expiratory reserve volume + Residual volume"}, {"key": "C", "text": "Tidal volume + Expiratory reserve volume"}, {"key": "D", "text": "Inspiratory reserve volume + Tidal volume + Expiratory reserve volume"}]'::jsonb, 'B', 'FRC = ERV + RV. It represents the volume of air in the lungs at the end of normal passive expiration, where the inward recoil of the lung equals the outward recoil of the chest wall. FRC is the lung''s resting volume and serves as an oxygen reserve between breaths. 📚 Guyton & Hall, 14th Ed, Ch.38 (p.498)', 1, 'nucleux-content', '{}'),
  ('Physiology', 'Oxygen-Hemoglobin Dissociation Curve', 'A patient presents with cherry-red skin, headache, and confusion after a house fire. Pulse oximetry shows 98%. The most likely diagnosis is:', '[{"key": "A", "text": "Cyanide poisoning"}, {"key": "B", "text": "Carbon monoxide poisoning"}, {"key": "C", "text": "Methemoglobinemia"}, {"key": "D", "text": "Smoke inhalation injury"}]'::jsonb, 'B', 'Cherry-red skin + normal pulse ox reading + altered mental status after fire exposure = CO poisoning. Pulse oximetry cannot distinguish COHb from OxyHb, giving falsely normal readings. PaO2 is also normal. Diagnosis requires co-oximetry showing elevated COHb levels. 📚 Ganong''s, 26th Ed, Ch.35', 1, 'nucleux-content', '{}'),
  ('Physiology', 'Oxygen-Hemoglobin Dissociation Curve', 'Which of the following causes a LEFT shift of the oxygen-hemoglobin dissociation curve?', '[{"key": "A", "text": "Increased 2,3-DPG"}, {"key": "B", "text": "Increased temperature"}, {"key": "C", "text": "Decreased pH"}, {"key": "D", "text": "Fetal hemoglobin"}]'::jsonb, 'D', 'HbF has higher O2 affinity (left shift) because γ-chains bind 2,3-DPG poorly. Increased 2,3-DPG, temperature, and decreased pH (acidosis) all cause right shift (decreased affinity). 📚 Guyton & Hall, 14th Ed, Ch.41', 1, 'nucleux-content', '{}'),
  ('Physiology', 'Oxygen-Hemoglobin Dissociation Curve', 'The Bohr effect describes:', '[{"key": "A", "text": "The effect of O2 on CO2 binding to hemoglobin"}, {"key": "B", "text": "The effect of CO2/H+ on O2 binding to hemoglobin"}, {"key": "C", "text": "Cooperative O2 binding by hemoglobin subunits"}, {"key": "D", "text": "The effect of temperature on O2 binding"}]'::jsonb, 'B', 'Bohr effect: increased CO2/H+ decreases Hb-O2 affinity → promotes O2 release at tissues. The Haldane effect is the reciprocal — the effect of O2 on CO2 binding. Both effects work together to optimize gas exchange at tissues and lungs. 📚 Guyton & Hall, 14th Ed, Ch.41 (p.537)', 1, 'nucleux-content', '{}'),
  ('Physiology', 'Oxygen-Hemoglobin Dissociation Curve', 'A patient receives massive blood transfusion with stored blood. Post-transfusion, despite normal hemoglobin, tissue hypoxia persists. The most likely cause is:', '[{"key": "A", "text": "Transfusion reaction causing hemolysis"}, {"key": "B", "text": "Decreased 2,3-DPG in stored blood"}, {"key": "C", "text": "Hyperkalemia from stored blood"}, {"key": "D", "text": "Citrate toxicity"}]'::jsonb, 'B', 'Stored blood progressively loses 2,3-DPG → left-shifted ODC → Hb holds O2 tightly → impaired O2 unloading at tissues despite adequate Hb and PaO2. 2,3-DPG regenerates within 24-48 hours after transfusion. Clinically significant in massive transfusion scenarios. 📚 Ganong''s, 26th Ed, Ch.35', 2, 'nucleux-content', '{}'),
  ('Physiology', 'Oxygen-Hemoglobin Dissociation Curve', 'P50 of normal adult hemoglobin is approximately:', '[{"key": "A", "text": "13 mmHg"}, {"key": "B", "text": "27 mmHg"}, {"key": "C", "text": "40 mmHg"}, {"key": "D", "text": "60 mmHg"}]'::jsonb, 'B', 'P50 is the PO2 at which hemoglobin is 50% saturated. Normal P50 ≈ 26.7 mmHg (~27). Increased P50 = right shift (decreased affinity). Decreased P50 = left shift (increased affinity). HbF has P50 ≈ 19 mmHg (left-shifted). Myoglobin P50 ≈ 5 mmHg (very high affinity). 📚 Guyton & Hall, 14th Ed, Ch.41 (p.533)', 1, 'nucleux-content', '{}'),
  ('Surgery', 'Breast', 'A 50-year-old woman presents with a hard, fixed 3 cm lump in the upper outer quadrant with ipsilateral axillary lymphadenopathy. Core biopsy shows ER+/PR+/HER2−. What is the molecular subtype?', '[{"key": "A", "text": "a"}, {"key": "B", "text": "b"}, {"key": "C", "text": "c"}, {"key": "D", "text": "d"}]'::jsonb, 'A', 'ER+/PR+/HER2− with low Ki67 is Luminal A (best prognosis). If Ki67 were high, it would be
